Modules["Animations.Blur"] = function()
local Utilities = VoidRequire("Core.Utilities")

local Blur = {}
Blur.__index = Blur

function Blur.new()
	local self = setmetatable({}, Blur)
	self.Size = 0
	self.TargetSize = 0
	self.Speed = 12
	self.Enabled = false
	self.Instance = nil
	return self
end

function Blur:Create(Parent)
	local Success, BlurEffect = pcall(function()
		return Instance.new("BlurEffect")
	end)
	if Success and BlurEffect then
		BlurEffect.Size = self.Size
		BlurEffect.Parent = Parent or game:GetService("Lighting")
		self.Instance = BlurEffect
		self.Enabled = true
	end
	return self.Instance
end

function Blur:Set(Size)
	self.TargetSize = Size or 0
end

function Blur:Show(Size)
	self.TargetSize = Size or 24
end

function Blur:Hide()
	self.TargetSize = 0
end

function Blur:Step(Delta)
	self.Size = Utilities.Damp(self.Size, self.TargetSize, self.Speed, Delta)
	if self.Instance then
		self.Instance.Size = self.Size
	end
end

function Blur:IsVisible()
	return self.Size > 0.5
end

function Blur:Destroy()
	if self.Instance then
		self.Instance:Destroy()
		self.Instance = nil
	end
end

local BlurStack = {}
BlurStack.__index = BlurStack

function BlurStack.new()
	local self = setmetatable({}, BlurStack)
	self.Layers = {}
	return self
end

function BlurStack:Push(Size)
	local Layer = Blur.new()
	Layer:Create()
	Layer:Set(Size)
	table.insert(self.Layers, Layer)
	return Layer
end

function BlurStack:Pop()
	local Layer = table.remove(self.Layers)
	if Layer then
		Layer:Hide()
		task.delay(0.4, function()
			Layer:Destroy()
		end)
	end
end

function BlurStack:Step(Delta)
	for _, Layer in ipairs(self.Layers) do
		Layer:Step(Delta)
	end
end

function BlurStack:Clear()
	for _, Layer in ipairs(self.Layers) do
		Layer:Destroy()
	end
	self.Layers = {}
end

Blur.Stack = BlurStack

return Blur

end

Modules["Animations.Glow"] = function()
local Utilities = VoidRequire("Core.Utilities")

local Glow = {}
Glow.__index = Glow

function Glow.new(Instance, Options)
	local self = setmetatable({}, Glow)
	self.Instance = Instance
	self.Color = Options and Options.Color or Color3.fromRGB(120, 170, 255)
	self.Intensity = Options and Options.Intensity or 0
	self.TargetIntensity = Options and Options.Intensity or 0
	self.Speed = Options and Options.Speed or 10
	self.PulseSpeed = Options and Options.PulseSpeed or 2
	self.PulseAmount = Options and Options.PulseAmount or 0
	self.Pulsing = false
	self.Stroke = nil
	self.Gradient = nil
	self._Time = 0
	self:Setup()
	return self
end

function Glow:Setup()
	local Stroke = Instance.new("UIStroke")
	Stroke.Color = self.Color
	Stroke.Thickness = 1
	Stroke.Transparency = 1 - self.Intensity
	Stroke.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
	Stroke.Parent = self.Instance
	self.Stroke = Stroke
end

function Glow:SetColor(Color)
	self.Color = Color
	if self.Stroke then
		self.Stroke.Color = Color
	end
end

function Glow:SetIntensity(Intensity)
	self.TargetIntensity = Utilities.Clamp(Intensity, 0, 1)
end

function Glow:Show(Intensity)
	self.TargetIntensity = Utilities.Clamp(Intensity or 0.8, 0, 1)
end

function Glow:Hide()
	self.TargetIntensity = 0
end

function Glow:StartPulse(Amount, Speed)
	self.Pulsing = true
	self.PulseAmount = Amount or 0.2
	self.PulseSpeed = Speed or 2
end

function Glow:StopPulse()
	self.Pulsing = false
end

function Glow:Step(Delta)
	self._Time = self._Time + Delta
	local Target = self.TargetIntensity
	if self.Pulsing then
		Target = self.TargetIntensity + math.sin(self._Time * self.PulseSpeed) * self.PulseAmount
		Target = Utilities.Clamp(Target, 0, 1)
	end
	self.Intensity = Utilities.Damp(self.Intensity, Target, self.Speed, Delta)
	if self.Stroke then
		self.Stroke.Transparency = 1 - self.Intensity
		self.Stroke.Color = self.Color
	end
end

function Glow:Destroy()
	if self.Stroke then
		self.Stroke:Destroy()
		self.Stroke = nil
	end
end

local Bloom = {}
Bloom.__index = Bloom

function Bloom.new()
	local self = setmetatable({}, Bloom)
	self.Intensity = 0
	self.TargetIntensity = 0
	self.Speed = 8
	self.Instance = nil
	return self
end

function Bloom:Create(Parent)
	local Success, BloomEffect = pcall(function()
		return Instance.new("BloomEffect")
	end)
	if Success and BloomEffect then
		BloomEffect.Intensity = self.Intensity
		BloomEffect.Threshold = 0.7
		BloomEffect.Size = 24
		BloomEffect.Parent = Parent or game:GetService("Lighting")
		self.Instance = BloomEffect
	end
	return self.Instance
end

function Bloom:Set(Intensity)
	self.TargetIntensity = Intensity or 0
end

function Bloom:Step(Delta)
	self.Intensity = Utilities.Damp(self.Intensity, self.TargetIntensity, self.Speed, Delta)
	if self.Instance then
		self.Instance.Intensity = self.Intensity
	end
end

function Bloom:Destroy()
	if self.Instance then
		self.Instance:Destroy()
		self.Instance = nil
	end
end

Glow.Bloom = Bloom

return Glow

end

Modules["Animations.Particles"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Physics = VoidRequire("Animations.Physics")
local Spring = VoidRequire("Animations.Spring")

local Particles = {}
Particles.__index = Particles

function Particles.new(Container)
	local self = setmetatable({}, Particles)
	self.Container = Container
	self.Field = Physics.Field.new()
	self.Emitters = {}
	self.MaxParticles = 400
	self.RenderEnabled = true
	self._Pool = {}
	self._Active = {}
	return self
end

function Particles:CreateParticle(Properties)
	local Particle = Physics.Particle.new(Properties)
	local Frame = self:GetFromPool()
	Frame.Position = UDim2.fromOffset(Particle.Position.X, Particle.Position.Y)
	Frame.BackgroundColor3 = Particle.Color
	Frame.Size = UDim2.fromOffset(Particle.Size, Particle.Size)
	Frame.Visible = true
	Particle._Frame = Frame
	table.insert(self._Active, Particle)
	self.Field:AddParticle(Particle)
	return Particle
end

function Particles:GetFromPool()
	if #self._Pool > 0 then
		return table.remove(self._Pool)
	end
	local Frame = Utilities.Create("Frame", {
		BackgroundTransparency = 0,
		BorderSizePixel = 0,
		AnchorPoint = Vector2.new(0.5, 0.5),
		ZIndex = 50,
		Parent = self.Container,
	})
	local Corner = Utilities.Roundify(Frame, 999)
	return Frame
end

function Particles:ReturnToPool(Frame)
	Frame.Visible = false
	table.insert(self._Pool, Frame)
end

function Particles:Emit(Count, Config)
	Count = Count or 10
	Config = Config or {}
	local Center = Config.Position or Vector2.new(0, 0)
	local Spread = Config.Spread or 360
	local Speed = Config.Speed or 60
	local Life = Config.Life or 1
	local Size = Config.Size or 4
	local Color = Config.Color or Color3.fromRGB(140, 180, 255)
	local Shape = Config.Shape or "Circle"
	local Gravity = Config.Gravity or Vector2.new(0, 0)
	for _ = 1, Count do
		if #self._Active >= self.MaxParticles then
			break
		end
		local Angle = math.rad(math.random(0, 360))
		local Velocity = Vector2.new(math.cos(Angle), math.sin(Angle)) * (Speed * (0.5 + math.random() * 0.5))
		self:CreateParticle({
			Position = Center,
			Velocity = Velocity,
			Life = Life * (0.6 + math.random() * 0.6),
			Size = Size * (0.6 + math.random() * 0.8),
			Color = Color,
			Shape = Shape,
			Gravity = Gravity,
			Drag = Config.Drag or 0.6,
		})
	end
end

function Particles:Orbit(Center, Count, Radius, Color)
	Count = Count or 12
	for I = 1, Count do
		local Angle = (I / Count) * math.pi * 2
		local Position = Center + Vector2.new(math.cos(Angle), math.sin(Angle)) * Radius
		local Tangent = Vector2.new(-math.sin(Angle), math.cos(Angle)) * 40
		self:CreateParticle({
			Position = Position,
			Velocity = Tangent,
			Life = 999,
			Size = 3,
			Color = Color or Color3.fromRGB(150, 190, 255),
			Drag = 0,
			Gravity = Vector2.new(0, 0),
		})
	end
end

function Particles:Step(Delta)
	self.Field:Step(Delta)
	for Index = #self._Active, 1, -1 do
		local Particle = self._Active[Index]
		if not Particle.Alive then
			if Particle._Frame then
				self:ReturnToPool(Particle._Frame)
			end
			table.remove(self._Active, Index)
		else
			local Frame = Particle._Frame
			if Frame then
				Frame.Position = UDim2.fromOffset(Particle.Position.X, Particle.Position.Y)
				Frame.BackgroundColor3 = Particle.Color
				local Scale = Particle:GetAlpha()
				Frame.BackgroundTransparency = 1 - Scale
				Frame.Size = UDim2.fromOffset(Particle.Size * (0.5 + Scale * 0.5), Particle.Size * (0.5 + Scale * 0.5))
			end
		end
	end
end

function Particles:GetActiveCount()
	return #self._Active
end

function Particles:Clear()
	for _, Particle in ipairs(self._Active) do
		if Particle._Frame then
			self:ReturnToPool(Particle._Frame)
		end
	end
	self._Active = {}
	self.Field:Clear()
end

function Particles:Destroy()
	self:Clear()
	for _, Frame in ipairs(self._Pool) do
		Frame:Destroy()
	end
	self._Pool = {}
end

return Particles

end

Modules["Animations.Physics"] = function()
local Utilities = VoidRequire("Core.Utilities")

local Physics = {}
Physics.__index = Physics

function Physics.new(Initial)
	local self = setmetatable({}, Physics)
	self.Position = Initial and Initial.Position or Vector2.new(0, 0)
	self.Velocity = Initial and Initial.Velocity or Vector2.new(0, 0)
	self.Acceleration = Initial and Initial.Acceleration or Vector2.new(0, 0)
	self.Drag = Initial and Initial.Drag or 0.1
	self.Mass = Initial and Initial.Mass or 1
	self.Gravity = Initial and Initial.Gravity or Vector2.new(0, 0)
	self.Bounds = Initial and Initial.Bounds
	self.Restitution = Initial and Initial.Restitution or 0.6
	self.Friction = Initial and Initial.Friction or 0.98
	return self
end

function Physics:ApplyForce(Force)
	self.Acceleration = self.Acceleration + Force / self.Mass
end

function Physics:ApplyImpulse(Impulse)
	self.Velocity = self.Velocity + Impulse / self.Mass
end

function Physics:SetBounds(Min, Max)
	self.Bounds = { Min = Min, Max = Max }
end

function Physics:Step(Delta)
	Delta = math.min(Delta, 1 / 30)
	self.Velocity = self.Velocity + (self.Acceleration + self.Gravity) * Delta
	self.Velocity = self.Velocity * (1 - self.Drag * Delta)
	self.Position = self.Position + self.Velocity * Delta
	if self.Bounds then
		local Min = self.Bounds.Min
		local Max = self.Bounds.Max
		if self.Position.X < Min.X then
			self.Position = Vector2.new(Min.X, self.Position.Y)
			self.Velocity = Vector2.new(-self.Velocity.X * self.Restitution, self.Velocity.Y * self.Friction)
		elseif self.Position.X > Max.X then
			self.Position = Vector2.new(Max.X, self.Position.Y)
			self.Velocity = Vector2.new(-self.Velocity.X * self.Restitution, self.Velocity.Y * self.Friction)
		end
		if self.Position.Y < Min.Y then
			self.Position = Vector2.new(self.Position.X, Min.Y)
			self.Velocity = Vector2.new(self.Velocity.X * self.Friction, -self.Velocity.Y * self.Restitution)
		elseif self.Position.Y > Max.Y then
			self.Position = Vector2.new(self.Position.X, Max.Y)
			self.Velocity = Vector2.new(self.Velocity.X * self.Friction, -self.Velocity.Y * self.Restitution)
		end
	end
	self.Acceleration = Vector2.new(0, 0)
end

function Physics:IsResting()
	return self.Velocity.Magnitude < 0.05
end

local Particle = {}
Particle.__index = Particle

function Particle.new(Properties)
	local self = setmetatable({}, Particle)
	self.Position = Properties.Position or Vector2.new(0, 0)
	self.Velocity = Properties.Velocity or Vector2.new(0, 0)
	self.Acceleration = Properties.Acceleration or Vector2.new(0, 0)
	self.Life = Properties.Life or 1
	self.MaxLife = Properties.Life or 1
	self.Size = Properties.Size or 4
	self.Color = Properties.Color or Color3.fromRGB(255, 255, 255)
	self.Alpha = Properties.Alpha or 1
	self.Rotation = Properties.Rotation or 0
	self.AngularVelocity = Properties.AngularVelocity or 0
	self.Shape = Properties.Shape or "Circle"
	self.Drag = Properties.Drag or 0.5
	self.Gravity = Properties.Gravity or Vector2.new(0, 0)
	self.Alive = true
	return self
end

function Particle:Step(Delta)
	self.Velocity = self.Velocity + (self.Acceleration + self.Gravity) * Delta
	self.Velocity = self.Velocity * (1 - self.Drag * Delta)
	self.Position = self.Position + self.Velocity * Delta
	self.Rotation = self.Rotation + self.AngularVelocity * Delta
	self.Life = self.Life - Delta
	if self.Life <= 0 then
		self.Alive = false
	end
end

function Particle:GetAlpha()
	return self.Alpha * Utilities.Clamp(self.Life / self.MaxLife, 0, 1)
end

Physics.Particle = Particle

local Field = {}
Field.__index = Field

function Field.new()
	local self = setmetatable({}, Field)
	self.Forces = {}
	self.Particles = {}
	return self
end

function Field:AddForce(Force)
	table.insert(self.Forces, Force)
end

function Field:AddParticle(Particle)
	table.insert(self.Particles, Particle)
end

function Field:Step(Delta)
	for Index = #self.Particles, 1, -1 do
		local P = self.Particles[Index]
		for _, Force in ipairs(self.Forces) do
			Force(P, Delta)
		end
		P:Step(Delta)
		if not P.Alive then
			table.remove(self.Particles, Index)
		end
	end
end

function Field:GetCount()
	return #self.Particles
end

function Field:Clear()
	self.Particles = {}
end

Physics.Field = Field

return Physics

end

Modules["Animations.Spring"] = function()
local Utilities = VoidRequire("Core.Utilities")

local Spring = {}
Spring.__index = Spring

function Spring.new(Initial, Stiffness, Damping, Mass, Velocity)
	local self = setmetatable({}, Spring)
	self.Value = Initial or 0
	self.Target = Initial or 0
	self.Velocity = Velocity or 0
	self.Stiffness = Stiffness or 170
	self.Damping = Damping or 22
	self.Mass = Mass or 1
	self.Precision = 0.001
	self.Changed = nil
	return self
end

function Spring:SetTarget(Target)
	self.Target = Target
end

function Spring:Impulse(Velocity)
	self.Velocity = self.Velocity + Velocity
end

function Spring:SetValue(Value)
	self.Value = Value
	self.Velocity = 0
end

function Spring:Step(Delta)
	Delta = math.min(Delta, 1 / 30)
	local Force = -self.Stiffness * (self.Value - self.Target)
	local Damping = -self.Damping * self.Velocity
	local Acceleration = (Force + Damping) / self.Mass
	self.Velocity = self.Velocity + Acceleration * Delta
	self.Value = self.Value + self.Velocity * Delta
	if math.abs(self.Velocity) < self.Precision and math.abs(self.Value - self.Target) < self.Precision then
		self.Value = self.Target
		self.Velocity = 0
		return true
	end
	return false
end

function Spring:IsSettled()
	return self.Value == self.Target and self.Velocity == 0
end

function Spring:Snap()
	self.Value = self.Target
	self.Velocity = 0
end

local Spring2D = {}
Spring2D.__index = Spring2D

function Spring2D.new(InitialX, InitialY, Stiffness, Damping)
	local self = setmetatable({}, Spring2D)
	self.X = Spring.new(InitialX or 0, Stiffness, Damping)
	self.Y = Spring.new(InitialY or 0, Stiffness, Damping)
	return self
end

function Spring2D:SetTarget(X, Y)
	self.X:SetTarget(X)
	self.Y:SetTarget(Y)
end

function Spring2D:Step(Delta)
	local DoneX = self.X:Step(Delta)
	local DoneY = self.Y:Step(Delta)
	return DoneX and DoneY
end

function Spring2D:Get()
	return self.X.Value, self.Y.Value
end

local SpringColor = {}
SpringColor.__index = SpringColor

function SpringColor.new(Initial, Stiffness, Damping)
	local self = setmetatable({}, SpringColor)
	local R, G, B = Initial.R, Initial.G, Initial.B
	self.R = Spring.new(R, Stiffness, Damping)
	self.G = Spring.new(G, Stiffness, Damping)
	self.B = Spring.new(B, Stiffness, Damping)
	return self
end

function SpringColor:SetTarget(Color)
	self.R:SetTarget(Color.R)
	self.G:SetTarget(Color.G)
	self.B:SetTarget(Color.B)
end

function SpringColor:Step(Delta)
	self.R:Step(Delta)
	self.G:Step(Delta)
	self.B:Step(Delta)
end

function SpringColor:Get()
	return Color3.new(self.R.Value, self.G.Value, self.B.Value)
end

local SpringNumber = Spring

Spring.Spring2D = Spring2D
Spring.SpringColor = SpringColor
Spring.Number = SpringNumber

return Spring

end

Modules["Animations.Tween"] = function()
local Utilities = VoidRequire("Core.Utilities")

local Tween = {}
Tween.__index = Tween

local EasingFunctions = {
	Linear = function(T) return T end,
	QuadIn = function(T) return T * T end,
	QuadOut = function(T) return 1 - (1 - T) * (1 - T) end,
	QuadInOut = function(T) return T < 0.5 and 2 * T * T or 1 - (-2 * T + 2) ^ 2 / 2 end,
	CubicIn = function(T) return T ^ 3 end,
	CubicOut = function(T) return 1 - (1 - T) ^ 3 end,
	CubicInOut = function(T) return T < 0.5 and 4 * T ^ 3 or 1 - (-2 * T + 2) ^ 3 / 2 end,
	QuartIn = function(T) return T ^ 4 end,
	QuartOut = function(T) return 1 - (1 - T) ^ 4 end,
	QuartInOut = function(T) return T < 0.5 and 8 * T ^ 4 or 1 - (-2 * T + 2) ^ 4 / 2 end,
	ExpoIn = function(T) return T == 0 and 0 or 2 ^ (10 * T - 10) end,
	ExpoOut = function(T) return T == 1 and 1 or 1 - 2 ^ (-10 * T) end,
	ExpoInOut = function(T)
		if T == 0 then return 0 end
		if T == 1 then return 1 end
		return T < 0.5 and 2 ^ (20 * T - 10) / 2 or (2 - 2 ^ (-20 * T + 10)) / 2
	end,
	CircIn = function(T) return 1 - math.sqrt(1 - T ^ 2) end,
	CircOut = function(T) return math.sqrt(1 - (T - 1) ^ 2) end,
	CircInOut = function(T)
		return T < 0.5 and (1 - math.sqrt(1 - (2 * T) ^ 2)) / 2 or (math.sqrt(1 - (-2 * T + 2) ^ 2) + 1) / 2
	end,
	BackIn = Utilities.EaseOutBack,
	BackOut = function(T) return 1 + 2.70158 * (T - 1) ^ 3 + 1.70158 * (T - 1) ^ 2 end,
	BackInOut = function(T)
		local C1 = 1.70158
		local C2 = C1 * 1.525
		return T < 0.5 and ((2 * T) ^ 2 * ((C2 + 1) * 2 * T - C2)) / 2 or ((2 * T - 2) ^ 2 * ((C2 + 1) * (T * 2 - 2) + C2) + 2) / 2
	end,
	ElasticIn = function(T)
		if T == 0 then return 0 end
		if T == 1 then return 1 end
		local C4 = (2 * math.pi) / 3
		return -(2 ^ (10 * T - 10)) * math.sin((T * 10 - 10.75) * C4)
	end,
	ElasticOut = Utilities.EaseOutElastic,
	ElasticInOut = function(T)
		if T == 0 then return 0 end
		if T == 1 then return 1 end
		local C5 = (2 * math.pi) / 4.5
		return T < 0.5 and -(2 ^ (20 * T - 10) * math.sin((20 * T - 11.125) * C5)) / 2 or (2 ^ (-20 * T + 10) * math.sin((20 * T - 11.125) * C5)) / 2 + 1
	end,
	BounceIn = function(T)
		return 1 - Utilities.EaseOutBounce(1 - T)
	end,
	BounceOut = Utilities.EaseOutBounce,
	BounceInOut = function(T)
		return T < 0.5 and (1 - Utilities.EaseOutBounce(1 - 2 * T)) / 2 or (1 + Utilities.EaseOutBounce(2 * T - 1)) / 2
	end,
	SineIn = function(T) return 1 - math.cos((T * math.pi) / 2) end,
	SineOut = Utilities.EaseInOutSine and function(T) return math.sin((T * math.pi) / 2) end,
