EasingFunctions.SineOut = function(T) return math.sin((T * math.pi) / 2) end

function Tween.GetEasing(Name)
	return EasingFunctions[Name] or EasingFunctions.QuadOut
end

function Tween.new(Options)
	local self = setmetatable({}, Tween)
	self.Duration = Options.Duration or 0.4
	self.Easing = Tween.GetEasing(Options.Easing or "QuadOut")
	self.Delay = Options.Delay or 0
	self.OnUpdate = Options.OnUpdate
	self.OnComplete = Options.OnComplete
	self.OnStart = Options.OnStart
	self.Elapsed = 0
	self.Started = false
	self.Completed = false
	self.Paused = false
	self.Reversed = false
	self.Yoyo = Options.Yoyo or false
	self.RepeatCount = Options.RepeatCount or 0
	self.RepeatIndex = 0
	self.From = Options.From
	self.To = Options.To
	self.Value = Options.From
	self._Direction = 1
	return self
end

function Tween:Start()
	self.Started = true
	self.Elapsed = 0
	if self.OnStart then
		self.OnStart()
	end
	return self
end

function Tween:Play()
	return self:Start()
end

function Tween:Step(Delta)
	if not self.Started or self.Completed or self.Paused then
		return
	end
	if self.Delay > 0 then
		self.Delay = self.Delay - Delta
		if self.Delay > 0 then
			return
		end
		Delta = -self.Delay
		self.Delay = 0
	end
	self.Elapsed = self.Elapsed + Delta * self._Direction
	local Progress = Utilities.Clamp(self.Elapsed / self.Duration, 0, 1)
	local Eased = self.Easing(Progress)
	if self.From ~= nil and self.To ~= nil then
		self.Value = Utilities.Lerp(self.From, self.To, Eased)
	end
	if self.OnUpdate then
		self.OnUpdate(self.Value, Eased, Progress)
	end
	if Progress >= 1 then
		if self.Yoyo and self._Direction == 1 then
			self._Direction = -1
			self.Elapsed = self.Duration
		elseif self.RepeatCount > 0 or self.RepeatCount == -1 then
			self.RepeatIndex = self.RepeatIndex + 1
			if self.RepeatCount == -1 or self.RepeatIndex < self.RepeatCount then
				self.Elapsed = 0
				self._Direction = 1
			else
				self:Finish()
			end
		else
			self:Finish()
		end
	end
end

function Tween:Finish()
	self.Completed = true
	self.Value = self.To
	if self.OnComplete then
		self.OnComplete()
	end
end

function Tween:Pause()
	self.Paused = true
end

function Tween:Resume()
	self.Paused = false
end

function Tween:Cancel()
	self.Completed = true
end

function Tween:IsCompleted()
	return self.Completed
end

function Tween:IsActive()
	return self.Started and not self.Completed
end

local Timeline = {}
Timeline.__index = Timeline

function Timeline.new()
	local self = setmetatable({}, Timeline)
	self.Tracks = {}
	self.Tweens = {}
	self.Elapsed = 0
	self.Duration = 0
	self.Playing = false
	self.Completed = false
	self.OnComplete = nil
	return self
end

function Timeline:Add(Tween, Offset)
	Offset = Offset or 0
	Tween._Offset = Offset
	table.insert(self.Tweens, Tween)
	self.Duration = math.max(self.Duration, Offset + Tween.Duration)
	return self
end

function Timeline:Track(Name)
	local Track = Timeline.new()
	self.Tracks[Name] = Track
	return Track
end

function Timeline:Play()
	self.Playing = true
	self.Elapsed = 0
	self.Completed = false
	for _, Tween in ipairs(self.Tweens) do
		Tween:Start()
	end
	return self
end

function Timeline:Step(Delta)
	if not self.Playing or self.Completed then
		return
	end
	self.Elapsed = self.Elapsed + Delta
	local AllDone = true
	for _, Tween in ipairs(self.Tweens) do
		if self.Elapsed >= (Tween._Offset or 0) then
			Tween:Step(Delta)
		end
		if not Tween.Completed then
			AllDone = false
		end
	end
	if AllDone then
		self.Completed = true
		self.Playing = false
		if self.OnComplete then
			self.OnComplete()
		end
	end
end

function Timeline:Stop()
	self.Playing = false
end

Tween.Timeline = Timeline
Tween.Easings = EasingFunctions

return Tween

end

Modules["Assets.Fonts"] = function()
local Fonts = {}

Fonts.Primary = Enum.Font.Gotham
Fonts.Bold = Enum.Font.GothamBold
Fonts.Semibold = Enum.Font.GothamMedium
Fonts.Medium = Enum.Font.GothamMedium
Fonts.Light = Enum.Font.Gotham
Fonts.Thin = Enum.Font.Gotham
Fonts.Mono = Enum.Font.Code
Fonts.Display = Enum.Font.GothamBold
Fonts.Rounded = Enum.Font.Gotham
Fonts.Heading = Enum.Font.GothamBold
Fonts.Body = Enum.Font.Gotham
Fonts.Caption = Enum.Font.Gotham
Fonts.Numeric = Enum.Font.GothamMedium

Fonts.Scale = {
	Display = 28,
	Title = 20,
	Header = 16,
	Subheader = 15,
	Body = 14,
	Caption = 12,
	Small = 11,
	Micro = 10,
	Tiny = 9,
}

Fonts.Weight = {
	Light = Enum.FontWeight.Light,
	Regular = Enum.FontWeight.Regular,
	Medium = Enum.FontWeight.Medium,
	Bold = Enum.FontWeight.Bold,
	Heavy = Enum.FontWeight.Heavy,
}

function Fonts.Get(Name)
	return Fonts[Name] or Fonts.Primary
end

function Fonts.Size(Name)
	return Fonts.Scale[Name] or 14
end

function Fonts.Resolve(Options)
	Options = Options or {}
	local Font = Fonts.Get(Options.Family or "Primary")
	local Size = Options.Size or Fonts.Size(Options.Scale or "Body")
	return Font, Size
end

function Fonts.Pair(Family, Scale)
	return Fonts.Get(Family), Fonts.Size(Scale)
end

Fonts.Measure = {
	Display = 1.1,
	Title = 1.2,
	Header = 1.25,
	Body = 1.35,
	Caption = 1.4,
	Small = 1.45,
}

function Fonts.LineHeight(Scale)
	return Fonts.Measure[Scale] or 1.3
end

return Fonts

end

