Modules["Core.Animation"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Scheduler = VoidRequire("Core.Scheduler")
local Events = VoidRequire("Core.Events")
local Spring = VoidRequire("Animations.Spring")
local Tween = VoidRequire("Animations.Tween")
local Physics = VoidRequire("Animations.Physics")
local Blur = VoidRequire("Animations.Blur")
local Glow = VoidRequire("Animations.Glow")
local Particles = VoidRequire("Animations.Particles")

local Animation = {}
Animation.__index = Animation

function Animation.new()
	local self = setmetatable({}, Animation)
	self.Scheduler = Scheduler.new()
	self.Springs = {}
	self.Tweens = {}
	self.Timelines = {}
	self.Blurs = {}
	self.Glows = {}
	self.ParticleSystems = {}
	self.Updated = Events.new()
	self._Task = self.Scheduler:AddTask(function(Delta)
		self:Update(Delta)
	end, "Render")
	return self
end

function Animation:Update(Delta)
	for Index = #self.Springs, 1, -1 do
		local SpringItem = self.Springs[Index]
		local Settled = SpringItem.Spring:Step(Delta)
		if SpringItem.OnUpdate then
			SpringItem.OnUpdate(SpringItem.Spring.Value)
		end
		if Settled then
			if SpringItem.OnComplete then
				SpringItem.OnComplete(SpringItem.Spring.Value)
			end
			table.remove(self.Springs, Index)
		end
	end

	for Index = #self.Tweens, 1, -1 do
		local TweenItem = self.Tweens[Index]
		TweenItem:Step(Delta)
		if TweenItem.Completed then
			table.remove(self.Tweens, Index)
		end
	end

	for Index = #self.Timelines, 1, -1 do
		local Timeline = self.Timelines[Index]
		Timeline:Step(Delta)
		if Timeline.Completed then
			table.remove(self.Timelines, Index)
		end
	end

	for _, Blur in ipairs(self.Blurs) do
		Blur:Step(Delta)
	end

	for _, Glow in ipairs(self.Glows) do
		Glow:Step(Delta)
	end

	for _, ParticleSystem in ipairs(self.ParticleSystems) do
		ParticleSystem:Step(Delta)
	end

	self.Updated:Fire(Delta)
end

function Animation:Spring(Initial, Options)
	Options = Options or {}
	local SpringItem = Spring.new(
		Initial,
		Options.Stiffness,
		Options.Damping,
		Options.Mass,
		Options.Velocity
	)
	local Wrapper = {
		Spring = SpringItem,
		OnUpdate = Options.OnUpdate,
		OnComplete = Options.OnComplete,
	}
	table.insert(self.Springs, Wrapper)
	return SpringItem
end

function Animation:Tween(Options)
	local TweenItem = Tween.new(Options)
	TweenItem:Start()
	table.insert(self.Tweens, TweenItem)
	return TweenItem
end

function Animation:Timeline()
	local Timeline = Tween.Timeline.new()
	table.insert(self.Timelines, Timeline)
	return Timeline
end

function Animation:Blur()
	local BlurItem = Blur.new()
	table.insert(self.Blurs, BlurItem)
	return BlurItem
end

function Animation:Glow(Instance, Options)
	local GlowItem = Glow.new(Instance, Options)
	table.insert(self.Glows, GlowItem)
	return GlowItem
end

function Animation:Particles(Container)
	local ParticleSystem = Particles.new(Container)
	table.insert(self.ParticleSystems, ParticleSystem)
	return ParticleSystem
end

function Animation:TrackSpring(SpringItem, OnUpdate, OnComplete)
	local Wrapper = {
		Spring = SpringItem,
		OnUpdate = OnUpdate,
		OnComplete = OnComplete,
	}
	table.insert(self.Springs, Wrapper)
	return SpringItem
end

function Animation:Animate(Instance, Property, Goal, Options)
	Options = Options or {}
	local Current = Instance[Property]
	local IsColor = typeof(Current) == "Color3"
	local IsUDim2 = typeof(Current) == "UDim2"
	local IsNumber = type(Current) == "number"
	local IsVector2 = typeof(Current) == "Vector2"

	if Options.Spring then
		if IsColor then
			local SpringColor = Spring.SpringColor.new(Current, Options.Stiffness, Options.Damping)
			SpringColor:SetTarget(Goal)
			return self:TrackSpring(SpringColor, function(Color)
				Instance[Property] = Color
			end)
		elseif IsNumber then
			local S = self:Spring(Current, {
				Stiffness = Options.Stiffness,
				Damping = Options.Damping,
				OnUpdate = function(Value)
					Instance[Property] = Value
				end,
			})
			S:SetTarget(Goal)
			return S
		end
	else
		if IsColor then
			local From = Current
			return self:Tween({
				Duration = Options.Duration or 0.3,
				Easing = Options.Easing or "QuadOut",
				Delay = Options.Delay or 0,
				OnUpdate = function(_, _, Progress)
					Instance[Property] = Color3.new(
						Utilities.Lerp(From.R, Goal.R, Progress),
						Utilities.Lerp(From.G, Goal.G, Progress),
						Utilities.Lerp(From.B, Goal.B, Progress)
					)
				end,
			})
		elseif IsUDim2 then
			local From = Current
			return self:Tween({
				Duration = Options.Duration or 0.3,
				Easing = Options.Easing or "QuadOut",
				Delay = Options.Delay or 0,
				OnUpdate = function(_, _, Progress)
					Instance[Property] = UDim2.new(
						Utilities.Lerp(From.X.Scale, Goal.X.Scale, Progress),
						Utilities.Lerp(From.X.Offset, Goal.X.Offset, Progress),
						Utilities.Lerp(From.Y.Scale, Goal.Y.Scale, Progress),
						Utilities.Lerp(From.Y.Offset, Goal.Y.Offset, Progress)
					)
				end,
			})
		elseif IsNumber then
			local From = Current
			return self:Tween({
				Duration = Options.Duration or 0.3,
				Easing = Options.Easing or "QuadOut",
				Delay = Options.Delay or 0,
				OnUpdate = function(_, _, Progress)
					Instance[Property] = Utilities.Lerp(From, Goal, Progress)
				end,
			})
		elseif IsVector2 then
			local From = Current
			return self:Tween({
				Duration = Options.Duration or 0.3,
				Easing = Options.Easing or "QuadOut",
				Delay = Options.Delay or 0,
				OnUpdate = function(_, _, Progress)
					Instance[Property] = Vector2.new(
						Utilities.Lerp(From.X, Goal.X, Progress),
						Utilities.Lerp(From.Y, Goal.Y, Progress)
					)
				end,
			})
		end
	end
end

function Animation:Sequence(Steps)
	local Timeline = self:Timeline()
	local Offset = 0
	for _, Step in ipairs(Steps) do
		local TweenItem = Tween.new(Step)
		TweenItem:Start()
		Timeline:Add(TweenItem, Offset)
		Offset = Offset + (Step.Offset or Step.Duration or 0.3)
	end
	return Timeline
end

function Animation:Stagger(Items, AnimateFunction, Options)
	Options = Options or {}
	local Delay = Options.Delay or 0.05
	local Timeline = self:Timeline()
	for Index, Item in ipairs(Items) do
		local TweenItem = AnimateFunction(Item, Index)
		if TweenItem then
			Timeline:Add(TweenItem, (Index - 1) * Delay)
		end
	end
	return Timeline
end

function Animation:Wait(Seconds)
	return self.Scheduler:Yield(Seconds)
end

function Animation:SetSpeed(Speed)
	self.Scheduler.Active = Speed > 0
end

function Animation:Shutdown()
	self.Springs = {}
	self.Tweens = {}
	self.Timelines = {}
	for _, Blur in ipairs(self.Blurs) do
		Blur:Destroy()
	end
	self.Blurs = {}
	for _, Glow in ipairs(self.Glows) do
		Glow:Destroy()
	end
	self.Glows = {}
	for _, ParticleSystem in ipairs(self.ParticleSystems) do
		ParticleSystem:Destroy()
	end
	self.ParticleSystems = {}
	self.Scheduler:Shutdown()
end

Animation.Classes = {
	Spring = Spring,
	Tween = Tween,
	Physics = Physics,
	Blur = Blur,
	Glow = Glow,
	Particles = Particles,
}

return Animation

end

Modules["Core.Application"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Events = VoidRequire("Core.Events")
local Cleanup = VoidRequire("Core.Cleanup")
local Scheduler = VoidRequire("Core.Scheduler")
local State = VoidRequire("Core.State")
local Animation = VoidRequire("Core.Animation")
local Renderer = VoidRequire("Core.Renderer")
local Window = VoidRequire("Core.Window")
local ThemeManager = VoidRequire("Themes.ThemeManager")
local ConfigManager = VoidRequire("Managers.ConfigManager")
local PluginManager = VoidRequire("Managers.PluginManager")
local NotificationManager = VoidRequire("Managers.NotificationManager")
local InputManager = VoidRequire("Managers.InputManager")
local WindowManager = VoidRequire("Managers.WindowManager")
local AssetManager = VoidRequire("Managers.AssetManager")
local LayoutManager = VoidRequire("Managers.LayoutManager")
local Icons = VoidRequire("Assets.Icons")
local Fonts = VoidRequire("Assets.Fonts")
local Images = VoidRequire("Assets.Images")
local Widgets = VoidRequire("Widgets")

local Application = {}
Application.__index = Application

function Application.new(Options)
	Options = Options or {}
	local self = setmetatable({}, Application)
	self.Options = Options
	self.Version = "2.0.0"
	self.Name = Options.Name or "VoidUI"
	self.Started = false
	self.Ready = false
	self.Cleanup = Cleanup.new()
	self.Events = Events.new()
	self.State = State.new("Booting")
	self.Scheduler = Scheduler.new()
	self.Animation = Animation.new()
	self.ThemeManager = ThemeManager.new()
	self.ConfigManager = ConfigManager.new({ Name = Options.ConfigName or "VoidUI_Config" })
	self.PluginManager = PluginManager.new()
	self.InputManager = InputManager.new()
	self.WindowManager = WindowManager.new(nil)
	self.AssetManager = AssetManager.new()
	self.LayoutManager = LayoutManager.new()
	self.Renderer = Renderer.new(self.ThemeManager, self.Animation)
	self.WindowManager.Parent = self.Renderer:GetLayer("Windows")
	self.NotificationManager = NotificationManager.new(self.Renderer:GetLayer("Notifications"), self.ThemeManager)
	self.Widgets = Widgets
	self.Windows = {}
	self.Splash = nil
	self:_Initialize()
	return self
end

function Application:_Initialize()
	local ThemeName = self.Options.Theme or "Default"
	self.ThemeManager:Set(ThemeName)
	self.Theme = self.ThemeManager
	self:_BindGlobalHotkeys()
end

function Application:_BindGlobalHotkeys()
	self.InputManager:BindHotkey("VoidUI_Hide", { Enum.KeyCode.RightShift }, function()
		self:ToggleVisibility()
	end, { Modifiers = {} })
end

function Application:ToggleVisibility()
	local Screen = self.Renderer.Screen
	Screen.Enabled = not Screen.Enabled
end

function Application:SetTheme(Name)
	self.ThemeManager:Set(Name)
	self:_ApplyThemeToWindows()
end

function Application:SetAccent(Color)
	self.ThemeManager:SetAccent(Color)
	self:_ApplyThemeToWindows()
end

function Application:_ApplyThemeToWindows()
	for _, Window in ipairs(self.Windows) do
		if Window._ApplyTheme then
			Window:_ApplyTheme()
		end
	end
end

function Application:CreateWindow(Options)
	local WindowInstance = Window.new(self, Options)
	table.insert(self.Windows, WindowInstance)
	self.WindowManager:Register(WindowInstance)
	return WindowInstance
end

function Application:GetWindow(Title)
	return self.WindowManager:FindByTitle(Title)
end

function Application:Notify(Options)
	return self.NotificationManager:Notify(Options)
end

function Application:RegisterPlugin(Plugin)
	return self.PluginManager:Register(Plugin)
end

function Application:LoadPlugin(Name, Context)
	return self.PluginManager:Load(Name, Context or self)
end

function Application:CreateConfig(Options)
	return ConfigManager.new(Options)
end

function Application:SaveConfig()
	return self.ConfigManager:Save()
end

function Application:LoadConfig()
	return self.ConfigManager:Load()
end

function Application:GetStats()
	return {
		Windows = #self.Windows,
		Theme = self.ThemeManager:GetName(),
		Accent = self.ThemeManager:GetAccent(),
		Assets = self.AssetManager:GetStats(),
		Plugins = self.PluginManager:Count(),
		FPS = math.round(1 / (game:GetService("RunService").RenderStepped:Wait() or 1 / 60)),
	}
end

function Application:RunStartupSequence(Callback)
	if self.Started then
		return
	end
	self.Started = true
	self.State:Set("Starting")
	self.Splash = self:_BuildSplash()
	self:_PlayStartup(function()
		self.Ready = true
		self.State:Set("Ready")
		self.Events:Fire("Ready")
		if Callback then
			pcall(Callback)
		end
	end)
end

function Application:_BuildSplash()
	local Theme = self.ThemeManager
	local Layer = self.Renderer:GetLayer("Splash")
	local Screen = Utilities.Create("Frame", {
		Name = "Splash",
		BackgroundColor3 = Theme.Color("Background"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		ZIndex = 100,
		Parent = Layer,
	})
	local Gradient = Utilities.AddGradient(Screen, Theme.Gradient("Background"), 90)
	Gradient.Transparency = NumberSequence.new(0.6)

	local Center = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(400, 300),
		Position = UDim2.fromScale(0.5, 0.5),
		AnchorPoint = Vector2.new(0.5, 0.5),
		ZIndex = 101,
		Parent = Screen,
	})

	local Core = Utilities.Create("Frame", {
		Name = "Core",
		BackgroundColor3 = Theme.Color("Accent"),
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(40, 40),
		Position = UDim2.fromScale(0.5, 0.4),
		AnchorPoint = Vector2.new(0.5, 0.5),
		ZIndex = 102,
		Parent = Center,
	})
	local CoreCorner = Utilities.Roundify(Core, 999)
	local CoreGlow = Utilities.AddStroke(Core, Theme.Color("AccentGlow"), 2)
	CoreGlow.Transparency = 0.4

	local ParticleContainer = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(300, 300),
		Position = UDim2.fromScale(0.5, 0.4),
		AnchorPoint = Vector2.new(0.5, 0.5),
		ZIndex = 101,
		Parent = Center,
	})
	local Particles = self.Animation:Particles(ParticleContainer)

	local Logo = Icons.Create("Void", Theme.Color("AccentLight"), 64)
	Logo.Position = UDim2.fromScale(0.5, 0.4)
	Logo.AnchorPoint = Vector2.new(0.5, 0.5)
	Logo.ZIndex = 103
	Logo.Parent = Center
	Logo.ImageTransparency = 1

	local Title = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 30),
		Position = UDim2.fromScale(0.5, 0.62),
		AnchorPoint = Vector2.new(0.5, 0.5),
		Font = Theme.Typography("FontBold"),
		TextSize = 28,
		TextColor3 = Theme.Color("Text"),
		Text = "VoidUI",
		ZIndex = 103,
		Parent = Center,
	})
	Title.TextTransparency = 1

	local Status = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 20),
		Position = UDim2.fromScale(0.5, 0.72),
		AnchorPoint = Vector2.new(0.5, 0.5),
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("CaptionSize"),
		TextColor3 = Theme.Color("TextMuted"),
		Text = "Initializing VoidUI",
		ZIndex = 103,
		Parent = Center,
	})
	Status.TextTransparency = 1

	local ProgressBar = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(0.6, 0, 0, 4),
		Position = UDim2.fromScale(0.5, 0.8),
		AnchorPoint = Vector2.new(0.5, 0.5),
		ZIndex = 103,
		Parent = Center,
	})
	local BarCorner = Utilities.Roundify(ProgressBar, 999)
	local ProgressFill = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Accent"),
		BorderSizePixel = 0,
		Size = UDim2.new(0, 0, 1, 0),
		ZIndex = 104,
		Parent = ProgressBar,
	})
	local FillCorner = Utilities.Roundify(ProgressFill, 999)
	local FillGradient = Utilities.AddGradient(ProgressFill, Theme.Gradient("Accent"), 90)

	return {
		Screen = Screen,
		Center = Center,
		Core = Core,
		Particles = Particles,
		Logo = Logo,
		Title = Title,
		Status = Status,
		ProgressBar = ProgressBar,
		ProgressFill = ProgressFill,
	}
end

function Application:_PlayStartup(Done)
	local Splash = self.Splash
	local Theme = self.ThemeManager
	local Steps = {
		"Initializing VoidUI",
		"Loading modules",
		"Loading renderer",
		"Loading themes",
		"Loading widgets",
		"Loading plugins",
		"Ready",
	}
	local Index = 1

	local function Next()
		if Index > #Steps then
			self:_FinishStartup(Done)
			return
		end
		local Step = Steps[Index]
		Splash.Status.Text = Step
		self.Animation:Animate(Splash.Status, "TextTransparency", 0, { Duration = 0.2 })
		local Progress = Index / #Steps
		self.Animation:Animate(Splash.ProgressFill, "Size", UDim2.new(Progress, 0, 1, 0), { Duration = 0.4, Easing = "QuadOut" })
		Index = Index + 1
		task.delay(0.45, Next)
	end

	self.Animation:Animate(Splash.Screen, "BackgroundTransparency", 0, { Duration = 0.4 })
	self.Animation:Animate(Splash.Core, "Size", UDim2.fromOffset(60, 60), { Duration = 0.5, Easing = "BackOut" })
	Splash.Particles:Orbit(Vector2.new(150, 120), 14, 90, Theme.Color("AccentGlow"))
	task.delay(0.4, function()
		self.Animation:Animate(Splash.Logo, "ImageTransparency", 0, { Duration = 0.4 })
		self.Animation:Animate(Splash.Title, "TextTransparency", 0, { Duration = 0.4 })
		self.Animation:Animate(Splash.Core, "Size", UDim2.fromOffset(50, 50), { Duration = 0.6, Easing = "QuadOut" })
		task.delay(0.3, Next)
	end)
end

function Application:_FinishStartup(Done)
	local Splash = self.Splash
	self.Animation:Animate(Splash.Screen, "BackgroundTransparency", 1, { Duration = 0.5, Easing = "QuadIn" })
	task.delay(0.5, function()
		Splash.Screen:Destroy()
		Splash.Particles:Destroy()
		self.Splash = nil
		pcall(Done)
	end)
end

function Application:ShowSplash()
	if not self.Splash then
		self.Splash = self:_BuildSplash()
	end
end

function Application:HideSplash()
	if self.Splash then
		self.Splash.Screen:Destroy()
		self.Splash = nil
	end
end

function Application:CreateCommandPalette()
	local Palette = self.Widgets.CommandPalette.new(self)
	return Palette
end

function Application:CreateContextMenu(Items)
	return self.Widgets.ContextMenu.new(self, Items)
end

function Application:CreateTooltip(Text)
	return self.Widgets.Tooltip.new(self, Text)
end

function Application:CreateModal(Options)
	return self.Widgets.Modal.new(self, Options)
end

function Application:CreateBreadcrumbs(Items)
	return self.Widgets.Breadcrumbs.new(self, Items)
end

function Application:SubscribeReady(Callback)
	return self.Events:Connect(function(Event)
		if Event == "Ready" then
			pcall(Callback)
		end
	end)
end

function Application:SubscribeThemeChanged(Callback)
	return self.ThemeManager:Subscribe(Callback)
end

function Application:SubscribeAccentChanged(Callback)
	return self.ThemeManager:SubscribeAccent(Callback)
end

function Application:Destroy()
	for _, Window in ipairs(self.Windows) do
		if Window.Destroy then
			pcall(Window.Destroy, Window)
		end
	end
	self.Windows = {}
	self.PluginManager:Destroy()
	self.InputManager:Destroy()
	self.NotificationManager:Destroy()
	self.WindowManager:Destroy()
	self.AssetManager:Destroy()
	self.LayoutManager:Destroy()
	self.ConfigManager:Destroy()
	self.Renderer:Destroy()
	self.Animation:Shutdown()
	self.Scheduler:Shutdown()
	self.Cleanup:Destroy()
	self.Started = false
	self.Ready = false
end

return Application

end

Modules["Core.Cleanup"] = function()
local Utilities = VoidRequire("Core.Utilities")

local Cleanup = {}
Cleanup.__index = Cleanup

function Cleanup.new()
	local self = setmetatable({}, Cleanup)
	self.Items = {}
	self.Connections = {}
	self.Tasks = {}
	self.Instances = {}
	self.Callbacks = {}
	self.Destroyed = false
	return self
end

function Cleanup:Add(Item)
	if Item == nil then
		return Item
	end
	if type(Item) == "function" then
		table.insert(self.Callbacks, Item)
	elseif typeof(Item) == "RBXScriptConnection" then
		table.insert(self.Connections, Item)
	elseif typeof(Item) == "Instance" then
		table.insert(self.Instances, Item)
	elseif type(Item) == "table" and Item.Disconnect then
		table.insert(self.Connections, Item)
	elseif type(Item) == "table" and Item.Cancel then
		table.insert(self.Tasks, Item)
	else
		table.insert(self.Items, Item)
	end
	return Item
end

function Cleanup:AddConnection(Connection)
	table.insert(self.Connections, Connection)
	return Connection
end

function Cleanup:AddInstance(Instance)
	table.insert(self.Instances, Instance)
	return Instance
end

function Cleanup:AddCallback(Callback)
	table.insert(self.Callbacks, Callback)
	return Callback
end

function Cleanup:AddTask(Task)
	table.insert(self.Tasks, Task)
	return Task
end

function Cleanup:Track(Object)
	return self:Add(Object)
end

function Cleanup:Untrack(Object)
	local Lists = { self.Connections, self.Instances, self.Tasks, self.Callbacks, self.Items }
	for _, List in ipairs(Lists) do
		local Index = Utilities.TableFind(List, Object)
		if Index then
			table.remove(List, Index)
			return true
		end
	end
	return false
end

function Cleanup:DisconnectConnections()
	for _, Connection in ipairs(self.Connections) do
		if Connection.Connected then
			Connection:Disconnect()
		end
	end
	self.Connections = {}
end

function Cleanup:DestroyInstances()
	for _, Instance in ipairs(self.Instances) do
		if Instance and Instance.Parent then
			pcall(function()
				Instance:Destroy()
			end)
		end
	end
	self.Instances = {}
end

function Cleanup:CancelTasks()
	for _, Task in ipairs(self.Tasks) do
		if Task.Cancel then
			pcall(Task.Cancel)
		end
	end
	self.Tasks = {}
end

function Cleanup:RunCallbacks()
	for _, Callback in ipairs(self.Callbacks) do
		pcall(Callback)
	end
	self.Callbacks = {}
end

function Cleanup:Destroy()
	if self.Destroyed then
		return
	end
	self.Destroyed = true
	self:DisconnectConnections()
	self:CancelTasks()
	self:DestroyInstances()
	self:RunCallbacks()
	self.Items = {}
end

function Cleanup:IsDestroyed()
	return self.Destroyed
end

local CleanupGroup = {}
CleanupGroup.__index = CleanupGroup

function CleanupGroup.new()
	local self = setmetatable({}, CleanupGroup)
	self.Groups = {}
	return self
end

function CleanupGroup:Create(Name)
	local Group = Cleanup.new()
	self.Groups[Name] = Group
	return Group
end

function CleanupGroup:Get(Name)
	return self.Groups[Name]
end

function CleanupGroup:Destroy(Name)
	if Name then
		local Group = self.Groups[Name]
		if Group then
			Group:Destroy()
			self.Groups[Name] = nil
		end
	else
		for _, Group in pairs(self.Groups) do
			Group:Destroy()
		end
		self.Groups = {}
	end
end

Cleanup.Group = CleanupGroup

return Cleanup

end

Modules["Core.Events"] = function()
local Utilities = VoidRequire("Core.Utilities")

local Events = {}
Events.__index = Events

function Events.new()
	local self = setmetatable({}, Events)
	self.Connections = {}
	self.ConnectionsByKey = {}
	return self
end

function Events:Connect(Callback)
	local Connection = {
		Callback = Callback,
		Connected = true,
		Disconnect = function()
			self:Disconnect(Connection)
		end,
	}
	table.insert(self.Connections, Connection)
	return Connection
end

function Events:ConnectOnce(Callback)
	local Connection
	Connection = self:Connect(function(...)
		Connection:Disconnect()
		Utilities.SafeCall(Callback, ...)
	end)
	return Connection
end

function Events:Disconnect(Connection)
	if Connection then
		Connection.Connected = false
		local Index = Utilities.TableFind(self.Connections, Connection)
		if Index then
			table.remove(self.Connections, Index)
		end
	end
end

function Events:DisconnectAll()
	for _, Connection in ipairs(self.Connections) do
		Connection.Connected = false
	end
	self.Connections = {}
end

function Events:Fire(...)
	for Index = #self.Connections, 1, -1 do
		local Connection = self.Connections[Index]
		if Connection.Connected then
			Utilities.SafeCall(Connection.Callback, ...)
		else
			table.remove(self.Connections, Index)
		end
	end
end

function Events:Wait()
	local Thread = coroutine.running()
	local Connection
	Connection = self:ConnectOnce(function(...)
		task.spawn(Thread, ...)
	end)
	return coroutine.yield()
end

function Events:GetConnectionCount()
	return #self.Connections
end

function Events:HasConnections()
	return #self.Connections > 0
end

local Signal = Events

local EventBus = {}
EventBus.__index = EventBus

function EventBus.new()
	local self = setmetatable({}, EventBus)
	self.Channels = {}
	return self
end

function EventBus:GetChannel(Name)
	if not self.Channels[Name] then
		self.Channels[Name] = Events.new()
	end
	return self.Channels[Name]
end

function EventBus:Emit(Name, ...)
	local Channel = self.Channels[Name]
	if Channel then
		Channel:Fire(...)
	end
end

function EventBus:Subscribe(Name, Callback)
	return self:GetChannel(Name):Connect(Callback)
end

function EventBus:Unsubscribe(Name, Connection)
	local Channel = self.Channels[Name]
	if Channel and Connection then
		Channel:Disconnect(Connection)
	end
end

function EventBus:Clear(Name)
	if Name then
		if self.Channels[Name] then
			self.Channels[Name]:DisconnectAll()
		end
	else
		for _, Channel in pairs(self.Channels) do
			Channel:DisconnectAll()
		end
	end
end

Events.Signal = Signal
Events.EventBus = EventBus
Events.Bus = EventBus.new()

return Events

end

Modules["Core.Renderer"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Cleanup = VoidRequire("Core.Cleanup")
local Events = VoidRequire("Core.Events")
local Glow = VoidRequire("Animations.Glow")
local Blur = VoidRequire("Animations.Blur")
local Particles = VoidRequire("Animations.Particles")

local Renderer = {}
Renderer.__index = Renderer

function Renderer.new(Theme, Animation)
	local self = setmetatable({}, Renderer)
	self.Theme = Theme
	self.Animation = Animation
	self.Screen = nil
	self.Layers = {}
	self.Cleanup = Cleanup.new()
	self.Updated = Events.new()
	self.Glows = {}
	self.Blurs = {}
	self.ParticleSystems = {}
	self.CursorLight = nil
	self:_Initialize()
	return self
end

function Renderer:_Initialize()
	local Player = game:GetService("Players").LocalPlayer
	local PlayerGui = Player and Player:WaitForChild("PlayerGui")
	local Screen = Utilities.Create("ScreenGui", {
		Name = "VoidUI",
		ResetOnSpawn = false,
		ZIndexBehavior = Enum.ZIndexBehavior.Sibling,
		DisplayOrder = 1000,
		IgnoreGuiInset = true,
	})
	if PlayerGui then
		Screen.Parent = PlayerGui
	else
		Screen.Parent = game:GetService("CoreGui")
	end
	self.Screen = Screen
	self.Cleanup:AddInstance(Screen)

	self.Layers.Background = self:_CreateLayer("Background", 1)
	self.Layers.Windows = self:_CreateLayer("Windows", 2)
	self.Layers.Overlays = self:_CreateLayer("Overlays", 3)
	self.Layers.Notifications = self:_CreateLayer("Notifications", 4)
	self.Layers.Cursor = self:_CreateLayer("Cursor", 5)
	self.Layers.Splash = self:_CreateLayer("Splash", 6)

	self:_BuildCursorLight()
end

function Renderer:_CreateLayer(Name, ZIndex)
	local Layer = Utilities.Create("Frame", {
		Name = Name,
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		ZIndex = ZIndex,
		Parent = self.Screen,
	})
	return Layer
end

function Renderer:_BuildCursorLight()
	if not self.Theme.Effect("CursorLightEnabled") then
		return
	end
	local Light = Utilities.Create("Frame", {
		Name = "CursorLight",
		BackgroundColor3 = self.Theme.Color("Accent"),
		BackgroundTransparency = 0.85,
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(220, 220),
		AnchorPoint = Vector2.new(0.5, 0.5),
		ZIndex = 0,
		Parent = self.Layers.Cursor,
	})
	local Corner = Utilities.Roundify(Light, 999)
	local Gradient = Utilities.AddGradient(Light, ColorSequence.new({
		ColorSequenceKeypoint.new(0, self.Theme.Color("AccentGlow")),
		ColorSequenceKeypoint.new(1, Color3.new(0, 0, 0)),
	}), 0)
	Gradient.Transparency = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.6),
		NumberSequenceKeypoint.new(1, 1),
	})
	self.CursorLight = Light

	local UserInputService = game:GetService("UserInputService")
	local Connection = UserInputService.InputChanged:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseMovement then
			Light.Position = UDim2.fromOffset(Input.Position.X, Input.Position.Y)
		end
	end)
	self.Cleanup:AddConnection(Connection)
end

function Renderer:CreateCard(Properties, Layer)
	local Theme = self.Theme
	local Card = Utilities.Create("Frame", Utilities.Merge({
		BackgroundColor3 = Theme.Color("Card"),
		BorderSizePixel = 0,
	}, Properties or {}))
	local Corner = Utilities.Roundify(Card, Theme.Layout("Radius"))
	local Stroke = Utilities.AddStroke(Card, Theme.Color("Border"), Theme.Layout("BorderThickness"))
	if Theme.Effect("GlowEnabled") then
		local GlowEffect = self.Animation:Glow(Card, {
			Color = Theme.Color("AccentGlow"),
			Intensity = 0,
		})
		self.Glows[Card] = GlowEffect
	end
	local LayerFrame = Layer and self.Layers[Layer] or self.Layers.Windows
	Card.Parent = LayerFrame
	return Card
end

function Renderer:CreateShadow(Frame, Intensity)
	local Theme = self.Theme
	if not Theme.Effect("ShadowEnabled") then
		return nil
	end
	local Shadow = Utilities.Create("ImageLabel", {
		Name = "Shadow",
		BackgroundColor3 = Theme.Color("Shadow"),
		BackgroundTransparency = 1 - (Intensity or Theme.Layout("ShadowOpacity")),
		BorderSizePixel = 0,
		Size = UDim2.new(1, Theme.Layout("ShadowBlur"), 1, Theme.Layout("ShadowBlur")),
		Position = UDim2.fromOffset(-Theme.Layout("ShadowBlur") / 2, -Theme.Layout("ShadowBlur") / 2),
		ZIndex = Frame.ZIndex - 1,
		Image = "rbxassetid://0",
		ImageTransparency = 1,
		Parent = Frame,
	})
	local Corner = Utilities.Roundify(Shadow, Theme.Layout("Radius") + Theme.Layout("ShadowBlur") / 2)
	return Shadow
end

function Renderer:CreateBlur(Parent)
	local BlurEffect = self.Animation:Blur()
	BlurEffect:Create(Parent or game:GetService("Lighting"))
	table.insert(self.Blurs, BlurEffect)
	return BlurEffect
end

function Renderer:CreateParticles(Container)
	local ParticleSystem = self.Animation:Particles(Container)
	table.insert(self.ParticleSystems, ParticleSystem)
	return ParticleSystem
end

function Renderer:SetGlow(Frame, Intensity)
	local GlowEffect = self.Glows[Frame]
	if GlowEffect then
		GlowEffect:SetIntensity(Intensity)
	end
end

function Renderer:ShowGlow(Frame, Intensity)
	local GlowEffect = self.Glows[Frame]
	if GlowEffect then
		GlowEffect:Show(Intensity)
	end
end

function Renderer:HideGlow(Frame)
	local GlowEffect = self.Glows[Frame]
	if GlowEffect then
		GlowEffect:Hide()
	end
end

function Renderer:ApplyTheme(Theme)
	self.Theme = Theme
end

function Renderer:GetLayer(Name)
	return self.Layers[Name]
end

function Renderer:SetDisplayOrder(Order)
	self.Screen.DisplayOrder = Order
end

function Renderer:SetIgnoreGuiInset(Ignore)
	self.Screen.IgnoreGuiInset = Ignore
end

function Renderer:Flash(Frame, Color)
	local Original = Frame.BackgroundColor3
	self.Animation:Animate(Frame, "BackgroundColor3", Color or self.Theme.Color("Accent"), {
		Duration = 0.15,
		Easing = "QuadOut",
	})
	task.delay(0.15, function()
		self.Animation:Animate(Frame, "BackgroundColor3", Original, {
			Duration = 0.3,
			Easing = "QuadOut",
		})
	end)
end

function Renderer:Pulse(Frame, Scale)
	Scale = Scale or 1.05
	local Original = Frame.Size
	self.Animation:Tween({
		Duration = 0.12,
		Easing = "BackOut",
		OnUpdate = function(_, _, Progress)
			local S = Utilities.Lerp(1, Scale, Progress)
			Frame.Size = UDim2.new(Original.X.Scale * S, Original.X.Offset * S, Original.Y.Scale * S, Original.Y.Offset * S)
		end,
	})
	task.delay(0.12, function()
		self.Animation:Tween({
			Duration = 0.2,
			Easing = "BackOut",
			OnUpdate = function(_, _, Progress)
				local S = Utilities.Lerp(Scale, 1, Progress)
				Frame.Size = UDim2.new(Original.X.Scale * S, Original.X.Offset * S, Original.Y.Scale * S, Original.Y.Offset * S)
			end,
		})
	end)
end

function Renderer:Destroy()
	for _, GlowEffect in pairs(self.Glows) do
		GlowEffect:Destroy()
	end
	self.Glows = {}
	for _, BlurEffect in ipairs(self.Blurs) do
		BlurEffect:Destroy()
	end
	self.Blurs = {}
	for _, ParticleSystem in ipairs(self.ParticleSystems) do
		ParticleSystem:Destroy()
	end
	self.ParticleSystems = {}
	self.Cleanup:Destroy()
	self.Updated:DisconnectAll()
end

return Renderer

end

Modules["Core.Scheduler"] = function()
local RunService = game:GetService("RunService")

local Scheduler = {}
Scheduler.__index = Scheduler

function Scheduler.new()
	local self = setmetatable({}, Scheduler)
	self.Tasks = {}
	self.HeartbeatTasks = {}
	self.RenderTasks = {}
	self.SteppedTasks = {}
	self.Timers = {}
	self.Active = true
	self.LastTick = tick()
	self:Initialize()
	return self
end

function Scheduler:Initialize()
	self.HeartbeatConnection = RunService.Heartbeat:Connect(function(Delta)
		if not self.Active then
			return
		end
		self:ProcessTimers(Delta)
		self:ProcessTasks(self.HeartbeatTasks, Delta)
	end)

	self.RenderConnection = RunService.RenderStepped:Connect(function(Delta)
		if not self.Active then
			return
		end
		self:ProcessTasks(self.RenderTasks, Delta)
	end)

	self.SteppedConnection = RunService.Stepped:Connect(function(_, Delta)
		if not self.Active then
			return
		end
		self:ProcessTasks(self.SteppedTasks, Delta)
	end)
end

function Scheduler:ProcessTasks(Tasks, Delta)
	for Index = #Tasks, 1, -1 do
		local Task = Tasks[Index]
		if Task.Paused then
			continue
		end
		local Success, ShouldRemove = pcall(Task.Function, Delta, tick())
		if not Success then
			warn("[VoidUI] Scheduler task error:", ShouldRemove)
			table.remove(Tasks, Index)
		elseif ShouldRemove == true then
			table.remove(Tasks, Index)
		end
	end
end

function Scheduler:ProcessTimers(Delta)
	for Index = #self.Timers, 1, -1 do
		local Timer = self.Timers[Index]
		if Timer.Paused then
			continue
		end
		Timer.Elapsed = Timer.Elapsed + Delta
		if Timer.Elapsed >= Timer.Duration then
			Timer.Elapsed = Timer.Elapsed - Timer.Duration
			local Success, Result = pcall(Timer.Callback)
			if not Success then
				warn("[VoidUI] Timer error:", Result)
			end
			if Timer.Repeat == false then
				table.remove(self.Timers, Index)
			end
		end
	end
end

function Scheduler:AddTask(Function, Mode)
	local Task = {
		Function = Function,
		Paused = false,
	}
	Mode = Mode or "Heartbeat"
	local List = self.HeartbeatTasks
	if Mode == "Render" then
		List = self.RenderTasks
	elseif Mode == "Stepped" then
		List = self.SteppedTasks
	end
	table.insert(List, Task)
	return {
		Pause = function()
			Task.Paused = true
		end,
		Resume = function()
			Task.Paused = false
		end,
		Cancel = function()
			Task.Function = function()
				return true
			end
		end,
	}
end

function Scheduler:Every(Duration, Callback, Repeat)
	local Timer = {
		Duration = Duration,
		Elapsed = 0,
		Callback = Callback,
		Repeat = Repeat ~= false,
		Paused = false,
	}
	table.insert(self.Timers, Timer)
	return {
		Pause = function()
			Timer.Paused = true
		end,
		Resume = function()
			Timer.Paused = false
		end,
		Cancel = function()
			Timer.Callback = function() end
			Timer.Repeat = false
		end,
	}
end

function Scheduler:After(Duration, Callback)
	return self:Every(Duration, Callback, false)
end

function Scheduler:Once(Function, Mode)
	return self:AddTask(function()
		Function()
		return true
	end, Mode)
end

function Scheduler:Delay(Duration, Callback)
	return self:After(Duration, Callback)
end

function Scheduler:Yield(Seconds)
	local Thread = coroutine.running()
	self:After(Seconds, function()
		task.spawn(Thread)
	end)
	return coroutine.yield()
end

function Scheduler:SetActive(Active)
	self.Active = Active
end

function Scheduler:Shutdown()
	self.Active = false
	if self.HeartbeatConnection then
		self.HeartbeatConnection:Disconnect()
	end
	if self.RenderConnection then
		self.RenderConnection:Disconnect()
	end
	if self.SteppedConnection then
		self.SteppedConnection:Disconnect()
	end
	self.Tasks = {}
	self.HeartbeatTasks = {}
	self.RenderTasks = {}
	self.SteppedTasks = {}
	self.Timers = {}
end

return Scheduler

end

Modules["Core.State"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Events = VoidRequire("Core.Events")

local State = {}
State.__index = State

function State.new(Initial)
	local self = setmetatable({}, State)
	self.Value = Initial
	self.Changed = Events.new()
	self._Connections = {}
	return self
end

function State:Get()
	return self.Value
end

function State:Set(NewValue, Silent)
	if NewValue == self.Value then
		return
	end
	local OldValue = self.Value
	self.Value = NewValue
	if not Silent then
		self.Changed:Fire(NewValue, OldValue)
	end
end

function State:Update(Transform)
	self:Set(Transform(self.Value))
end

function State:Subscribe(Callback)
	return self.Changed:Connect(Callback)
end

function State:SubscribeOnce(Callback)
	return self.Changed:ConnectOnce(Callback)
end

function State:Map(Transform)
	local Derived = State.new(Transform(self.Value))
	self:Subscribe(function(Value)
		Derived:Set(Transform(Value))
	end)
	return Derived
end

function State:Combine(Other, Combine)
	local Derived = State.new(Combine(self.Value, Other:Get()))
	local function Update()
		Derived:Set(Combine(self.Value, Other:Get()))
	end
	self:Subscribe(Update)
	Other:Subscribe(Update)
	return Derived
end

function State:Destroy()
	self.Changed:DisconnectAll()
	self.Value = nil
end

local Store = {}
Store.__index = Store

function Store.new(Initial)
	local self = setmetatable({}, Store)
	self.State = {}
	self.Changed = Events.new()
	if Initial then
		for Key, Value in pairs(Initial) do
			self.State[Key] = State.new(Value)
		end
	end
	return self
end

function Store:Create(Key, Initial)
	self.State[Key] = State.new(Initial)
	return self.State[Key]
end

function Store:Get(Key)
	local S = self.State[Key]
	return S and S:Get()
end

function Store:Set(Key, Value)
	local S = self.State[Key]
	if S then
		S:Set(Value)
		self.Changed:Fire(Key, Value)
	end
end

function Store:Subscribe(Key, Callback)
	local S = self.State[Key]
	if S then
		return S:Subscribe(Callback)
	end
	return nil
end

function Store:SubscribeAll(Callback)
	return self.Changed:Connect(Callback)
end

function Store:Destroy()
	for _, S in pairs(self.State) do
		S:Destroy()
	end
	self.State = {}
	self.Changed:DisconnectAll()
end

State.Store = Store

return State

end

Modules["Core.Utilities"] = function()
local Utilities = {}

local RunService = game:GetService("RunService")
local HttpService = game:GetService("HttpService")
local TweenService = game:GetService("TweenService")

function Utilities.DeepCopy(Original)
	local Copy
	if type(Original) == "table" then
		Copy = {}
		for Key, Value in pairs(Original) do
			Copy[Utilities.DeepCopy(Key)] = Utilities.DeepCopy(Value)
		end
	else
		Copy = Original
	end
	return Copy
end

function Utilities.ShallowCopy(Original)
	local Copy = {}
	for Key, Value in pairs(Original) do
		Copy[Key] = Value
	end
	return Copy
end

function Utilities.Merge(Base, Override)
	local Result = Utilities.ShallowCopy(Base)
	if Override then
		for Key, Value in pairs(Override) do
			if type(Value) == "table" and type(Result[Key]) == "table" then
				Result[Key] = Utilities.Merge(Result[Key], Value)
			else
				Result[Key] = Value
			end
		end
	end
	return Result
end

function Utilities.Clone(Table)
	return Utilities.DeepCopy(Table)
end

function Utilities.IsTable(Value)
	return type(Value) == "table"
end

function Utilities.IsCallable(Value)
	return type(Value) == "function"
end

function Utilities.IsInstance(Value)
	return typeof(Value) == "Instance"
end

function Utilities.IsColor3(Value)
	return typeof(Value) == "Color3"
end

function Utilities.IsUDim2(Value)
	return typeof(Value) == "UDim2"
end

function Utilities.IsVector2(Value)
	return typeof(Value) == "Vector2"
end

function Utilities.Clamp(Value, Minimum, Maximum)
	return math.max(Minimum, math.min(Maximum, Value))
end

function Utilities.Lerp(Start, Goal, Alpha)
	return Start + (Goal - Start) * Alpha
end

function Utilities.InverseLerp(Start, Goal, Value)
	if Start == Goal then
		return 0
	end
	return (Value - Start) / (Goal - Start)
end

function Utilities.Map(Value, InMin, InMax, OutMin, OutMax)
	return Utilities.Lerp(OutMin, OutMax, Utilities.InverseLerp(InMin, InMax, Value))
end

function Utilities.Round(Value, Precision)
	local Multiplier = 10 ^ (Precision or 0)
	return math.floor(Value * Multiplier + 0.5) / Multiplier
end

function Utilities.Snap(Value, Increment)
	if Increment <= 0 then
		return Value
	end
	return math.floor(Value / Increment + 0.5) * Increment
end

function Utilities.Sign(Value)
	if Value > 0 then
		return 1
	elseif Value < 0 then
		return -1
	end
	return 0
end

function Utilities.Approach(Current, Target, Delta)
	if Current < Target then
		return math.min(Current + Delta, Target)
	elseif Current > Target then
		return math.max(Current - Delta, Target)
	end
	return Target
end

function Utilities.Damp(Current, Target, Lambda, DeltaTime)
	return Utilities.Lerp(Current, Target, 1 - math.exp(-Lambda * DeltaTime))
end

function Utilities.Color3ToHex(Color)
	return string.format("#%02X%02X%02X", math.floor(Color.R * 255 + 0.5), math.floor(Color.G * 255 + 0.5), math.floor(Color.B * 255 + 0.5))
end

function Utilities.HexToColor3(Hex)
	Hex = Hex:gsub("#", "")
	local Length = #Hex
	if Length == 3 then
		Hex = Hex:gsub("(.)", "%1%1")
	elseif Length == 8 then
		Hex = Hex:sub(1, 6)
	end
	local Red = tonumber(Hex:sub(1, 2), 16) or 0
	local Green = tonumber(Hex:sub(3, 4), 16) or 0
	local Blue = tonumber(Hex:sub(5, 6), 16) or 0
	return Color3.fromRGB(Red, Green, Blue)
end

function Utilities.Color3ToRGB(Color)
	return math.floor(Color.R * 255 + 0.5), math.floor(Color.G * 255 + 0.5), math.floor(Color.B * 255 + 0.5)
end

function Utilities.RGBToColor3(Red, Green, Blue)
	return Color3.fromRGB(Red, Green, Blue)
end

function Utilities.HSVToColor3(Hue, Saturation, Value)
	return Color3.fromHSV(Hue, Saturation, Value)
end

function Utilities.Color3ToHSV(Color)
	return Color3.toHSV(Color)
end

function Utilities.Lighten(Color, Amount)
	local Hue, Saturation, Value = Color3.toHSV(Color)
	return Color3.fromHSV(Hue, Saturation, Utilities.Clamp(Value + Amount, 0, 1))
end

function Utilities.Darken(Color, Amount)
	local Hue, Saturation, Value = Color3.toHSV(Color)
	return Color3.fromHSV(Hue, Saturation, Utilities.Clamp(Value - Amount, 0, 1))
end

function Utilities.Saturate(Color, Amount)
	local Hue, Saturation, Value = Color3.toHSV(Color)
	return Color3.fromHSV(Hue, Utilities.Clamp(Saturation + Amount, 0, 1), Value)
end

function Utilities.Desaturate(Color, Amount)
	local Hue, Saturation, Value = Color3.toHSV(Color)
	return Color3.fromHSV(Hue, Utilities.Clamp(Saturation - Amount, 0, 1), Value)
end

function Utilities.MixColors(First, Second, Alpha)
	return Color3.new(
		Utilities.Lerp(First.R, Second.R, Alpha),
		Utilities.Lerp(First.G, Second.G, Alpha),
		Utilities.Lerp(First.B, Second.B, Alpha)
	)
end

function Utilities.Complementary(Color)
	local Hue, Saturation, Value = Color3.toHSV(Color)
	return Color3.fromHSV((Hue + 0.5) % 1, Saturation, Value)
end

function Utilities.WithAlpha(Color, Alpha)
	return Color3.new(Color.R, Color.G, Color.B)
end

function Utilities.GenerateAccent(BaseColor)
	local Palette = {}
	Palette.Base = BaseColor
	Palette.Light = Utilities.Lighten(BaseColor, 0.18)
	Palette.Lighter = Utilities.Lighten(BaseColor, 0.34)
	Palette.Dark = Utilities.Darken(BaseColor, 0.18)
	Palette.Darker = Utilities.Darken(BaseColor, 0.34)
	Palette.Complement = Utilities.Complementary(BaseColor)
	Palette.Glow = Utilities.MixColors(BaseColor, Color3.new(1, 1, 1), 0.25)
	return Palette
end

function Utilities.ContrastColor(Background)
	local Luminance = 0.2126 * Background.R + 0.7152 * Background.G + 0.0722 * Background.B
	if Luminance > 0.5 then
		return Color3.new(0.08, 0.08, 0.1)
	else
		return Color3.new(0.96, 0.96, 0.98)
	end
end

function Utilities.UUID()
	return HttpService:GenerateGUID(false)
end

function Utilities.RandomString(Length)
	local Characters = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
	local Result = ""
	for _ = 1, (Length or 8) do
		local Index = math.random(1, #Characters)
		Result = Result .. Characters:sub(Index, Index)
	end
	return Result
end

function Utilities.Split(String, Separator)
	local Parts = {}
	local Pattern = string.format("([^%s]+)", Separator or " ")
	for Part in string.gmatch(String, Pattern) do
		table.insert(Parts, Part)
	end
	return Parts
end

function Utilities.Trim(String)
	return String:match("^%s*(.-)%s*$")
end

function Utilities.StartsWith(String, Prefix)
	return String:sub(1, #Prefix) == Prefix
end

function Utilities.EndsWith(String, Suffix)
	return String:sub(-#Suffix) == Suffix
end

function Utilities.Contains(String, Substring)
	return string.find(String, Substring, 1, true) ~= nil
end

function Utilities.Capitalize(String)
	return String:sub(1, 1):upper() .. String:sub(2)
end

function Utilities.TitleCase(String)
	local Result = String:gsub("(%a)([%w_']*)", function(First, Rest)
		return First:upper() .. Rest:lower()
	end)
	return Result
end

function Utilities.FormatNumber(Value)
	local Suffixes = { "", "K", "M", "B", "T" }
	local Index = 1
	local Number = Value
	while Number >= 1000 and Index < #Suffixes do
		Number = Number / 1000
		Index = Index + 1
	end
	if Index == 1 then
		return tostring(Value)
	end
	return string.format("%.2f%s", Number, Suffixes[Index])
end

function Utilities.FormatTime(Seconds)
	local Minutes = math.floor(Seconds / 60)
	local Remaining = math.floor(Seconds % 60)
	return string.format("%02d:%02d", Minutes, Remaining)
end

function Utilities.TableLength(Table)
	local Count = 0
	for _ in pairs(Table) do
		Count = Count + 1
	end
	return Count
end

function Utilities.TableKeys(Table)
	local Keys = {}
	for Key in pairs(Table) do
		table.insert(Keys, Key)
	end
	return Keys
end

function Utilities.TableValues(Table)
	local Values = {}
	for _, Value in pairs(Table) do
		table.insert(Values, Value)
	end
	return Values
end

function Utilities.TableFind(Table, Value)
	for Index, Item in pairs(Table) do
		if Item == Value then
			return Index
		end
	end
	return nil
end

function Utilities.TableContains(Table, Value)
	return Utilities.TableFind(Table, Value) ~= nil
end

function Utilities.TableFilter(Table, Predicate)
	local Result = {}
	for Index, Value in pairs(Table) do
		if Predicate(Value, Index) then
			table.insert(Result, Value)
		end
	end
	return Result
end

function Utilities.TableMap(Table, Transform)
	local Result = {}
	for Index, Value in pairs(Table) do
		Result[Index] = Transform(Value, Index)
	end
	return Result
end

function Utilities.TableReverse(Table)
	local Result = {}
	local Length = #Table
	for Index = 1, Length do
		Result[Index] = Table[Length - Index + 1]
	end
	return Result
end

function Utilities.TableFlatten(Table)
	local Result = {}
	local function Flatten(Input)
		for _, Value in ipairs(Input) do
			if type(Value) == "table" then
				Flatten(Value)
			else
				table.insert(Result, Value)
			end
		end
	end
	Flatten(Table)
	return Result
end

function Utilities.SortBy(Table, Key, Ascending)
	local Result = Utilities.ShallowCopy(Table)
	table.sort(Result, function(First, Second)
		if Ascending == false then
			return First[Key] > Second[Key]
		end
		return First[Key] < Second[Key]
	end)
	return Result
end

function Utilities.First(Table)
	return Table[1]
end

function Utilities.Last(Table)
	return Table[#Table]
end

function Utilities.GetOrCreate(Table, Key, Default)
	if Table[Key] == nil then
		Table[Key] = Default
	end
	return Table[Key]
end

function Utilities.Try(Function, ...)
	local Success, Result = pcall(Function, ...)
	if Success then
		return true, Result
	else
		return false, Result
	end
end

function Utilities.SafeCall(Function, ...)
	if type(Function) == "function" then
		local Success, Result = pcall(Function, ...)
		if not Success then
			warn("[VoidUI] Callback error:", Result)
		end
		return Success, Result
	end
	return false
end

function Utilities.Debounce(Function, Delay)
	local LastCall = 0
	Delay = Delay or 0.1
	return function(...)
		local Now = tick()
		if Now - LastCall >= Delay then
			LastCall = Now
			return Function(...)
		end
	end
end

function Utilities.Throttle(Function, Delay)
	local LastRun = 0
	local PendingArgs
	Delay = Delay or 0.1
	return function(...)
		local Now = tick()
		PendingArgs = { ... }
		if Now - LastRun >= Delay then
			LastRun = Now
			Function(unpack(PendingArgs))
		end
	end
end

function Utilities.Delay(Duration, Function)
	local Connection
	Connection = delay(Duration, function()
		if Connection then
			Connection = nil
		end
		Utilities.SafeCall(Function)
	end)
	return Connection
end

function Utilities.Spawn(Function, ...)
	task.spawn(Function, ...)
end

function Utilities.Wait(Seconds)
	task.wait(Seconds)
end

function Utilities.IsDescendantOf(Instance, Ancestor)
	local Current = Instance
	while Current do
		if Current == Ancestor then
			return true
		end
		Current = Current.Parent
	end
	return false
end

function Utilities.FindFirstChildOfClass(Parent, ClassName)
	for _, Child in ipairs(Parent:GetChildren()) do
		if Child.ClassName == ClassName then
			return Child
		end
	end
	return nil
end

function Utilities.DestroyChildren(Parent, ClassName)
	for _, Child in ipairs(Parent:GetChildren()) do
		if not ClassName or Child.ClassName == ClassName then
			Child:Destroy()
		end
	end
end

function Utilities.SetProperty(Instance, Property, Value)
	local Success = pcall(function()
		Instance[Property] = Value
	end)
	return Success
end

function Utilities.Tween(Instance, Property, Goal, Duration, EasingStyle, EasingDirection)
	local Info = TweenInfo.new(
		Duration or 0.3,
		EasingStyle or Enum.EasingStyle.Quad,
		EasingDirection or Enum.EasingDirection.Out
	)
	local Tween = TweenService:Create(Instance, Info, { [Property] = Goal })
	Tween:Play()
	return Tween
end

function Utilities.Create(Class, Properties, Children)
	local Instance = Instance.new(Class)
	if Properties then
		for Key, Value in pairs(Properties) do
			local Success = pcall(function()
				Instance[Key] = Value
			end)
			if not Success then
				warn("[VoidUI] Failed to set property", Key, "on", Class)
			end
		end
	end
	if Children then
		for _, Child in ipairs(Children) do
			if type(Child) == "table" and Child.Instance then
				Child.Instance.Parent = Instance
			elseif typeof(Child) == "Instance" then
				Child.Parent = Instance
			end
		end
	end
	return Instance
end

function Utilities.New(Class, Properties)
	return Utilities.Create(Class, Properties)
end

function Utilities.UDim2FromOffset(X, Y)
	return UDim2.fromOffset(X, Y)
end

function Utilities.UDim2FromScale(X, Y)
	return UDim2.fromScale(X, Y)
end

function Utilities.Vector2(X, Y)
	return Vector2.new(X, Y)
end

function Utilities.Color(R, G, B)
	if type(R) == "number" and G == nil then
		return Color3.fromRGB(R, R, R)
	end
	return Color3.fromRGB(R, G, B)
end

function Utilities.GetMouse()
	local Player = game:GetService("Players").LocalPlayer
	if Player then
		return Player:GetMouse()
	end
	return nil
end

function Utilities.GetViewportSize()
	local Camera = workspace.CurrentCamera
	if Camera then
		return Camera.ViewportSize
	end
	return Vector2.new(1920, 1080)
end

function Utilities.IsStudio()
	return RunService:IsStudio()
end

function Utilities.IsRunning()
	return RunService:IsRunning()
end

function Utilities.GetDeltaTime()
	return RunService:IsRunning() and game:GetService("RunService").RenderStepped:Wait() or 0
end

function Utilities.Frame(Properties)
	return Utilities.Create("Frame", Properties)
end

function Utilities.Label(Properties)
	return Utilities.Create("TextLabel", Properties)
end

function Utilities.Button(Properties)
	return Utilities.Create("TextButton", Properties)
end

function Utilities.Image(Properties)
	return Utilities.Create("ImageLabel", Properties)
end

function Utilities.Roundify(Parent, Radius)
	local Corner = Instance.new("UICorner")
	Corner.CornerRadius = UDim.new(0, Radius or 8)
	Corner.Parent = Parent
	return Corner
end

function Utilities.AddPadding(Parent, Padding)
	local UIPadding = Instance.new("UIPadding")
	UIPadding.PaddingLeft = UDim.new(0, Padding or 8)
	UIPadding.PaddingRight = UDim.new(0, Padding or 8)
	UIPadding.PaddingTop = UDim.new(0, Padding or 8)
	UIPadding.PaddingBottom = UDim.new(0, Padding or 8)
	UIPadding.Parent = Parent
	return UIPadding
end

function Utilities.AddListLayout(Parent, Direction, Padding, Align)
	local Layout = Instance.new("UIListLayout")
	Layout.FillDirection = Direction or Enum.FillDirection.Vertical
	Layout.Padding = UDim.new(0, Padding or 6)
	Layout.SortOrder = Enum.SortOrder.LayoutOrder
	Layout.HorizontalAlignment = Align or Enum.HorizontalAlignment.Left
	Layout.VerticalAlignment = Enum.VerticalAlignment.Top
	Layout.Parent = Parent
	return Layout
end

function Utilities.AddGridLayout(Parent, CellSize, CellPadding)
	local Layout = Instance.new("UIGridLayout")
	Layout.CellSize = CellSize or UDim2.fromOffset(100, 100)
	Layout.CellPadding = CellPadding or UDim2.fromOffset(6, 6)
	Layout.SortOrder = Enum.SortOrder.LayoutOrder
	Layout.Parent = Parent
	return Layout
end

function Utilities.AddStroke(Parent, Color, Thickness, Transparency)
	local Stroke = Instance.new("UIStroke")
	Stroke.Color = Color or Color3.fromRGB(255, 255, 255)
	Stroke.Thickness = Thickness or 1
	Stroke.Transparency = Transparency or 0
	Stroke.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
	Stroke.Parent = Parent
	return Stroke
end

function Utilities.AddGradient(Parent, Colors, Rotation)
	local Gradient = Instance.new("UIGradient")
	Gradient.Color = Colors or ColorSequence.new(Color3.fromRGB(255, 255, 255))
	Gradient.Rotation = Rotation or 90
	Gradient.Parent = Parent
	return Gradient
end

function Utilities.AddAspectRatio(Parent, Ratio)
	local Constraint = Instance.new("UIAspectRatioConstraint")
	Constraint.AspectRatio = Ratio or 1
	Constraint.Parent = Parent
	return Constraint
end

function Utilities.AddScale(Parent, XScale, YScale)
	local Constraint = Instance.new("UIScale")
	Constraint.Scale = 1
	Constraint.Parent = Parent
	return Constraint
end

function Utilities.Bezier(Points, T)
	local N = #Points
	if N == 0 then
		return Vector2.new()
	elseif N == 1 then
		return Points[1]
	end
	local Result = Vector2.new()
	for I = 0, N - 1 do
		local Coefficient = Utilities.Binomial(N - 1, I) * (1 - T) ^ (N - 1 - I) * T ^ I
		Result = Result + Points[I + 1] * Coefficient
	end
	return Result
end

function Utilities.Binomial(N, K)
	if K > N then
		return 0
	end
	local Result = 1
	for I = 1, K do
		Result = Result * (N - K + I) / I
	end
	return Result
end

function Utilities.EaseInOutSine(T)
	return -(math.cos(math.pi * T) - 1) / 2
end

function Utilities.EaseOutBack(T)
	local C1 = 1.70158
	local C3 = C1 + 1
	return 1 + C3 * (T - 1) ^ 3 + C1 * (T - 1) ^ 2
end

function Utilities.EaseOutElastic(T)
	if T == 0 then
		return 0
	elseif T == 1 then
		return 1
	end
	local C4 = (2 * math.pi) / 3
	return 2 ^ (-10 * T) * math.sin((T * 10 - 0.75) * C4) + 1
end

function Utilities.EaseOutBounce(T)
	local N1 = 7.5625
	local D1 = 2.75
	if T < 1 / D1 then
		return N1 * T * T
	elseif T < 2 / D1 then
		T = T - 1.5 / D1
		return N1 * T * T + 0.75
	elseif T < 2.5 / D1 then
		T = T - 2.25 / D1
		return N1 * T * T + 0.9375
	else
		T = T - 2.625 / D1
		return N1 * T * T + 0.984375
	end
end

function Utilities.Smoothstep(Edge0, Edge1, X)
	local T = Utilities.Clamp((X - Edge0) / (Edge1 - Edge0), 0, 1)
	return T * T * (3 - 2 * T)
end

function Utilities.Distance(PointA, PointB)
	return (PointA - PointB).Magnitude
end

function Utilities.AngleBetween(VectorA, VectorB)
	return math.acos(math.clamp(VectorA.Unit:Dot(VectorB.Unit), -1, 1))
end

function Utilities.PointInBounds(Point, Min, Max)
	return Point.X >= Min.X and Point.X <= Max.X and Point.Y >= Min.Y and Point.Y <= Max.Y
end

function Utilities.WrapIndex(Index, Length)
	return ((Index - 1) % Length) + 1
end

function Utilities.Chunk(Table, Size)
	local Result = {}
	for Index = 1, #Table, Size do
		local Slice = {}
		for J = Index, math.min(Index + Size - 1, #Table) do
			table.insert(Slice, Table[J])
		end
		table.insert(Result, Slice)
	end
	return Result
end

function Utilities.UniqueId()
	return Utilities.RandomString(12)
end

function Utilities.EncodeJSON(Data)
	local Success, Result = pcall(function()
		return HttpService:JSONEncode(Data)
	end)
	if Success then
		return Result
	else
		warn("[VoidUI] JSON encode failed:", Result)
		return "{}"
	end
end

function Utilities.DecodeJSON(String)
	local Success, Result = pcall(function()
		return HttpService:JSONDecode(String)
	end)
	if Success then
		return Result
	else
		warn("[VoidUI] JSON decode failed:", Result)
		return {}
	end
end

function Utilities.VersionCompare(VersionA, VersionB)
	local PartsA = Utilities.Split(VersionA, ".")
	local PartsB = Utilities.Split(VersionB, ".")
	for I = 1, math.max(#PartsA, #PartsB) do
		local A = tonumber(PartsA[I]) or 0
		local B = tonumber(PartsB[I]) or 0
		if A > B then
			return 1
		elseif A < B then
			return -1
		end
	end
	return 0
end

return Utilities

end

Modules["Core.Window"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Events = VoidRequire("Core.Events")
local Cleanup = VoidRequire("Core.Cleanup")
local Icons = VoidRequire("Assets.Icons")

local Window = {}
Window.__index = Window

function Window.new(Application, Options)
	local self = setmetatable({}, Window)
	self.Application = Application
	self.Theme = Application.Theme
	self.Renderer = Application.Renderer
	self.Animation = Application.Animation
	self.Title = Options.Title or "VoidUI"
	self.Icon = Options.Icon or "Void"
	self.Subtitle = Options.Subtitle or ""
	self.Size = UDim2.fromOffset(
		Options.Size and Options.Size.X or self.Theme.Layout("WindowWidth"),
		Options.Size and Options.Size.Y or self.Theme.Layout("WindowHeight")
	)
	self.Position = Options.Position or UDim2.fromOffset(120, 80)
	self.ZIndex = 100
	self.Minimized = false
	self.Maximized = false
	self.Closed = false
	self.Draggable = Options.Draggable ~= false
	self.Resizable = Options.Resizable ~= false
	self.Dockable = Options.Dockable ~= false
	self.Tabs = {}
	self.ActiveTab = nil
	self.Changed = Events.new()
	self.TabChanged = Events.new()
	self.ClosedEvent = Events.new()
	self.MinimizedEvent = Events.new()
	self.Cleanup = Cleanup.new()
	self._DragData = nil
	self._ResizeData = nil
	self:_Build()
	return self
end

function Window:_Build()
	local Theme = self.Theme
	local Layer = self.Renderer:GetLayer("Windows")

	local Shadow = Utilities.Create("ImageLabel", {
		Name = "WindowShadow",
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 60, 1, 60),
		Position = UDim2.fromOffset(-30, -30),
		Image = "rbxassetid://0",
		ImageTransparency = 1,
		ZIndex = self.ZIndex - 1,
		Parent = Layer,
	})

	local Main = Utilities.Create("Frame", {
		Name = "Window",
		BackgroundColor3 = Theme.Color("Background"),
		BorderSizePixel = 0,
		Size = self.Size,
		Position = self.Position,
		ZIndex = self.ZIndex,
		ClipsDescendants = true,
		Parent = Layer,
	})
	local Corner = Utilities.Roundify(Main, Theme.Layout("RadiusLarge"))
	local Stroke = Utilities.AddStroke(Main, Theme.Color("Border"), Theme.Layout("BorderThickness"))
	self.Main = Main
	self.Shadow = Shadow

	local Gradient = Utilities.AddGradient(Main, Theme.Gradient("Background"), 90)
	Gradient.Transparency = NumberSequence.new(0.85)

	local GlowEffect = self.Animation:Glow(Main, {
		Color = Theme.Color("AccentGlow"),
		Intensity = 0.25,
	})

	local Header = Utilities.Create("Frame", {
		Name = "Header",
		BackgroundColor3 = Theme.Color("BackgroundElevated"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, Theme.Layout("HeaderHeight")),
		ZIndex = self.ZIndex + 1,
		Parent = Main,
	})
	local HeaderCorner = Utilities.Roundify(Header, Theme.Layout("RadiusLarge"))
	local HeaderClip = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, Theme.Layout("RadiusLarge")),
		ClipsDescendants = true,
		ZIndex = self.ZIndex + 1,
		Parent = Header,
	})
	local HeaderGradient = Utilities.AddGradient(Header, Theme.Gradient("Surface"), 90)
	HeaderGradient.Transparency = NumberSequence.new(0.7)

	local HeaderContent = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		ZIndex = self.ZIndex + 2,
		Parent = Header,
	})
	local HeaderLayout = Utilities.AddListLayout(HeaderContent, Enum.FillDirection.Horizontal, 10, Enum.HorizontalAlignment.Left)
	HeaderLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	HeaderLayout.Padding = UDim.new(0, 14)

	local IconFrame = Icons.Create(self.Icon, Theme.Color("Accent"), 22)
	IconFrame.LayoutOrder = 1
	IconFrame.Parent = HeaderContent

	local TitleBlock = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -200, 1, 0),
		ZIndex = self.ZIndex + 2,
		Parent = HeaderContent,
	})
	local TitleLayout = Utilities.AddListLayout(TitleBlock, Enum.FillDirection.Vertical, 0)
	local TitleLabel = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 20),
		Font = Theme.Typography("FontBold"),
		TextSize = Theme.Typography("TitleSize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Title,
		ZIndex = self.ZIndex + 2,
		Parent = TitleBlock,
	})
	local SubtitleLabel = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 12),
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("SmallSize"),
		TextColor3 = Theme.Color("TextDim"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Subtitle,
		Visible = #self.Subtitle > 0,
		ZIndex = self.ZIndex + 2,
		Parent = TitleBlock,
	})

	local Controls = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(0, 90, 1, 0),
		ZIndex = self.ZIndex + 2,
		Parent = HeaderContent,
	})
	local ControlsLayout = Utilities.AddListLayout(Controls, Enum.FillDirection.Horizontal, 4, Enum.HorizontalAlignment.Right)
	ControlsLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	ControlsLayout.Padding = UDim.new(0, 6)

	self.MinimizeButton = self:_CreateControlButton("Minus", function()
		self:Minimize()
	end)
	self.MinimizeButton.Parent = Controls
	self.MaximizeButton = self:_CreateControlButton("Square", function()
		self:ToggleMaximize()
	end)
	self.MaximizeButton.Parent = Controls
	self.CloseButton = self:_CreateControlButton("Close", function()
		self:Close()
	end, Theme.Color("Danger"))
	self.CloseButton.Parent = Controls

	local Body = Utilities.Create("Frame", {
		Name = "Body",
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, -Theme.Layout("HeaderHeight")),
		Position = UDim2.new(0, 0, 0, Theme.Layout("HeaderHeight")),
		ZIndex = self.ZIndex + 1,
		Parent = Main,
	})

	local Sidebar = Utilities.Create("Frame", {
		Name = "Sidebar",
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(0, Theme.Layout("SidebarWidth"), 1, 0),
		ZIndex = self.ZIndex + 1,
		Parent = Body,
	})
	local SidebarCorner = Utilities.Roundify(Sidebar, Theme.Layout("Radius"))
	local SidebarGradient = Utilities.AddGradient(Sidebar, Theme.Gradient("Surface"), 90)
	SidebarGradient.Transparency = NumberSequence.new(0.6)

	local TabList = Utilities.Create("ScrollingFrame", {
		Name = "TabList",
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, -20),
		Position = UDim2.new(0, 0, 0, 10),
		ScrollBarThickness = 4,
		ScrollBarImageColor3 = Theme.Color("Scrollbar"),
		ZIndex = self.ZIndex + 2,
		Parent = Sidebar,
	})
	local TabListLayout = Utilities.AddListLayout(TabList, Enum.FillDirection.Vertical, 6, Enum.HorizontalAlignment.Center)
	TabListLayout.Padding = UDim.new(0, 6)

	local Content = Utilities.Create("Frame", {
		Name = "Content",
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -Theme.Layout("SidebarWidth"), 1, 0),
		Position = UDim2.new(0, Theme.Layout("SidebarWidth"), 0, 0),
		ZIndex = self.ZIndex + 1,
		Parent = Body,
	})

	local ContentScroll = Utilities.Create("ScrollingFrame", {
		Name = "ContentScroll",
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		CanvasSize = UDim2.new(0, 0, 0, 0),
		AutomaticCanvasSize = Enum.AutomaticCanvasSize.Y,
		ScrollBarThickness = 6,
		ScrollBarImageColor3 = Theme.Color("Scrollbar"),
		ZIndex = self.ZIndex + 2,
		Parent = Content,
	})
	local ContentLayout = Utilities.AddListLayout(ContentScroll, Enum.FillDirection.Vertical, 10, Enum.HorizontalAlignment.Center)
	ContentLayout.Padding = UDim.new(0, 14)
	local ContentPadding = Utilities.AddPadding(ContentScroll, 16)

	self.Header = Header
	self.Body = Body
	self.Sidebar = Sidebar
	self.TabList = TabList
	self.Content = Content
	self.ContentScroll = ContentScroll
	self.TitleLabel = TitleLabel
	self.SubtitleLabel = SubtitleLabel
	self.GlowEffect = GlowEffect

	self:_SetupDragging()
	self:_SetupResizing()
	self:_SetupHover()

	self.Application.WindowManager:Register(self)
end

function Window:_CreateControlButton(IconName, Callback, Color)
	local Theme = self.Theme
	local Button = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("SurfaceHover"),
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(28, 28),
		AutoButtonColor = false,
		Text = "",
		ZIndex = self.ZIndex + 3,
	})
	local Corner = Utilities.Roundify(Button, Theme.Layout("RadiusSmall"))
	local Icon = Icons.Create(IconName, Color or Theme.Color("TextMuted"), 16)
	Icon.ZIndex = self.ZIndex + 4
	Icon.Parent = Button
	local HoverConnection = Button.MouseEnter:Connect(function()
		self.Animation:Animate(Button, "BackgroundColor3", Theme.Color("SurfaceActive"), { Duration = 0.15 })
		self.Animation:Animate(Icon, "ImageColor3", Color or Theme.Color("Text"), { Duration = 0.15 })
	end)
	local LeaveConnection = Button.MouseLeave:Connect(function()
		self.Animation:Animate(Button, "BackgroundColor3", Theme.Color("SurfaceHover"), { Duration = 0.15 })
		self.Animation:Animate(Icon, "ImageColor3", Color or Theme.Color("TextMuted"), { Duration = 0.15 })
	end)
	local ClickConnection = Button.MouseButton1Click:Connect(function()
		pcall(Callback)
	end)
	self.Cleanup:AddConnection(HoverConnection)
	self.Cleanup:AddConnection(LeaveConnection)
	self.Cleanup:AddConnection(ClickConnection)
	return Button
end

function Window:_SetupDragging()
	if not self.Draggable then
		return
	end
	local Dragging = false
	local StartPos
	local StartMouse
	local UserInputService = game:GetService("UserInputService")

	local Begin = self.Header.InputBegan:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 then
			Dragging = true
			StartPos = self.Main.Position
			StartMouse = Input.Position
			self.Application.WindowManager:Focus(self)
		end
	end)
	local End = UserInputService.InputEnded:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 then
			Dragging = false
		end
	end)
	local Move = UserInputService.InputChanged:Connect(function(Input)
		if Dragging and Input.UserInputType == Enum.UserInputType.MouseMovement then
			local Delta = Input.Position - StartMouse
			local NewPos = UDim2.new(StartPos.X.Scale, StartPos.X.Offset + Delta.X, StartPos.Y.Scale, StartPos.Y.Offset + Delta.Y)
			NewPos = self.Application.WindowManager:Snap(self, NewPos)
			self.Main.Position = NewPos
			self.Shadow.Position = UDim2.new(0, NewPos.X.Offset - 30, 0, NewPos.Y.Offset - 30)
			self.Position = NewPos
		end
	end)
	self.Cleanup:AddConnection(Begin)
	self.Cleanup:AddConnection(End)
	self.Cleanup:AddConnection(Move)
end

function Window:_SetupResizing()
	if not self.Resizable then
		return
	end
	local UserInputService = game:GetService("UserInputService")
	local Edges = {
		Right = Vector2.new(1, 0),
		Bottom = Vector2.new(0, 1),
		BottomRight = Vector2.new(1, 1),
	}
	for EdgeName, Direction in pairs(Edges) do
		local Handle = Utilities.Create("Frame", {
			Name = "Resize_" .. EdgeName,
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(Direction.X > 0 and 0 or 1, Direction.X > 0 and 8 or 0, Direction.Y > 0 and 0 or 1, Direction.Y > 0 and 8 or 0),
			Position = UDim2.new(Direction.X, Direction.X > 0 and -4 or 0, Direction.Y, Direction.Y > 0 and -4 or 0),
			ZIndex = self.ZIndex + 5,
			Parent = self.Main,
		})
		local Resizing = false
		local StartSize
		local StartMouse
		local Begin = Handle.InputBegan:Connect(function(Input)
			if Input.UserInputType == Enum.UserInputType.MouseButton1 then
				Resizing = true
				StartSize = self.Main.AbsoluteSize
				StartMouse = Input.Position
			end
		end)
		local End = UserInputService.InputEnded:Connect(function(Input)
			if Input.UserInputType == Enum.UserInputType.MouseButton1 then
				Resizing = false
			end
		end)
		local Move = UserInputService.InputChanged:Connect(function(Input)
			if Resizing and Input.UserInputType == Enum.UserInputType.MouseMovement then
				local Delta = Input.Position - StartMouse
				local NewX = math.max(360, StartSize.X + Delta.X * Direction.X)
				local NewY = math.max(260, StartSize.Y + Delta.Y * Direction.Y)
				self:SetSize(UDim2.fromOffset(NewX, NewY))
			end
		end)
		self.Cleanup:AddConnection(Begin)
		self.Cleanup:AddConnection(End)
		self.Cleanup:AddConnection(Move)
	end
end

function Window:_SetupHover()
	local HoverConnection = self.Main.MouseEnter:Connect(function()
		self.Renderer:ShowGlow(self.Main, 0.4)
	end)
	local LeaveConnection = self.Main.MouseLeave:Connect(function()
		self.Renderer:HideGlow(self.Main)
	end)
	self.Cleanup:AddConnection(HoverConnection)
	self.Cleanup:AddConnection(LeaveConnection)
end

function Window:CreateTab(Options)
	local Tab = self.Application.Widgets.Tabs.new(self, Options)
	table.insert(self.Tabs, Tab)
	if not self.ActiveTab then
		self:SelectTab(Tab)
	end
	return Tab
end

function Window:SelectTab(Tab)
	if self.ActiveTab == Tab then
		return
	end
	if self.ActiveTab then
		self.ActiveTab:Deselect()
	end
	self.ActiveTab = Tab
	Tab:Select()
	self.TabChanged:Fire(Tab)
end

function Window:GetActiveTab()
	return self.ActiveTab
end

function Window:SetTitle(Title)
	self.Title = Title
	self.TitleLabel.Text = Title
end

function Window:SetSubtitle(Subtitle)
	self.Subtitle = Subtitle
	self.SubtitleLabel.Text = Subtitle
	self.SubtitleLabel.Visible = #Subtitle > 0
end

function Window:SetIcon(Icon)
	self.Icon = Icon
end

function Window:SetPosition(Position)
	self.Position = Position
	self.Animation:Animate(self.Main, "Position", Position, { Duration = 0.3, Easing = "QuadOut" })
	self.Shadow.Position = UDim2.new(0, Position.X.Offset - 30, 0, Position.Y.Offset - 30)
end

function Window:SetSize(Size)
	self.Size = Size
	self.Main.Size = Size
	self.Shadow.Size = UDim2.new(1, 60, 1, 60)
end

function Window:SetZIndex(ZIndex)
	self.ZIndex = ZIndex
	self.Main.ZIndex = ZIndex
	self.Shadow.ZIndex = ZIndex - 1
end

function Window:Minimize()
	if self.Minimized then
		return
	end
	self.Minimized = true
	self.Animation:Tween({
		Duration = 0.3,
		Easing = "QuadIn",
		OnUpdate = function(_, _, Progress)
			self.Main.Size = UDim2.new(self.Size.X.Scale, self.Size.X.Offset, self.Size.Y.Scale, self.Size.Y.Offset * (1 - Progress))
			self.Main.BackgroundTransparency = Progress * 0.5
		end,
	})
	self.MinimizedEvent:Fire()
end

function Window:Restore()
	if not self.Minimized then
		return
	end
	self.Minimized = false
	self.Animation:Tween({
		Duration = 0.3,
		Easing = "QuadOut",
		OnUpdate = function(_, _, Progress)
			self.Main.Size = UDim2.new(self.Size.X.Scale, self.Size.X.Offset, self.Size.Y.Scale, self.Size.Y.Offset * Progress)
			self.Main.BackgroundTransparency = (1 - Progress) * 0.5
		end,
	})
end

function Window:ToggleMaximize()
	if self.Maximized then
		self:Restore()
		self.Maximized = false
	else
		self._PreMaximize = self.Main.Position
		self.Maximized = true
		local Viewport = Utilities.GetViewportSize()
		self.Animation:Animate(self.Main, "Size", UDim2.new(1, -20, 1, -20), { Duration = 0.35, Easing = "QuadOut" })
		self.Animation:Animate(self.Main, "Position", UDim2.fromOffset(10, 10), { Duration = 0.35, Easing = "QuadOut" })
	end
end

function Window:Unfold()
	self.Main.Size = UDim2.new(0, 0, 0, 0)
	self.Main.BackgroundTransparency = 1
	self.Animation:Tween({
		Duration = 0.6,
		Easing = "BackOut",
		OnUpdate = function(_, _, Progress)
			self.Main.Size = UDim2.new(self.Size.X.Scale * Progress, self.Size.X.Offset * Progress, self.Size.Y.Scale * Progress, self.Size.Y.Offset * Progress)
			self.Main.BackgroundTransparency = 1 - Progress
		end,
	})
end

function Window:Close()
	if self.Closed then
		return
	end
	self.Closed = true
	self.Animation:Tween({
		Duration = 0.3,
		Easing = "QuadIn",
		OnUpdate = function(_, _, Progress)
			self.Main.Size = UDim2.new(self.Size.X.Scale * (1 - Progress), self.Size.X.Offset * (1 - Progress), self.Size.Y.Scale * (1 - Progress), self.Size.Y.Offset * (1 - Progress))
			self.Main.BackgroundTransparency = Progress
		end,
		OnComplete = function()
			self.Main:Destroy()
			self.Shadow:Destroy()
			self.Application.WindowManager:Unregister(self)
			self.ClosedEvent:Fire()
			self.Cleanup:Destroy()
		end,
	})
end

function Window:IsClosed()
	return self.Closed
end

function Window:SubscribeChanged(Callback)
	return self.Changed:Connect(Callback)
end

function Window:SubscribeTabChanged(Callback)
	return self.TabChanged:Connect(Callback)
end

function Window:SubscribeClosed(Callback)
	return self.ClosedEvent:Connect(Callback)
end

function Window:Destroy()
	self:Close()
end

return Window

end

Modules["Managers.AssetManager"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Events = VoidRequire("Core.Events")

local AssetManager = {}
AssetManager.__index = AssetManager

function AssetManager.new()
	local self = setmetatable({}, AssetManager)
	self.Cache = {}
	self.Pools = {}
	self.References = {}
	self.Created = 0
	self.Reused = 0
	self.Evicted = 0
	self.Changed = Events.new()
	self.MaxCache = 500
	return self
end

function AssetManager:CacheAsset(Key, Asset)
	self.Cache[Key] = Asset
	self.References[Key] = (self.References[Key] or 0) + 1
	self.Created = self.Created + 1
	self:_EvictIfNeeded()
	self.Changed:Fire("Cache", Key)
end

function AssetManager:GetAsset(Key)
	local Asset = self.Cache[Key]
	if Asset then
		self.Reused = self.Reused + 1
		return Asset
	end
	return nil
end

function AssetManager:HasAsset(Key)
	return self.Cache[Key] ~= nil
end

function AssetManager:Release(Key)
	local Ref = self.References[Key] or 0
	if Ref > 1 then
		self.References[Key] = Ref - 1
	else
		self.References[Key] = nil
		self.Cache[Key] = nil
		self.Evicted = self.Evicted + 1
	end
	self.Changed:Fire("Release", Key)
end

function AssetManager:CreatePool(Name, Factory, Reset)
	self.Pools[Name] = {
		Factory = Factory,
		Reset = Reset,
		Available = {},
		InUse = {},
	}
end

function AssetManager:Acquire(Name, ...)
	local Pool = self.Pools[Name]
	if not Pool then
		return nil
	end
	local Item
	if #Pool.Available > 0 then
		Item = table.remove(Pool.Available)
		self.Reused = self.Reused + 1
	else
		Item = Pool.Factory(...)
		self.Created = self.Created + 1
	end
	Pool.InUse[Item] = true
	return Item
end

function AssetManager:ReleasePoolItem(Name, Item)
	local Pool = self.Pools[Name]
	if not Pool then
		return
	end
	if Pool.InUse[Item] then
		Pool.InUse[Item] = nil
		if Pool.Reset then
			pcall(Pool.Reset, Item)
		end
		table.insert(Pool.Available, Item)
	end
end

function AssetManager:GetPoolSize(Name)
	local Pool = self.Pools[Name]
	if not Pool then
		return 0
	end
	return #Pool.Available + Utilities.TableLength(Pool.InUse)
end

function AssetManager:Prewarm(Name, Count, ...)
	local Pool = self.Pools[Name]
	if not Pool then
		return
	end
	for _ = 1, Count do
		local Item = Pool.Factory(...)
		table.insert(Pool.Available, Item)
	end
end

function AssetManager:_EvictIfNeeded()
	if Utilities.TableLength(self.Cache) > self.MaxCache then
		local Oldest
		local OldestKey
		for Key, _ in pairs(self.Cache) do
			if not OldestKey then
				OldestKey = Key
			end
		end
		if OldestKey then
			self.Cache[OldestKey] = nil
			self.References[OldestKey] = nil
			self.Evicted = self.Evicted + 1
		end
	end
end

function AssetManager:GetStats()
	return {
		Created = self.Created,
		Reused = self.Reused,
		Evicted = self.Evicted,
		Cached = Utilities.TableLength(self.Cache),
	}
end

function AssetManager:Clear()
	for Key, _ in pairs(self.Cache) do
		self.Cache[Key] = nil
		self.References[Key] = nil
	end
	for Name, Pool in pairs(self.Pools) do
		Pool.Available = {}
		Pool.InUse = {}
	end
end

function AssetManager:Subscribe(Callback)
	return self.Changed:Connect(Callback)
end

function AssetManager:Destroy()
	self:Clear()
	self.Changed:DisconnectAll()
end

return AssetManager

end

Modules["Managers.ConfigManager"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Events = VoidRequire("Core.Events")
local State = VoidRequire("Core.State")

local ConfigManager = {}
ConfigManager.__index = ConfigManager

local CURRENT_VERSION = "2.0.0"

function ConfigManager.new(Options)
	Options = Options or {}
	local self = setmetatable({}, ConfigManager)
	self.Name = Options.Name or "VoidUI_Config"
	self.AutoSave = Options.AutoSave ~= false
	self.AutoSaveInterval = Options.AutoSaveInterval or 30
	self.Version = CURRENT_VERSION
	self.Data = {}
	self.Profiles = {}
	self.CurrentProfile = "Default"
	self.Changed = Events.new()
	self.Loaded = Events.new()
	self.Saved = Events.new()
	self.State = State.new(self.Data)
	self._SaveTimer = nil
	self._Storage = Options.Storage or "Local"
	self:Initialize()
	return self
end

function ConfigManager:Initialize()
	self.Profiles["Default"] = {}
	if self.AutoSave then
		self._SaveTimer = self:CreateTimer(self.AutoSaveInterval, function()
			self:Save()
		end)
	end
end

function ConfigManager:CreateTimer(Interval, Callback)
	local Connection
	local Elapsed = 0
	Connection = game:GetService("RunService").Heartbeat:Connect(function(Delta)
		Elapsed = Elapsed + Delta
		if Elapsed >= Interval then
			Elapsed = 0
			pcall(Callback)
		end
	end)
	return Connection
end

function ConfigManager:Set(Key, Value)
	self.Data[Key] = Utilities.DeepCopy(Value)
	self.Changed:Fire(Key, Value)
	self.State:Set(self.Data)
end

function ConfigManager:Get(Key, Default)
	local Value = self.Data[Key]
	if Value == nil then
		return Default
	end
	return Utilities.DeepCopy(Value)
end

function ConfigManager:GetState(Key)
	return self.Data[Key]
end

function ConfigManager:Has(Key)
	return self.Data[Key] ~= nil
end

function ConfigManager:Remove(Key)
	self.Data[Key] = nil
	self.Changed:Fire(Key, nil)
end

function ConfigManager:Update(Key, Transform)
	local Current = self.Data[Key]
	self.Data[Key] = Transform(Current)
	self.Changed:Fire(Key, self.Data[Key])
end

function ConfigManager:Merge(Other)
	for Key, Value in pairs(Other) do
		self.Data[Key] = Utilities.DeepCopy(Value)
	end
	self.Changed:Fire("*", self.Data)
end

function ConfigManager:Serialize()
	return {
		Version = self.Version,
		Profile = self.CurrentProfile,
		Data = Utilities.DeepCopy(self.Data),
		Profiles = Utilities.DeepCopy(self.Profiles),
		SavedAt = os.time(),
	}
end

function ConfigManager:Deserialize(Payload)
	if not Payload then
		return false
	end
	local Migrated = self:Migrate(Payload)
	self.Data = Utilities.DeepCopy(Migrated.Data or {})
	self.Profiles = Utilities.DeepCopy(Migrated.Profiles or { Default = {} })
	self.CurrentProfile = Migrated.Profile or "Default"
	self.Changed:Fire("*", self.Data)
	self.Loaded:Fire(self.Data)
	return true
end

function ConfigManager:Migrate(Payload)
	local Version = Payload.Version or "1.0.0"
	if Utilities.VersionCompare(Version, self.Version) < 0 then
		Payload.Data = Payload.Data or {}
		Payload.MigratedFrom = Version
		Payload.Version = self.Version
	end
	return Payload
end

function ConfigManager:Save()
	local Payload = self:Serialize()
	local Encoded = Utilities.EncodeJSON(Payload)
	local Success = pcall(function()
		if self._Storage == "Local" then
			local Success2, DataStore = pcall(function()
				return game:GetService("DataStoreService"):GetDataStore(self.Name)
			end)
			if Success2 and DataStore then
				DataStore:SetAsync("Config", Encoded)
			end
		end
	end)
	self.Saved:Fire(Payload)
	return Encoded
end

function ConfigManager:Load()
	local Success, Encoded = pcall(function()
		local Success2, DataStore = pcall(function()
			return game:GetService("DataStoreService"):GetDataStore(self.Name)
		end)
		if Success2 and DataStore then
			return DataStore:GetAsync("Config")
		end
		return nil
	end)
	if Success and Encoded then
		local Payload = Utilities.DecodeJSON(Encoded)
		return self:Deserialize(Payload)
	end
	return false
end

function ConfigManager:Export()
	return Utilities.EncodeJSON(self:Serialize())
end

function ConfigManager:Import(JSON)
	local Payload = Utilities.DecodeJSON(JSON)
	return self:Deserialize(Payload)
end

function ConfigManager:CreateProfile(Name)
	self.Profiles[Name] = Utilities.DeepCopy(self.Data)
end

function ConfigManager:SwitchProfile(Name)
	if not self.Profiles[Name] then
		self.Profiles[Name] = {}
	end
	self:Save()
	self.Data = Utilities.DeepCopy(self.Profiles[Name])
	self.CurrentProfile = Name
	self.Changed:Fire("*", self.Data)
	self.Loaded:Fire(self.Data)
end

function ConfigManager:DeleteProfile(Name)
	if Name ~= "Default" then
		self.Profiles[Name] = nil
	end
end

function ConfigManager:GetProfiles()
	return Utilities.TableKeys(self.Profiles)
end

function ConfigManager:GetCurrentProfile()
	return self.CurrentProfile
end

function ConfigManager:Subscribe(Callback)
	return self.Changed:Connect(Callback)
end

function ConfigManager:SubscribeLoaded(Callback)
	return self.Loaded:Connect(Callback)
end

function ConfigManager:SubscribeSaved(Callback)
	return self.Saved:Connect(Callback)
end

function ConfigManager:Destroy()
	if self._SaveTimer then
		self._SaveTimer:Disconnect()
		self._SaveTimer = nil
	end
	self.Changed:DisconnectAll()
	self.Loaded:DisconnectAll()
	self.Saved:DisconnectAll()
	self.Data = {}
	self.Profiles = {}
end

return ConfigManager

end

Modules["Managers.InputManager"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Events = VoidRequire("Core.Events")
local Cleanup = VoidRequire("Core.Cleanup")

local InputManager = {}
InputManager.__index = InputManager

function InputManager.new()
	local self = setmetatable({}, InputManager)
	self.Hotkeys = {}
	self.ContextMenus = {}
	self.Tooltips = {}
	self.KeyDown = Events.new()
	self.KeyUp = Events.new()
	self.PointerMoved = Events.new()
	self.PointerDown = Events.new()
	self.PointerUp = Events.new()
	self.Cleanup = Cleanup.new()
	self.MousePosition = Vector2.new(0, 0)
	self.PressedKeys = {}
	self:_Initialize()
	return self
end

function InputManager:_Initialize()
	local UserInputService = game:GetService("UserInputService")

	local DownConnection = UserInputService.InputBegan:Connect(function(Input, Processed)
		if Processed then
			return
		end
		self.PressedKeys[Input.KeyCode] = true
		self.KeyDown:Fire(Input, Processed)
		self:_CheckHotkeys(Input, false)
	end)
	self.Cleanup:AddConnection(DownConnection)

	local UpConnection = UserInputService.InputEnded:Connect(function(Input, Processed)
		self.PressedKeys[Input.KeyCode] = nil
		self.KeyUp:Fire(Input, Processed)
		self:_CheckHotkeys(Input, true)
	end)
	self.Cleanup:AddConnection(UpConnection)

	local MoveConnection = UserInputService.InputChanged:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseMovement then
			self.MousePosition = Input.Position
			self.PointerMoved:Fire(Input.Position)
		end
	end)
	self.Cleanup:AddConnection(MoveConnection)

	local DownPointer = UserInputService.InputBegan:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 or Input.UserInputType == Enum.UserInputType.Touch then
			self.PointerDown:Fire(Input)
		end
	end)
	self.Cleanup:AddConnection(DownPointer)

	local UpPointer = UserInputService.InputEnded:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 or Input.UserInputType == Enum.UserInputType.Touch then
			self.PointerUp:Fire(Input)
		end
	end)
	self.Cleanup:AddConnection(UpPointer)
end

function InputManager:BindHotkey(Name, KeyCodes, Callback, Options)
	Options = Options or {}
	local Hotkey = {
		Name = Name,
		Keys = type(KeyCodes) == "table" and KeyCodes or { KeyCodes },
		Callback = Callback,
		Modifiers = Options.Modifiers or {},
		Repeat = Options.Repeat or false,
		Enabled = true,
	}
	self.Hotkeys[Name] = Hotkey
	return Hotkey
end

function InputManager:UnbindHotkey(Name)
	self.Hotkeys[Name] = nil
end

function InputManager:EnableHotkey(Name)
	if self.Hotkeys[Name] then
		self.Hotkeys[Name].Enabled = true
	end
end

function InputManager:DisableHotkey(Name)
	if self.Hotkeys[Name] then
		self.Hotkeys[Name].Enabled = false
	end
end

function InputManager:_CheckHotkeys(Input, Released)
	for _, Hotkey in pairs(self.Hotkeys) do
		if not Hotkey.Enabled then
			continue
		end
		local Match = false
		for _, Key in ipairs(Hotkey.Keys) do
			if Key == Input.KeyCode then
				Match = true
				break
			end
		end
		if Match then
			local ModifiersOk = true
			for _, Mod in ipairs(Hotkey.Modifiers) do
				if not self.PressedKeys[Mod] then
					ModifiersOk = false
					break
				end
			end
			if ModifiersOk then
				pcall(Hotkey.Callback, Input, Released)
			end
		end
	end
end

function InputManager:IsKeyDown(KeyCode)
	return self.PressedKeys[KeyCode] == true
end

function InputManager:GetPressedKeys()
	return Utilities.ShallowCopy(self.PressedKeys)
end

function InputManager:FormatKey(KeyCode)
	local Name = tostring(KeyCode)
	return Name:gsub("Enum.KeyCode.", "")
end

function InputManager:ListenForNextKey(Callback)
	local Connection
	Connection = game:GetService("UserInputService").InputBegan:Connect(function(Input, Processed)
		if Processed then
			return
		end
		if Input.UserInputType == Enum.UserInputType.Keyboard then
			Connection:Disconnect()
			pcall(Callback, Input.KeyCode)
		end
	end)
	return Connection
end

function InputManager:RegisterContextMenu(Name, Items)
	self.ContextMenus[Name] = Items
end

function InputManager:ShowContextMenu(Name, Position)
	local Items = self.ContextMenus[Name]
	if not Items then
		return nil
	end
	return Items, Position
end

function InputManager:RegisterTooltip(Instance, Text)
	self.Tooltips[Instance] = Text
end

function InputManager:GetMousePosition()
	return self.MousePosition
end

function InputManager:SetMousePosition(Position)
	self.MousePosition = Position
end

function InputManager:IsModifierDown()
	local UserInputService = game:GetService("UserInputService")
	return UserInputService:IsKeyDown(Enum.KeyCode.LeftControl)
		or UserInputService:IsKeyDown(Enum.KeyCode.RightControl)
		or UserInputService:IsKeyDown(Enum.KeyCode.LeftShift)
		or UserInputService:IsKeyDown(Enum.KeyCode.RightShift)
end

function InputManager:GetDevice()
	local UserInputService = game:GetService("UserInputService")
	if UserInputService.TouchEnabled and not UserInputService.KeyboardEnabled then
		return "Touch"
	elseif UserInputService.GamepadEnabled then
		return "Gamepad"
	end
	return "Desktop"
end

function InputManager:SubscribeKeyDown(Callback)
	return self.KeyDown:Connect(Callback)
end

function InputManager:SubscribeKeyUp(Callback)
	return self.KeyUp:Connect(Callback)
end

function InputManager:SubscribePointerMoved(Callback)
	return self.PointerMoved:Connect(Callback)
end

function InputManager:Destroy()
	self.Cleanup:Destroy()
	self.Hotkeys = {}
	self.ContextMenus = {}
	self.Tooltips = {}
	self.KeyDown:DisconnectAll()
	self.KeyUp:DisconnectAll()
	self.PointerMoved:DisconnectAll()
	self.PointerDown:DisconnectAll()
	self.PointerUp:DisconnectAll()
end

return InputManager

end

Modules["Managers.LayoutManager"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Events = VoidRequire("Core.Events")

local LayoutManager = {}
LayoutManager.__index = LayoutManager

function LayoutManager.new()
	local self = setmetatable({}, LayoutManager)
	self.Regions = {}
	self.Constraints = {}
	self.Changed = Events.new()
	self.VirtualLists = {}
	return self
end

function LayoutManager:RegisterRegion(Name, Frame, Options)
	Options = Options or {}
	local Region = {
		Name = Name,
		Frame = Frame,
		Direction = Options.Direction or Enum.FillDirection.Vertical,
		Padding = Options.Padding or 8,
		Align = Options.Align or Enum.HorizontalAlignment.Left,
		Virtual = Options.Virtual or false,
		ItemHeight = Options.ItemHeight or 36,
		RenderWindow = Options.RenderWindow or 200,
		Items = {},
		Layout = nil,
	}
	if not Options.Virtual then
		local Layout = Utilities.AddListLayout(Frame, Region.Direction, Region.Padding, Region.Align)
		Region.Layout = Layout
	end
	self.Regions[Name] = Region
	return Region
end

function LayoutManager:AddItem(RegionName, Item, Index)
	local Region = self.Regions[RegionName]
	if not Region then
		return
	end
	if Index then
		table.insert(Region.Items, Index, Item)
	else
		table.insert(Region.Items, Item)
	end
	if not Region.Virtual and Item.Instance then
		Item.Instance.Parent = Region.Frame
		Item.Instance.LayoutOrder = #Region.Items
	end
	self.Changed:Fire(RegionName, "Add")
end

function LayoutManager:RemoveItem(RegionName, Item)
	local Region = self.Regions[RegionName]
	if not Region then
		return
	end
	local Index = Utilities.TableFind(Region.Items, Item)
	if Index then
		table.remove(Region.Items, Index)
		if Item.Instance and Item.Instance.Parent == Region.Frame then
			Item.Instance.Parent = nil
		end
		self.Changed:Fire(RegionName, "Remove")
	end
end

function LayoutManager:ClearRegion(RegionName)
	local Region = self.Regions[RegionName]
	if not Region then
		return
	end
	for _, Item in ipairs(Region.Items) do
		if Item.Instance then
			Item.Instance:Destroy()
		end
	end
	Region.Items = {}
	self.Changed:Fire(RegionName, "Clear")
end

function LayoutManager:EnableVirtual(RegionName, ScrollFrame, Viewport)
	local Region = self.Regions[RegionName]
	if not Region then
		return
	end
	Region.Virtual = true
	Region.ScrollFrame = ScrollFrame
	Region.Viewport = Viewport
	self.VirtualLists[RegionName] = Region
	self:_SetupVirtual(Region)
end

function LayoutManager:_SetupVirtual(Region)
	local Content = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Parent = Region.ScrollFrame,
	})
	Region.Content = Content
	local Layout = Utilities.AddListLayout(Content, Region.Direction, Region.Padding, Region.Align)
	Region.Layout = Layout

	local Connection
	Connection = Region.ScrollFrame:GetPropertyChangedSignal("CanvasPosition"):Connect(function()
		self:_UpdateVirtual(Region)
	end)
	Region._Connection = Connection
	self:_UpdateVirtual(Region)
end

function LayoutManager:_UpdateVirtual(Region)
	if not Region.ScrollFrame or not Region.Content then
		return
	end
	local Total = #Region.Items
	local ViewportHeight = Region.Viewport or Region.ScrollFrame.AbsoluteSize.Y
	local ScrollY = Region.ScrollFrame.CanvasPosition.Y
	local StartIndex = math.max(1, math.floor(ScrollY / Region.ItemHeight) - 2)
	local EndIndex = math.min(Total, math.ceil((ScrollY + ViewportHeight) / Region.ItemHeight) + 2)

	for Index, Item in ipairs(Region.Items) do
		local Visible = Index >= StartIndex and Index <= EndIndex
		if Visible and not Item.Instance then
			Item.Instance = Item.Factory and Item:Factory() or Item.Create()
			Item.Instance.LayoutOrder = Index
			Item.Instance.Parent = Region.Content
		elseif not Visible and Item.Instance then
			Item.Instance:Destroy()
			Item.Instance = nil
		end
	end
end

function LayoutManager:RefreshVirtual(RegionName)
	local Region = self.VirtualLists[RegionName]
	if Region then
		self:_UpdateVirtual(Region)
	end
end

function LayoutManager:SetConstraint(RegionName, Constraint)
	self.Constraints[RegionName] = Constraint
end

function LayoutManager:ApplyGrid(Frame, CellSize, CellPadding)
	return Utilities.AddGridLayout(Frame, CellSize, CellPadding)
end

function LayoutManager:ApplyList(Frame, Direction, Padding, Align)
	return Utilities.AddListLayout(Frame, Direction, Padding, Align)
end

function LayoutManager:ApplyPadding(Frame, Padding)
	return Utilities.AddPadding(Frame, Padding)
end

function LayoutManager:ApplyFlex(Frame, Direction, Padding, Align, Wrap)
	local Layout = Utilities.AddListLayout(Frame, Direction, Padding, Align)
	Layout.Wraps = Wrap or false
	return Layout
end

function LayoutManager:GetRegion(Name)
	return self.Regions[Name]
end

function LayoutManager:GetItemCount(RegionName)
	local Region = self.Regions[RegionName]
	return Region and #Region.Items or 0
end

function LayoutManager:Subscribe(Callback)
	return self.Changed:Connect(Callback)
end

function LayoutManager:Destroy()
	for _, Region in pairs(self.Regions) do
		if Region._Connection then
			Region._Connection:Disconnect()
		end
		self:ClearRegion(Region.Name)
	end
	self.Regions = {}
	self.VirtualLists = {}
	self.Constraints = {}
	self.Changed:DisconnectAll()
end

return LayoutManager

end

Modules["Managers.NotificationManager"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Events = VoidRequire("Core.Events")
local Cleanup = VoidRequire("Core.Cleanup")
local Icons = VoidRequire("Assets.Icons")

local NotificationManager = {}
NotificationManager.__index = NotificationManager

function NotificationManager.new(Parent, Theme)
	local self = setmetatable({}, NotificationManager)
	self.Parent = Parent
	self.Theme = Theme
	self.Notifications = {}
	self.Queue = {}
	self.MaxVisible = 4
	self.Position = "TopRight"
	self.Changed = Events.new()
	self.Dismissed = Events.new()
	self.Cleanup = Cleanup.new()
	self.Container = nil
	self:_Build()
	return self
end

function NotificationManager:_Build()
	local Container = Utilities.Create("Frame", {
		Name = "NotificationContainer",
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(0, 320, 1, 0),
		Position = UDim2.new(1, -20, 0, 20),
		AnchorPoint = Vector2.new(1, 0),
		Parent = self.Parent,
	})
	local Layout = Utilities.AddListLayout(Container, Enum.FillDirection.Vertical, 10, Enum.HorizontalAlignment.Right)
	Layout.VerticalAlignment = Enum.VerticalAlignment.Top
	self.Container = Container
	self.Cleanup:AddInstance(Container)
end

function NotificationManager:SetPosition(Position)
	self.Position = Position
	local Anchor = Vector2.new(1, 0)
	local Pos = UDim2.new(1, -20, 0, 20)
	if Position == "TopLeft" then
		Anchor = Vector2.new(0, 0)
		Pos = UDim2.new(0, 20, 0, 20)
	elseif Position == "BottomRight" then
		Anchor = Vector2.new(1, 1)
		Pos = UDim2.new(1, -20, 1, -20)
	elseif Position == "BottomLeft" then
		Anchor = Vector2.new(0, 1)
		Pos = UDim2.new(0, 20, 1, -20)
	end
	self.Container.AnchorPoint = Anchor
	self.Container.Position = Pos
end

function NotificationManager:Notify(Options)
	Options = Options or {}
	local Notification = self:_Create(Options)
	table.insert(self.Notifications, Notification)
	self.Changed:Fire(Notification)
	self:_Reflow()
	return Notification
end

function NotificationManager:Success(Title, Description, Duration)
	return self:Notify({ Title = Title, Description = Description, Type = "Success", Duration = Duration })
end

function NotificationManager:Warning(Title, Description, Duration)
	return self:Notify({ Title = Title, Description = Description, Type = "Warning", Duration = Duration })
end

function NotificationManager:Error(Title, Description, Duration)
	return self:Notify({ Title = Title, Description = Description, Type = "Danger", Duration = Duration })
end

function NotificationManager:Info(Title, Description, Duration)
	return self:Notify({ Title = Title, Description = Description, Type = "Info", Duration = Duration })
end

function NotificationManager:_Create(Options)
	local Theme = self.Theme
	local Type = Options.Type or "Info"
	local ColorMap = {
		Success = Theme.Color("Success"),
		Warning = Theme.Color("Warning"),
		Danger = Theme.Color("Danger"),
		Info = Theme.Color("Info"),
	}
	local IconMap = {
		Success = "CheckCircle",
		Warning = "Warning",
		Danger = "Danger",
		Info = "Info",
	}
	local Accent = ColorMap[Type] or Theme.Color("Accent")
	local Card = Utilities.Create("Frame", {
		Name = "Notification",
		BackgroundColor3 = Theme.Color("CardElevated"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		ClipsDescendants = true,
		Parent = self.Container,
	})
	local Corner = Utilities.Roundify(Card, Theme.Layout("Radius"))
	local Stroke = Utilities.AddStroke(Card, Theme.Color("Border"), 1)
	local Padding = Utilities.AddPadding(Card, 14)

	local AccentBar = Utilities.Create("Frame", {
		BackgroundColor3 = Accent,
		BorderSizePixel = 0,
		Size = UDim2.new(0, 3, 1, 0),
		Position = UDim2.new(0, 0, 0, 0),
		Parent = Card,
	})

	local Content = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -16, 1, 0),
		Position = UDim2.new(0, 16, 0, 0),
		Parent = Card,
	})
	local ContentLayout = Utilities.AddListLayout(Content, Enum.FillDirection.Horizontal, 12, Enum.HorizontalAlignment.Left)
	ContentLayout.VerticalAlignment = Enum.VerticalAlignment.Center

	local IconFrame = Icons.Create(IconMap[Type] or "Info", Accent, 22)
	IconFrame.Parent = Content

	local TextBlock = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -34, 1, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Parent = Content,
	})
	local TextLayout = Utilities.AddListLayout(TextBlock, Enum.FillDirection.Vertical, 3)
	local TitleLabel = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 18),
		Font = Theme.Typography("FontBold"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		TextTruncate = Enum.TextTruncate.AtEnd,
		Text = Options.Title or "Notification",
		Parent = TextBlock,
	})
	local DescLabel = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("CaptionSize"),
		TextColor3 = Theme.Color("TextMuted"),
		TextXAlignment = Enum.TextXAlignment.Left,
		TextWrapped = true,
		Text = Options.Description or "",
		Parent = TextBlock,
	})

	local Notification = {
		Id = Utilities.UniqueId(),
		Card = Card,
		Options = Options,
		Type = Type,
		CreatedAt = tick(),
		Duration = Options.Duration or 4,
		Dismissed = false,
		Dismiss = function()
			self:Dismiss(Notification)
		end,
	}

	Card.Size = UDim2.new(1, 0, 0, 0)
	Card.BackgroundTransparency = 1
	Card.Visible = true
	local TargetHeight = Card.AbsoluteSize.Y
	Card.Size = UDim2.new(1, 0, 0, 0)

	local TweenService = game:GetService("TweenService")
	local ShowTween = TweenService:Create(Card, TweenInfo.new(0.4, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {
		Size = UDim2.new(1, 0, 0, math.max(TargetHeight, 56)),
		BackgroundTransparency = 0,
	})
	ShowTween:Play()

	if Notification.Duration > 0 then
		local Connection
		Connection = game:GetService("RunService").Heartbeat:Connect(function(Delta)
			Notification.Duration = Notification.Duration - Delta
			if Notification.Duration <= 0 then
				Connection:Disconnect()
				Notification:Dismiss()
			end
		end)
		self.Cleanup:AddConnection(Connection)
	end

	local ClickConnection = Card.InputBegan:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 then
			Notification:Dismiss()
		end
	end)
	self.Cleanup:AddConnection(ClickConnection)

	return Notification
end

function NotificationManager:Dismiss(Notification)
	if Notification.Dismissed then
		return
	end
	Notification.Dismissed = true
	local TweenService = game:GetService("TweenService")
	local HideTween = TweenService:Create(Notification.Card, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {
		Size = UDim2.new(1, 0, 0, 0),
		BackgroundTransparency = 1,
	})
	HideTween:Play()
	HideTween.Completed:Connect(function()
		Notification.Card:Destroy()
		local Index = Utilities.TableFind(self.Notifications, Notification)
		if Index then
			table.remove(self.Notifications, Index)
		end
		self.Dismissed:Fire(Notification)
		self:_Reflow()
	end)
end

function NotificationManager:_Reflow()
	local Layout = self.Container:FindFirstChildOfClass("UIListLayout")
	if Layout then
		Layout:ApplyLayout()
	end
end

function NotificationManager:Clear()
	for _, Notification in ipairs(self.Notifications) do
		Notification:Dismiss()
	end
end

function NotificationManager:Count()
	return #self.Notifications
end

function NotificationManager:SetMaxVisible(Max)
	self.MaxVisible = Max
end

function NotificationManager:Destroy()
	self:Clear()
	self.Cleanup:Destroy()
end

return NotificationManager

end

Modules["Managers.PluginManager"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Events = VoidRequire("Core.Events")

local PluginManager = {}
PluginManager.__index = PluginManager

function PluginManager.new()
	local self = setmetatable({}, PluginManager)
	self.Plugins = {}
	self.Loaded = Events.new()
	self.Unloaded = Events.new()
	self.Enabled = Events.new()
	self.Disabled = Events.new()
	self.Hooks = {}
	self.Middlewares = {}
	return self
end

function PluginManager:Register(Plugin)
	if not Plugin or not Plugin.Name then
		warn("[VoidUI] Invalid plugin")
		return false
	end
	if self.Plugins[Plugin.Name] then
		warn("[VoidUI] Plugin already registered:", Plugin.Name)
		return false
	end
	Plugin.Enabled = false
	Plugin.Priority = Plugin.Priority or 100
	self.Plugins[Plugin.Name] = Plugin
	return true
end

function PluginManager:RegisterMany(Plugins)
	for _, Plugin in ipairs(Plugins) do
		self:Register(Plugin)
	end
end

function PluginManager:Get(Name)
	return self.Plugins[Name]
end

function PluginManager:List()
	return Utilities.TableValues(self.Plugins)
end

function PluginManager:Load(Name, Context)
	local Plugin = self.Plugins[Name]
	if not Plugin then
		return false
	end
	if Plugin.Enabled then
		return true
	end
	local Success, Error = pcall(function()
		if Plugin.Init then
			Plugin:Init(Context)
		end
		if Plugin.OnLoad then
			Plugin:OnLoad(Context)
		end
	end)
	if Success then
		Plugin.Enabled = true
		self.Loaded:Fire(Plugin, Context)
	else
		warn("[VoidUI] Plugin load failed:", Name, Error)
	end
	return Success
end

function PluginManager:Unload(Name)
	local Plugin = self.Plugins[Name]
	if not Plugin or not Plugin.Enabled then
		return false
	end
	pcall(function()
		if Plugin.OnUnload then
			Plugin:OnUnload()
		end
	end)
	Plugin.Enabled = false
	self.Unloaded:Fire(Plugin)
	return true
end

function PluginManager:Enable(Name)
	local Plugin = self.Plugins[Name]
	if Plugin and not Plugin.Enabled then
		Plugin.Enabled = true
		self.Enabled:Fire(Plugin)
	end
end

function PluginManager:Disable(Name)
	local Plugin = self.Plugins[Name]
	if Plugin and Plugin.Enabled then
		Plugin.Enabled = false
		self.Disabled:Fire(Plugin)
	end
end

function PluginManager:LoadAll(Context)
	local Sorted = self:List()
	table.sort(Sorted, function(A, B)
		return A.Priority < B.Priority
	end)
	for _, Plugin in ipairs(Sorted) do
		self:Load(Plugin.Name, Context)
	end
end

function PluginManager:UnloadAll()
	for _, Plugin in ipairs(self:List()) do
		self:Unload(Plugin.Name)
	end
end

function PluginManager:AddHook(EventName, Callback)
	if not self.Hooks[EventName] then
		self.Hooks[EventName] = {}
	end
	table.insert(self.Hooks[EventName], Callback)
end

function PluginManager:TriggerHook(EventName, ...)
	local Hooks = self.Hooks[EventName]
	if Hooks then
		for _, Callback in ipairs(Hooks) do
			pcall(Callback, ...)
		end
	end
end

function PluginManager:AddMiddleware(Middleware)
	table.insert(self.Middlewares, Middleware)
end

function PluginManager:RunMiddlewares(Context)
	for _, Middleware in ipairs(self.Middlewares) do
		pcall(Middleware, Context)
	end
end

function PluginManager:IsEnabled(Name)
	local Plugin = self.Plugins[Name]
	return Plugin and Plugin.Enabled or false
end

function PluginManager:Count()
	return Utilities.TableLength(self.Plugins)
end

function PluginManager:Destroy()
	self:UnloadAll()
	self.Plugins = {}
	self.Hooks = {}
	self.Middlewares = {}
	self.Loaded:DisconnectAll()
	self.Unloaded:DisconnectAll()
	self.Enabled:DisconnectAll()
	self.Disabled:DisconnectAll()
end

return PluginManager

end

Modules["Managers.WindowManager"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Events = VoidRequire("Core.Events")
local Cleanup = VoidRequire("Core.Cleanup")

local WindowManager = {}
WindowManager.__index = WindowManager

function WindowManager.new(Parent)
	local self = setmetatable({}, WindowManager)
	self.Parent = Parent
	self.Windows = {}
	self.Active = nil
	self.ZIndexCounter = 100
	self.Changed = Events.new()
	self.WindowAdded = Events.new()
	self.WindowRemoved = Events.new()
	self.FocusChanged = Events.new()
	self.Cleanup = Cleanup.new()
	self.SnappingEnabled = true
	self.SnapThreshold = 24
	return self
end

function WindowManager:Register(Window)
	if Utilities.TableFind(self.Windows, Window) then
		return
	end
	table.insert(self.Windows, Window)
	self.WindowAdded:Fire(Window)
	self:Focus(Window)
end

function WindowManager:Unregister(Window)
	local Index = Utilities.TableFind(self.Windows, Window)
	if Index then
		table.remove(self.Windows, Index)
		self.WindowRemoved:Fire(Window)
	end
end

function WindowManager:GetAll()
	return self.Windows
end

function WindowManager:Count()
	return #self.Windows
end

function WindowManager:Focus(Window)
	if self.Active == Window then
		return
	end
	self.Active = Window
	self.ZIndexCounter = self.ZIndexCounter + 10
	if Window and Window.SetZIndex then
		Window:SetZIndex(self.ZIndexCounter)
	end
	self.FocusChanged:Fire(Window)
end

function WindowManager:GetActive()
	return self.Active
end

function WindowManager:NextZIndex()
	self.ZIndexCounter = self.ZIndexCounter + 1
	return self.ZIndexCounter
end

function WindowManager:Tile(Direction)
	local Count = #self.Windows
	if Count == 0 then
		return
	end
	local Viewport = Utilities.GetViewportSize()
	local Columns = math.ceil(math.sqrt(Count))
	local Rows = math.ceil(Count / Columns)
	local CellWidth = Viewport.X / Columns
	local CellHeight = Viewport.Y / Rows
	for Index, Window in ipairs(self.Windows) do
		local Col = (Index - 1) % Columns
		local Row = math.floor((Index - 1) / Columns)
		if Window.SetPosition then
			Window:SetPosition(UDim2.fromOffset(Col * CellWidth + 10, Row * CellHeight + 10))
		end
		if Window.SetSize then
			Window:SetSize(UDim2.fromOffset(CellWidth - 20, CellHeight - 20))
		end
	end
end

function WindowManager:Cascade()
	local Offset = 40
	for Index, Window in ipairs(self.Windows) do
		if Window.SetPosition then
			Window:SetPosition(UDim2.fromOffset(60 + (Index - 1) * Offset, 60 + (Index - 1) * Offset))
		end
	end
end

function WindowManager:MinimizeAll()
	for _, Window in ipairs(self.Windows) do
		if Window.Minimize then
			Window:Minimize()
		end
	end
end

function WindowManager:RestoreAll()
	for _, Window in ipairs(self.Windows) do
		if Window.Restore then
			Window:Restore()
		end
	end
end

function WindowManager:CloseAll()
	for _, Window in ipairs(self.Windows) do
		if Window.Close then
			Window:Close()
		end
	end
end

function WindowManager:FindByTitle(Title)
	for _, Window in ipairs(self.Windows) do
		if Window.Title == Title then
			return Window
		end
	end
	return nil
end

function WindowManager:Snap(Window, Position)
	if not self.SnappingEnabled then
		return Position
	end
	local Viewport = Utilities.GetViewportSize()
	local Threshold = self.SnapThreshold
	local X = Position.X.Offset
	local Y = Position.Y.Offset
	if math.abs(X) < Threshold then
		X = 0
	elseif math.abs(X + Window.Size.X.Offset - Viewport.X) < Threshold then
		X = Viewport.X - Window.Size.X.Offset
	end
	if math.abs(Y) < Threshold then
		Y = 0
	elseif math.abs(Y + Window.Size.Y.Offset - Viewport.Y) < Threshold then
		Y = Viewport.Y - Window.Size.Y.Offset
	end
	return UDim2.fromOffset(X, Y)
end

function WindowManager:SetSnapping(Enabled)
	self.SnappingEnabled = Enabled
end

function WindowManager:SubscribeWindowAdded(Callback)
	return self.WindowAdded:Connect(Callback)
end

function WindowManager:SubscribeWindowRemoved(Callback)
	return self.WindowRemoved:Connect(Callback)
end

function WindowManager:SubscribeFocusChanged(Callback)
	return self.FocusChanged:Connect(Callback)
end

function WindowManager:Destroy()
	for _, Window in ipairs(self.Windows) do
		if Window.Destroy then
			pcall(Window.Destroy, Window)
		end
	end
	self.Windows = {}
	self.Active = nil
	self.Cleanup:Destroy()
	self.Changed:DisconnectAll()
	self.WindowAdded:DisconnectAll()
	self.WindowRemoved:DisconnectAll()
	self.FocusChanged:DisconnectAll()
end

return WindowManager

end

