Modules["Themes.ThemeManager"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Events = VoidRequire("Core.Events")
local State = VoidRequire("Core.State")

local ThemeManager = {}
ThemeManager.__index = ThemeManager

function ThemeManager.new()
	local self = setmetatable({}, ThemeManager)
	self.Themes = {}
	self.Current = nil
	self.CurrentName = "Default"
	self.Changed = Events.new()
	self.AccentChanged = Events.new()
	self.State = State.new("Default")
	self.CustomThemes = {}
	self.Accent = Color3.fromRGB(124, 162, 255)
	self._AccentPalette = Utilities.GenerateAccent(self.Accent)
	self:RegisterBuiltIns()
	-- Bind accessor methods so they work with both dot (Theme.Color("X"))
	-- and colon (Theme:Color("X")) call syntax.
	local function Bind(Method)
		return function(...)
			local Key = select(select("#", ...), ...)
			return Method(self, Key)
		end
	end
	self.Color = Bind(ThemeManager.Color)
	self.Gradient = Bind(ThemeManager.Gradient)
	self.Typography = Bind(ThemeManager.Typography)
	self.Layout = Bind(ThemeManager.Layout)
	self.Effect = Bind(ThemeManager.Effect)
	self.Animation = Bind(ThemeManager.Animation)
	return self
end

function ThemeManager:RegisterBuiltIns()
	local Default = VoidRequire("Themes.Default")
	local Midnight = VoidRequire("Themes.Midnight")
	local Nebula = VoidRequire("Themes.Nebula")
	local Crimson = VoidRequire("Themes.Crimson")
	local Emerald = VoidRequire("Themes.Emerald")
	self:Register(Default)
	self:Register(Midnight)
	self:Register(Nebula)
	self:Register(Crimson)
	self:Register(Emerald)
end

function ThemeManager:Register(Theme)
	if not Theme or not Theme.Name then
		return
	end
	self.Themes[Theme.Name] = Utilities.DeepCopy(Theme)
end

function ThemeManager:RegisterCustom(Name, Theme)
	self.CustomThemes[Name] = Utilities.DeepCopy(Theme)
	self:Register(Theme)
end

function ThemeManager:GetNames()
	return Utilities.TableKeys(self.Themes)
end

function ThemeManager:Get(Name)
	return self.Themes[Name]
end

function ThemeManager:Exists(Name)
	return self.Themes[Name] ~= nil
end

function ThemeManager:Set(Name)
	if not self.Themes[Name] then
		warn("[VoidUI] Theme not found:", Name)
		return false
	end
	self.CurrentName = Name
	self.Current = Utilities.DeepCopy(self.Themes[Name])
	self.State:Set(Name)
	self:ApplyAccent(self.Accent)
	self.Changed:Fire(self.Current, Name)
	return true
end

function ThemeManager:GetCurrent()
	return self.Current
end

function ThemeManager:GetName()
	return self.CurrentName
end

function ThemeManager:Color(Key)
	if self.Current and self.Current.Colors then
		return self.Current.Colors[Key] or Color3.fromRGB(255, 0, 255)
	end
	return Color3.fromRGB(255, 0, 255)
end

function ThemeManager:Gradient(Key)
	if self.Current and self.Current.Gradients then
		return self.Current.Gradients[Key]
	end
	return ColorSequence.new(Color3.fromRGB(255, 0, 255))
end

function ThemeManager:Typography(Key)
	if self.Current and self.Current.Typography then
		return self.Current.Typography[Key]
	end
	return nil
end

function ThemeManager:Layout(Key)
	if self.Current and self.Current.Layout then
		return self.Current.Layout[Key]
	end
	return nil
end

function ThemeManager:Effect(Key)
	if self.Current and self.Current.Effects then
		return self.Current.Effects[Key]
	end
	return nil
end

function ThemeManager:Animation(Key)
	if self.Current and self.Current.Animation then
		return self.Current.Animation[Key]
	end
	return nil
end

function ThemeManager:SetAccent(Color)
	self:ApplyAccent(Color)
	self.AccentChanged:Fire(Color)
end

function ThemeManager:ApplyAccent(Color)
	self.Accent = Color
	self._AccentPalette = Utilities.GenerateAccent(Color)
	if self.Current then
		self.Current.Colors.Accent = Color
		self.Current.Colors.AccentLight = self._AccentPalette.Light
		self.Current.Colors.AccentDark = self._AccentPalette.Dark
		self.Current.Colors.AccentGlow = self._AccentPalette.Glow
		self.Current.Gradients.Accent = ColorSequence.new({
			ColorSequenceKeypoint.new(0, Color),
			ColorSequenceKeypoint.new(1, self._AccentPalette.Complement),
		})
		self.Current.Gradients.Glow = ColorSequence.new({
			ColorSequenceKeypoint.new(0, self._AccentPalette.Glow),
			ColorSequenceKeypoint.new(1, self._AccentPalette.Complement),
		})
	end
end

function ThemeManager:GetAccent()
	return self.Accent
end

function ThemeManager:GetAccentPalette()
	return self._AccentPalette
end

function ThemeManager:ContrastFor(Background)
	return Utilities.ContrastColor(Background)
end

function ThemeManager:SetProperty(Category, Key, Value)
	if not self.Current then
		return
	end
	if not self.Current[Category] then
		self.Current[Category] = {}
	end
	self.Current[Category][Key] = Value
	self.Changed:Fire(self.Current, self.CurrentName)
end

function ThemeManager:GetProperty(Category, Key)
	if self.Current and self.Current[Category] then
		return self.Current[Category][Key]
	end
	return nil
end

function ThemeManager:CloneCurrent(Name)
	local Clone = Utilities.DeepCopy(self.Current)
	Clone.Name = Name or (self.CurrentName .. "_Custom")
	self:Register(Clone)
	return Clone
end

function ThemeManager:Export(Name)
	local Theme = self.Themes[Name or self.CurrentName]
	if not Theme then
		return nil
	end
	return Utilities.EncodeJSON(Theme)
end

function ThemeManager:Import(JSON)
	local Success, Theme = pcall(function()
		return Utilities.DecodeJSON(JSON)
	end)
	if Success and Theme and Theme.Name then
		self:Register(Theme)
		return Theme.Name
	end
	return nil
end

function ThemeManager:Serialize()
	return {
		Name = self.CurrentName,
		Accent = Utilities.Color3ToHex(self.Accent),
		Custom = Utilities.DeepCopy(self.CustomThemes),
	}
end

function ThemeManager:Deserialize(Data)
	if not Data then
		return
	end
	if Data.Custom then
		for Name, Theme in pairs(Data.Custom) do
			self:RegisterCustom(Name, Theme)
		end
	end
	if Data.Accent then
		self:SetAccent(Utilities.HexToColor3(Data.Accent))
	end
	if Data.Name then
		self:Set(Data.Name)
	end
end

function ThemeManager:Subscribe(Callback)
	return self.Changed:Connect(Callback)
end

function ThemeManager:SubscribeAccent(Callback)
	return self.AccentChanged:Connect(Callback)
end

function ThemeManager:Destroy()
	self.Changed:DisconnectAll()
	self.AccentChanged:DisconnectAll()
	self.Themes = {}
	self.CustomThemes = {}
	self.Current = nil
end

return ThemeManager

end

Modules["Widgets.Accordion"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local Accordion = {}
Accordion.__index = setmetatable(Accordion, Base)

function Accordion.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Accordion)
	self.Items = Options.Items or {}
	self.MultiExpand = Options.MultiExpand or false
	self.Expanded = {}
	self:_Build()
	return self
end

function Accordion:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(0)
	Container.AutomaticSize = Enum.AutomaticSize.Y
	local Card = self:_CreateCard(0, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})
	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Vertical, 6, Enum.HorizontalAlignment.Center)
	Layout.Padding = UDim.new(0, 6)
	local Padding = Utilities.AddPadding(Card, 10)
	self.Card = Card

	for Index, Item in ipairs(self.Items) do
		self:_CreateItem(Item, Index)
	end
end

function Accordion:_CreateItem(Item, Index)
	local Theme = self.Theme
	local ItemFrame = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Parent = self.Card,
	})

	local Header = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 36),
		AutoButtonColor = false,
		Text = "",
		Parent = ItemFrame,
	})
	local HeaderCorner = Utilities.Roundify(Header, Theme.Layout("RadiusSmall"))
	local HeaderLayout = Utilities.AddListLayout(Header, Enum.FillDirection.Horizontal, 8, Enum.HorizontalAlignment.Left)
	HeaderLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	HeaderLayout.Padding = UDim.new(0, 12)

	local Title = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -40, 1, 0),
		Font = Theme.Typography("FontSemibold"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = Item.Title or ("Item " .. Index),
		Parent = Header,
	})
	local Chevron = Icons.Create("ChevronDown", Theme.Color("TextMuted"), 16)
	Chevron.Parent = Header

	local Body = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Visible = false,
		Parent = ItemFrame,
	})
	local BodyLayout = Utilities.AddListLayout(Body, Enum.FillDirection.Vertical, 6, Enum.HorizontalAlignment.Center)
	BodyLayout.Padding = UDim.new(0, 6)
	local BodyPadding = Utilities.AddPadding(Body, 8)

	if type(Item.Content) == "string" then
		local Text = Utilities.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 0),
			AutomaticSize = Enum.AutomaticSize.Y,
			Font = Theme.Typography("Font"),
			TextSize = Theme.Typography("BodySize"),
			TextColor3 = Theme.Color("TextMuted"),
			TextWrapped = true,
			Text = Item.Content,
			Parent = Body,
		})
	elseif typeof(Item.Content) == "Instance" then
		Item.Content.Parent = Body
	end

	local Expanded = false
	local Click = Header.MouseButton1Click:Connect(function()
		Expanded = not Expanded
		self.Expanded[Index] = Expanded
		self.Animation:Animate(Chevron, "Rotation", Expanded and 180 or 0, { Duration = 0.2 })
		Body.Visible = true
		local TargetHeight = Expanded and Body.AbsoluteSize.Y or 0
		self.Animation:Tween({
			Duration = 0.25,
			Easing = "QuadOut",
			OnUpdate = function(_, _, Progress)
				Body.Size = UDim2.new(1, 0, 0, TargetHeight * Progress)
			end,
			OnComplete = function()
				if not Expanded then
					Body.Visible = false
				end
			end,
		})
		if not self.MultiExpand and Expanded then
			for OtherIndex, OtherExpanded in pairs(self.Expanded) do
				if OtherIndex ~= Index and OtherExpanded then
					self.Expanded[OtherIndex] = false
				end
			end
		end
		self.Changed:Fire(Index, Expanded)
	end)
	self.Cleanup:AddConnection(Click)
end

function Accordion:Expand(Index)
	self.Expanded[Index] = true
	self.Changed:Fire(Index, true)
end

function Accordion:Collapse(Index)
	self.Expanded[Index] = false
	self.Changed:Fire(Index, false)
end

return Accordion

end

Modules["Widgets.Audio"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local Audio = {}
Audio.__index = setmetatable(Audio, Base)

function Audio.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Audio)
	self.SoundId = Options.SoundId or Options.Source or ""
	self.Label = Options.Label or "Audio"
	self.Volume = Options.Volume or 1
	self.Playing = false
	self:_Build()
	return self
end

function Audio:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(56)
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})
	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Horizontal, 10, Enum.HorizontalAlignment.Left)
	Layout.VerticalAlignment = Enum.VerticalAlignment.Center
	local Padding = Utilities.AddPadding(Card, 12)

	local PlayButton = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("Accent"),
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(36, 36),
		AutoButtonColor = false,
		Text = "",
		Parent = Card,
	})
	local PlayCorner = Utilities.Roundify(PlayButton, 999)
	local PlayIcon = Icons.Create("Play", Theme.Color("TextInverse"), 18)
	PlayIcon.Parent = PlayButton
	self.PlayButton = PlayButton
	self.PlayIcon = PlayIcon

	local TextBlock = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -50, 1, 0),
		Parent = Card,
	})
	local TextLayout = Utilities.AddListLayout(TextBlock, Enum.FillDirection.Vertical, 4)
	local Label = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 16),
		Font = Theme.Typography("FontSemibold"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Label,
		Parent = TextBlock,
	})

	local VolumeTrack = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("SurfaceActive"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 4),
		Parent = TextBlock,
	})
	local VolumeCorner = Utilities.Roundify(VolumeTrack, 999)
	local VolumeFill = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Accent"),
		BorderSizePixel = 0,
		Size = UDim2.new(self.Volume, 0, 1, 0),
		Parent = VolumeTrack,
	})
	local VolumeFillCorner = Utilities.Roundify(VolumeFill, 999)
	self.VolumeFill = VolumeFill

	local Click = PlayButton.MouseButton1Click:Connect(function()
		self:Toggle()
	end)
	self.Cleanup:AddConnection(Click)
end

function Audio:Toggle()
	self.Playing = not self.Playing
	self.PlayIcon:Destroy()
	self.PlayIcon = Icons.Create(self.Playing and "Pause" or "Play", self.Theme.Color("TextInverse"), 18)
	self.PlayIcon.Parent = self.PlayButton
end

function Audio:SetVolume(Volume)
	self.Volume = Utilities.Clamp(Volume, 0, 1)
	self.VolumeFill.Size = UDim2.new(self.Volume, 0, 1, 0)
end

function Audio:SetSoundId(Id)
	self.SoundId = Id
end

return Audio

end

Modules["Widgets.Base"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Events = VoidRequire("Core.Events")
local Cleanup = VoidRequire("Core.Cleanup")

local Base = {}
Base.__index = Base

function Base.new(Application, Parent, Options)
	local self = setmetatable({}, Base)
	self.Application = Application
	self.Theme = Application.Theme
	self.Renderer = Application.Renderer
	self.Animation = Application.Animation
	self.Parent = Parent
	self.Options = Options or {}
	self.Instance = nil
	self.Container = nil
	self.Changed = Events.new()
	self.Destroyed = Events.new()
	self.Cleanup = Cleanup.new()
	self.Enabled = true
	self.Visible = true
	self.LayoutOrder = 0
	self._Hover = false
	self._Focused = false
	return self
end

function Base:SetParent(Parent)
	self.Parent = Parent
	if self.Container then
		self.Container.Parent = Parent
	end
end

function Base:SetLayoutOrder(Order)
	self.LayoutOrder = Order
	if self.Container then
		self.Container.LayoutOrder = Order
	end
end

function Base:SetEnabled(Enabled)
	self.Enabled = Enabled
	if self.Container then
		self.Container.Visible = Enabled
	end
end

function Base:SetVisible(Visible)
	self.Visible = Visible
	if self.Container then
		self.Container.Visible = Visible
	end
end

function Base:IsEnabled()
	return self.Enabled
end

function Base:IsVisible()
	return self.Visible
end

function Base:GetSize()
	if self.Container then
		return self.Container.AbsoluteSize
	end
	return Vector2.new(0, 0)
end

function Base:GetInstance()
	return self.Container or self.Instance
end

function Base:_CreateContainer(Height)
	local Theme = self.Theme
	local Container = Utilities.Create("Frame", {
		Name = "Widget",
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, Height or 36),
		AutomaticSize = Enum.AutomaticSize.Y,
		LayoutOrder = self.LayoutOrder,
		Parent = self.Parent,
	})
	self.Container = Container
	return Container
end

function Base:_CreateCard(Height, Properties)
	local Theme = self.Theme
	local Card = Utilities.Create("Frame", Utilities.Merge({
		Name = "Card",
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, Height or 36),
		Parent = self.Container,
	}, Properties or {}))
	local Corner = Utilities.Roundify(Card, Theme.Layout("RadiusSmall"))
	local Stroke = Utilities.AddStroke(Card, Theme.Color("Border"), Theme.Layout("BorderThickness"))
	self.Instance = Card
	return Card
end

function Base:_SetupHover(Card, HoverColor, GlowColor)
	local Theme = self.Theme
	HoverColor = HoverColor or Theme.Color("SurfaceHover")
	GlowColor = GlowColor or Theme.Color("AccentGlow")
	local Enter = Card.MouseEnter:Connect(function()
		self._Hover = true
		self.Animation:Animate(Card, "BackgroundColor3", HoverColor, { Duration = 0.15 })
		self.Renderer:ShowGlow(Card, 0.3)
	end)
	local Leave = Card.MouseLeave:Connect(function()
		self._Hover = false
		self.Animation:Animate(Card, "BackgroundColor3", Theme.Color("Surface"), { Duration = 0.15 })
		self.Renderer:HideGlow(Card)
	end)
	self.Cleanup:AddConnection(Enter)
	self.Cleanup:AddConnection(Leave)
end

function Base:_ApplyTheme()
	if self.Instance then
		self.Instance.BackgroundColor3 = self.Theme.Color("Surface")
	end
end

function Base:OnChanged(Callback)
	return self.Changed:Connect(Callback)
end

function Base:TriggerChanged(...)
	self.Changed:Fire(...)
end

function Base:Destroy()
	if self.Destroyed.Connected then
		self.Destroyed:Fire()
	end
	self.Cleanup:Destroy()
	if self.Container then
		self.Container:Destroy()
	end
	self.Changed:DisconnectAll()
	self.Destroyed:DisconnectAll()
end

return Base

end

Modules["Widgets.Breadcrumbs"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local Breadcrumbs = {}
Breadcrumbs.__index = setmetatable(Breadcrumbs, Base)

function Breadcrumbs.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options or {}), Breadcrumbs)
	self.Items = (Options and Options.Items) or {}
	self.OnNavigate = Options and Options.OnNavigate
	self:_Build()
	return self
end

function Breadcrumbs:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(28)
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})
	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Horizontal, 4, Enum.HorizontalAlignment.Left)
	Layout.VerticalAlignment = Enum.VerticalAlignment.Center
	local Padding = Utilities.AddPadding(Card, 10)
	self.Card = Card
	self:_Render()
end

function Breadcrumbs:_Render()
	for _, Child in ipairs(self.Card:GetChildren()) do
		if Child:IsA("TextButton") or Child:IsA("TextLabel") or Child:IsA("Frame") then
			Child:Destroy()
		end
	end
	local Theme = self.Theme
	for Index, Item in ipairs(self.Items) do
		local IsLast = Index == #self.Items
		local Crumb = Utilities.Create("TextButton", {
			BackgroundColor3 = Theme.Color("Surface"),
			BorderSizePixel = 0,
			Size = UDim2.new(0, 0, 1, -8),
			AutomaticSize = Enum.AutomaticSize.X,
			AutoButtonColor = false,
			Text = "",
			Parent = self.Card,
		})
		local CrumbCorner = Utilities.Roundify(Crumb, Theme.Layout("RadiusSmall"))
		local CrumbLayout = Utilities.AddListLayout(Crumb, Enum.FillDirection.Horizontal, 6, Enum.HorizontalAlignment.Left)
		CrumbLayout.VerticalAlignment = Enum.VerticalAlignment.Center
		CrumbLayout.Padding = UDim.new(0, 8)
		local CrumbPadding = Utilities.AddPadding(Crumb, 8)

		if Item.Icon then
			local IconFrame = Icons.Create(Item.Icon, IsLast and Theme.Color("Accent") or Theme.Color("TextMuted"), 14)
			IconFrame.Parent = Crumb
		end
		local Label = Utilities.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(0, 0, 1, 0),
			AutomaticSize = Enum.AutomaticSize.X,
			Font = Theme.Typography("Font"),
			TextSize = Theme.Typography("CaptionSize"),
			TextColor3 = IsLast and Theme.Color("Accent") or Theme.Color("TextMuted"),
			Text = Item.Label or Item.Name or "",
			Parent = Crumb,
		})
		if not IsLast then
			local Click = Crumb.MouseButton1Click:Connect(function()
				self.Changed:Fire(Item, Index)
				Utilities.SafeCall(self.OnNavigate, Item, Index)
			end)
			self.Cleanup:AddConnection(Click)
		end

		if not IsLast then
			local Separator = Utilities.Create("TextLabel", {
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				Size = UDim2.new(0, 12, 1, 0),
				Font = Theme.Typography("Font"),
				TextSize = Theme.Typography("CaptionSize"),
				TextColor3 = Theme.Color("TextDim"),
				Text = "/",
				Parent = self.Card,
			})
		end
	end
end

function Breadcrumbs:SetItems(Items)
	self.Items = Items
	self:_Render()
end

function Breadcrumbs:Push(Item)
	table.insert(self.Items, Item)
	self:_Render()
end

function Breadcrumbs:Pop()
	table.remove(self.Items)
	self:_Render()
end

return Breadcrumbs

end

Modules["Widgets.Button"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local Button = {}
Button.__index = setmetatable(Button, Base)

function Button.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Button)
	self.Variant = Options.Variant or "Primary"
	self.Icon = Options.Icon
	self.Text = Options.Text or "Button"
	self.Callback = Options.Callback
	self.Loading = false
	self:_Build()
	return self
end

function Button:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(44)
	local Colors = self:_ResolveColors()

	local Card = Utilities.Create("TextButton", {
		Name = "Button",
		BackgroundColor3 = Colors.Background,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		AutoButtonColor = false,
		Text = "",
		Parent = Container,
	})
	local Corner = Utilities.Roundify(Card, Theme.Layout("Radius"))
	local Stroke = Utilities.AddStroke(Card, Colors.Stroke, Theme.Layout("BorderThickness"))
	local Gradient = Utilities.AddGradient(Card, Colors.Gradient, 90)
	Gradient.Transparency = NumberSequence.new(Colors.GradientTransparency)
	self.Instance = Card
	self.Stroke = Stroke

	local Content = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		Parent = Card,
	})
	local Layout = Utilities.AddListLayout(Content, Enum.FillDirection.Horizontal, 8, Enum.HorizontalAlignment.Center)
	Layout.VerticalAlignment = Enum.VerticalAlignment.Center

	if self.Icon then
		local IconFrame = Icons.Create(self.Icon, Colors.Text, 18)
		IconFrame.Parent = Content
		self.IconFrame = IconFrame
	end

	local Label = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(0, 0, 1, 0),
		AutomaticSize = Enum.AutomaticSize.X,
		Font = Theme.Typography("FontSemibold"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Colors.Text,
		Text = self.Text,
		Parent = Content,
	})
	self.Label = Label

	self:_SetupInteractions(Card, Colors)
end

function Button:_ResolveColors()
	local Theme = self.Theme
	local Variant = self.Variant
	if Variant == "Primary" then
		return {
			Background = Theme.Color("Accent"),
			Stroke = Theme.Color("AccentLight"),
			Text = Theme.Color("TextInverse"),
			Gradient = Theme.Gradient("Accent"),
			GradientTransparency = 0.4,
		}
	elseif Variant == "Danger" then
		return {
			Background = Theme.Color("Danger"),
			Stroke = Theme.Color("Danger"),
			Text = Color3.fromRGB(255, 255, 255),
			Gradient = ColorSequence.new(Theme.Color("Danger")),
			GradientTransparency = 0.5,
		}
	elseif Variant == "Ghost" then
		return {
			Background = Theme.Color("Surface"),
			Stroke = Theme.Color("Border"),
			Text = Theme.Color("Text"),
			Gradient = ColorSequence.new(Theme.Color("Surface")),
			GradientTransparency = 1,
		}
	elseif Variant == "Icon" then
		return {
			Background = Theme.Color("Surface"),
			Stroke = Theme.Color("Border"),
			Text = Theme.Color("Text"),
			Gradient = ColorSequence.new(Theme.Color("Surface")),
			GradientTransparency = 1,
		}
	else
		return {
			Background = Theme.Color("SurfaceHover"),
			Stroke = Theme.Color("BorderStrong"),
			Text = Theme.Color("Text"),
			Gradient = ColorSequence.new(Theme.Color("SurfaceHover")),
			GradientTransparency = 1,
		}
	end
end

function Button:_SetupInteractions(Card, Colors)
	local Theme = self.Theme
	local Enter = Card.MouseEnter:Connect(function()
		self.Animation:Animate(Card, "BackgroundColor3", Theme.Color("AccentLight"), { Duration = 0.15 })
		self.Renderer:ShowGlow(Card, 0.4)
		self.Animation:Animate(Card, "Size", UDim2.new(1, 0, 1, -2), { Duration = 0.12, Easing = "QuadOut" })
	end)
	local Leave = Card.MouseLeave:Connect(function()
		self.Animation:Animate(Card, "BackgroundColor3", Colors.Background, { Duration = 0.15 })
		self.Renderer:HideGlow(Card)
		self.Animation:Animate(Card, "Size", UDim2.new(1, 0, 1, 0), { Duration = 0.12, Easing = "QuadOut" })
	end)
	local Down = Card.MouseButton1Down:Connect(function()
		self.Animation:Animate(Card, "Size", UDim2.new(1, 0, 1, 2), { Duration = 0.1 })
	end)
	local Up = Card.MouseButton1Up:Connect(function()
		self.Animation:Animate(Card, "Size", UDim2.new(1, 0, 1, -2), { Duration = 0.1 })
	end)
	local Click = Card.MouseButton1Click:Connect(function()
		if self.Loading then
			return
		end
		self.Renderer:Pulse(Card, 1.03)
		Utilities.SafeCall(self.Callback)
		self.Changed:Fire(self.Text)
	end)
	self.Cleanup:AddConnection(Enter)
	self.Cleanup:AddConnection(Leave)
	self.Cleanup:AddConnection(Down)
	self.Cleanup:AddConnection(Up)
	self.Cleanup:AddConnection(Click)
end

function Button:SetText(Text)
	self.Text = Text
	self.Label.Text = Text
end

function Button:SetVariant(Variant)
	self.Variant = Variant
	local Colors = self:_ResolveColors()
	self.Instance.BackgroundColor3 = Colors.Background
	self.Stroke.Color = Colors.Stroke
	self.Label.TextColor3 = Colors.Text
end

function Button:SetIcon(Icon)
	if self.IconFrame then
		self.IconFrame:Destroy()
		self.IconFrame = nil
	end
	if Icon then
		local Colors = self:_ResolveColors()
		self.IconFrame = Icons.Create(Icon, Colors.Text, 18)
		self.IconFrame.Parent = self.Instance:FindFirstChildOfClass("Frame")
	end
	self.Icon = Icon
end

function Button:SetCallback(Callback)
	self.Callback = Callback
end

function Button:SetLoading(Loading)
	self.Loading = Loading
	self.Instance.AutoButtonColor = not Loading
	self.Instance.BackgroundTransparency = Loading and 0.4 or 0
end

function Button:Click()
	Utilities.SafeCall(self.Callback)
end

return Button

end

Modules["Widgets.Chart"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")

local Chart = {}
Chart.__index = setmetatable(Chart, Base)

function Chart.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Chart)
	self.Type = Options.Type or "Bar"
	self.Data = Options.Data or {}
	self.Width = Options.Width or 280
	self.Height = Options.Height or 160
	self.Colors = Options.Colors or { self.Theme.Color("Accent"), self.Theme.Color("Success"), self.Theme.Color("Warning"), self.Theme.Color("Danger"), self.Theme.Color("Info") }
	self.ShowLegend = Options.ShowLegend or false
	self:_Build()
	return self
end

function Chart:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(self.Height + (self.ShowLegend and 40 or 8))
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})
	local Padding = Utilities.AddPadding(Card, 12)

	local Canvas = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, self.Height),
		Parent = Card,
	})
	self.Canvas = Canvas

	if self.ShowLegend then
		local Legend = Utilities.Create("Frame", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 28),
			Parent = Card,
		})
		local LegendLayout = Utilities.AddListLayout(Legend, Enum.FillDirection.Horizontal, 12, Enum.HorizontalAlignment.Center)
		LegendLayout.VerticalAlignment = Enum.VerticalAlignment.Center
		self.Legend = Legend
	end

	self:_Render()
end

function Chart:_Render()
	for _, Child in ipairs(self.Canvas:GetChildren()) do
		if Child:IsA("Frame") or Child:IsA("TextLabel") then
			Child:Destroy()
		end
	end
	local Data = self.Data
	local Count = #Data
	if Count == 0 then
		return
	end
	local Width = self.Canvas.AbsoluteSize.X
	local Height = self.Canvas.AbsoluteSize.Y

	if self.Type == "Bar" then
		local Max = 0
		for _, Item in ipairs(Data) do
			Max = math.max(Max, Item.Value or 0)
		end
		local Slot = Width / Count
		local BarWidth = Slot * 0.6
		for I, Item in ipairs(Data) do
			local Ratio = Max > 0 and (Item.Value or 0) / Max or 0
			local BarHeight = Ratio * (Height - 20)
			local Color = self.Colors[(I - 1) % #self.Colors + 1]
			local Bar = Utilities.Create("Frame", {
				BackgroundColor3 = Color,
				BorderSizePixel = 0,
				Size = UDim2.new(0, BarWidth, 0, 0),
				Position = UDim2.new(0, (I - 1) * Slot + (Slot - BarWidth) / 2, 1, -20),
				AnchorPoint = Vector2.new(0, 1),
				Parent = self.Canvas,
			})
			local BarCorner = Utilities.Roundify(Bar, 4)
			local BarGradient = Utilities.AddGradient(Bar, ColorSequence.new({
				ColorSequenceKeypoint.new(0, Utilities.Lighten(Color, 0.2)),
				ColorSequenceKeypoint.new(1, Color),
			}), 90)
			self.Animation:Tween({
				Duration = 0.4,
				Easing = "BackOut",
				Delay = I * 0.04,
				OnUpdate = function(_, _, Progress)
					Bar.Size = UDim2.new(0, BarWidth, 0, BarHeight * Progress)
				end,
			})
			local Label = Utilities.Create("TextLabel", {
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				Size = UDim2.new(0, Slot, 0, 16),
				Position = UDim2.new(0, (I - 1) * Slot, 1, 0),
				AnchorPoint = Vector2.new(0, 1),
				Font = self.Theme.Typography("Font"),
				TextSize = self.Theme.Typography("SmallSize"),
				TextColor3 = self.Theme.Color("TextMuted"),
				Text = tostring(Item.Label or ""),
				Parent = self.Canvas,
			})
		end
	elseif self.Type == "Pie" then
		local Total = 0
		for _, Item in ipairs(Data) do
			Total = Total + (Item.Value or 0)
		end
		local Center = Utilities.Create("Frame", {
			BackgroundColor3 = self.Theme.Color("SurfaceActive"),
			BorderSizePixel = 0,
			Size = UDim2.fromOffset(Height - 20, Height - 20),
			Position = UDim2.fromScale(0.5, 0.5),
			AnchorPoint = Vector2.new(0.5, 0.5),
			Parent = self.Canvas,
		})
		local CenterCorner = Utilities.Roundify(Center, 999)
		local Angle = 0
		for I, Item in ipairs(Data) do
			local Fraction = Total > 0 and (Item.Value or 0) / Total or 0
			local Color = self.Colors[(I - 1) % #self.Colors + 1]
			local Slice = Utilities.Create("Frame", {
				BackgroundColor3 = Color,
				BorderSizePixel = 0,
				Size = UDim2.fromScale(1, 1),
				Parent = Center,
			})
			local SliceCorner = Utilities.Roundify(Slice, 999)
			Slice.ClipsDescendants = true
		end
	end
end

function Chart:SetData(Data)
	self.Data = Data
	self:_Render()
end

function Chart:SetType(Type)
	self.Type = Type
	self:_Render()
end

return Chart

end

Modules["Widgets.CodeEditor"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local CodeEditor = {}
CodeEditor.__index = setmetatable(CodeEditor, Base)

function CodeEditor.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), CodeEditor)
	self.Code = Options.Code or ""
	self.Language = Options.Language or "lua"
	self.LineNumbers = Options.LineNumbers ~= false
	self:_Build()
	return self
end

function CodeEditor:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(0)
	Container.AutomaticSize = Enum.AutomaticSize.Y
	local Card = self:_CreateCard(0, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})

	local Toolbar = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 30),
		Parent = Card,
	})
	local ToolbarCorner = Utilities.Roundify(Toolbar, Theme.Layout("RadiusSmall"))
	local ToolbarLayout = Utilities.AddListLayout(Toolbar, Enum.FillDirection.Horizontal, 8, Enum.HorizontalAlignment.Left)
	ToolbarLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	ToolbarLayout.Padding = UDim.new(0, 10)
	local ToolbarPadding = Utilities.AddPadding(Toolbar, 10)

	local Title = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -120, 1, 0),
		Font = Theme.Typography("FontBold"),
		TextSize = Theme.Typography("CaptionSize"),
		TextColor3 = Theme.Color("TextMuted"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Language:upper() .. " Editor",
		Parent = Toolbar,
	})

	local RunButton = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("Accent"),
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(50, 22),
		AutoButtonColor = false,
		Font = Theme.Typography("FontSemibold"),
		TextSize = Theme.Typography("SmallSize"),
		TextColor3 = Theme.Color("TextInverse"),
		Text = "Run",
		Parent = Toolbar,
	})
	local RunCorner = Utilities.Roundify(RunButton, Theme.Layout("RadiusSmall"))
	local RunClick = RunButton.MouseButton1Click:Connect(function()
		self:Run()
	end)
	self.Cleanup:AddConnection(RunClick)

	local Body = Utilities.Create("Frame", {
		BackgroundColor3 = Color3.fromRGB(10, 11, 15),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, (self.Options and self.Options.Height) or 200),
		Parent = Card,
	})
	local BodyCorner = Utilities.Roundify(Body, Theme.Layout("RadiusSmall"))
	local BodyLayout = Utilities.AddListLayout(Body, Enum.FillDirection.Horizontal, 0, Enum.HorizontalAlignment.Left)

	local Gutter = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(40, 1),
		Parent = Body,
	})
	local GutterLayout = Utilities.AddListLayout(Gutter, Enum.FillDirection.Vertical, 0, Enum.HorizontalAlignment.Right)
	GutterLayout.Padding = UDim.new(0, 6)
	local GutterPadding = Utilities.AddPadding(Gutter, 6)

	local Editor = Utilities.Create("TextBox", {
		BackgroundColor3 = Color3.fromRGB(10, 11, 15),
		BorderSizePixel = 0,
		Size = UDim2.new(1, -40, 1, 0),
		Font = Theme.Typography("FontMono"),
		TextSize = Theme.Typography("CaptionSize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		TextYAlignment = Enum.TextYAlignment.Top,
		Text = self.Code,
		MultiLine = true,
		ClearTextOnFocus = false,
		Parent = Body,
	})
	local EditorPadding = Utilities.AddPadding(Editor, 8)

	self.Gutter = Gutter
	self.Editor = Editor

	local Changed = Editor:GetPropertyChangedSignal("Text"):Connect(function()
		self.Code = Editor.Text
		self:_UpdateGutter()
	end)
	self.Cleanup:AddConnection(Changed)

	self:_UpdateGutter()
end

function CodeEditor:_UpdateGutter()
	for _, Child in ipairs(self.Gutter:GetChildren()) do
		if Child:IsA("TextLabel") then
			Child:Destroy()
		end
	end
	local Lines = Utilities.Split(self.Code, "\n")
	for Index, _ in ipairs(Lines) do
		local Number = Utilities.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 18),
			Font = self.Theme.Typography("FontMono"),
			TextSize = self.Theme.Typography("SmallSize"),
			TextColor3 = self.Theme.Color("TextDim"),
			TextXAlignment = Enum.TextXAlignment.Right,
			Text = tostring(Index),
			Parent = self.Gutter,
		})
	end
end

function CodeEditor:Run()
	local Success, Result = pcall(function()
		return loadstring(self.Code)()
	end)
	if not Success then
		warn("[VoidUI] CodeEditor error:", Result)
	end
	return Result
end

function CodeEditor:SetCode(Code)
	self.Code = Code
	self.Editor.Text = Code
	self:_UpdateGutter()
end

function CodeEditor:GetCode()
	return self.Code
end

return CodeEditor

end

Modules["Widgets.ColorPicker"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local ColorPicker = {}
ColorPicker.__index = setmetatable(ColorPicker, Base)

function ColorPicker.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), ColorPicker)
	self.Value = Options.Default or Color3.fromRGB(124, 162, 255)
	self.Label = Options.Label or "Color"
	self.Callback = Options.Callback
	self.Open = false
	local H, S, V = Color3.toHSV(self.Value)
	self.Hue = H
	self.Saturation = S
	self.ValueV = V
	self:_Build()
	return self
end

function ColorPicker:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(self.Label ~= "" and 66 or 44)
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})

	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Horizontal, 12, Enum.HorizontalAlignment.Left)
	Layout.VerticalAlignment = Enum.VerticalAlignment.Center
	local Padding = Utilities.AddPadding(Card, 12)

	local TextBlock = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -60, 1, 0),
		Parent = Card,
	})
	local TextLayout = Utilities.AddListLayout(TextBlock, Enum.FillDirection.Vertical, 2)
	local Label = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 18),
		Font = Theme.Typography("FontSemibold"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Label,
		Parent = TextBlock,
	})
	local HexLabel = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 14),
		Font = Theme.Typography("FontMono"),
		TextSize = Theme.Typography("SmallSize"),
		TextColor3 = Theme.Color("TextDim"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = Utilities.Color3ToHex(self.Value),
		Parent = TextBlock,
	})

	local Swatch = Utilities.Create("TextButton", {
		BackgroundColor3 = self.Value,
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(40, 40),
		AutoButtonColor = false,
		Parent = Card,
	})
	local SwatchCorner = Utilities.Roundify(Swatch, Theme.Layout("RadiusSmall"))
	local SwatchStroke = Utilities.AddStroke(Swatch, Theme.Color("Border"), 1)

	self.Swatch = Swatch
	self.HexLabel = HexLabel

	self:_BuildPanel()
	self:_SetupInteractions(Swatch)
end

function ColorPicker:_BuildPanel()
	local Theme = self.Theme
	local Panel = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("CardElevated"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		ClipsDescendants = true,
		Visible = false,
		Parent = self.Container,
	})
	local PanelCorner = Utilities.Roundify(Panel, Theme.Layout("RadiusSmall"))
	local PanelStroke = Utilities.AddStroke(Panel, Theme.Color("Border"), 1)
	local PanelPadding = Utilities.AddPadding(Panel, 12)
	local PanelLayout = Utilities.AddListLayout(Panel, Enum.FillDirection.Vertical, 10, Enum.HorizontalAlignment.Center)

	local SatVal = Utilities.Create("TextButton", {
		BackgroundColor3 = Color3.fromHSV(self.Hue, 1, 1),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 140),
		AutoButtonColor = false,
		Text = "",
		Parent = Panel,
	})
	local SatValCorner = Utilities.Roundify(SatVal, Theme.Layout("RadiusSmall"))
	local SatValGradient = Utilities.AddGradient(SatVal, ColorSequence.new({
		ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 255, 255)),
		ColorSequenceKeypoint.new(1, Color3.fromHSV(self.Hue, 1, 1)),
	}), 90)
	local SatValOverlay = Utilities.Create("Frame", {
		BackgroundColor3 = Color3.fromRGB(0, 0, 0),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		Parent = SatVal,
	})
	local OverlayGradient = Utilities.AddGradient(SatValOverlay, ColorSequence.new({
		ColorSequenceKeypoint.new(0, Color3.fromRGB(0, 0, 0)),
		ColorSequenceKeypoint.new(1, Color3.fromRGB(0, 0, 0)),
	}), 0)
	OverlayGradient.Transparency = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0),
		NumberSequenceKeypoint.new(1, 1),
	})
	local Cursor = Utilities.Create("Frame", {
		BackgroundColor3 = Color3.fromRGB(255, 255, 255),
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(12, 12),
		AnchorPoint = Vector2.new(0.5, 0.5),
		Parent = SatVal,
	})
	local CursorCorner = Utilities.Roundify(Cursor, 999)
	local CursorStroke = Utilities.AddStroke(Cursor, Color3.fromRGB(0, 0, 0), 2)

	local HueBar = Utilities.Create("TextButton", {
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 16),
		AutoButtonColor = false,
		Text = "",
		Parent = Panel,
	})
	local HueBarCorner = Utilities.Roundify(HueBar, 999)
	local HueGradient = Utilities.AddGradient(HueBar, ColorSequence.new({
		ColorSequenceKeypoint.new(0, Color3.fromHSV(0, 1, 1)),
		ColorSequenceKeypoint.new(0.17, Color3.fromHSV(0.17, 1, 1)),
		ColorSequenceKeypoint.new(0.33, Color3.fromHSV(0.33, 1, 1)),
		ColorSequenceKeypoint.new(0.5, Color3.fromHSV(0.5, 1, 1)),
		ColorSequenceKeypoint.new(0.67, Color3.fromHSV(0.67, 1, 1)),
		ColorSequenceKeypoint.new(0.83, Color3.fromHSV(0.83, 1, 1)),
		ColorSequenceKeypoint.new(1, Color3.fromHSV(1, 1, 1)),
	}), 0)

	self.Panel = Panel
	self.SatVal = SatVal
	self.SatValGradient = SatValGradient
	self.Cursor = Cursor
	self.HueBar = HueBar

	self:_SetupPanelInteractions(SatVal, HueBar)
	self:_UpdateCursor()
end

function ColorPicker:_SetupPanelInteractions(SatVal, HueBar)
	local UserInputService = game:GetService("UserInputService")
	local SV_Drag = false
	local Hue_Drag = false

	local function UpdateSV(Input)
		local Pos = Input.Position - SatVal.AbsolutePosition
		local Size = SatVal.AbsoluteSize
		self.Saturation = Utilities.Clamp(Pos.X / Size.X, 0, 1)
		self.ValueV = Utilities.Clamp(1 - Pos.Y / Size.Y, 0, 1)
		self:_ApplyColor()
	end
	local function UpdateHue(Input)
		local Pos = Input.Position - HueBar.AbsolutePosition
		local Size = HueBar.AbsoluteSize
		self.Hue = Utilities.Clamp(Pos.X / Size.X, 0, 1)
		self.SatValGradient.Color = ColorSequence.new({
			ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 255, 255)),
			ColorSequenceKeypoint.new(1, Color3.fromHSV(self.Hue, 1, 1)),
		})
		self:_ApplyColor()
	end

	local SVBegin = SatVal.InputBegan:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 or Input.UserInputType == Enum.UserInputType.Touch then
			SV_Drag = true
			UpdateSV(Input)
		end
	end)
	local HueBegin = HueBar.InputBegan:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 or Input.UserInputType == Enum.UserInputType.Touch then
			Hue_Drag = true
			UpdateHue(Input)
		end
	end)
	local End = UserInputService.InputEnded:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 or Input.UserInputType == Enum.UserInputType.Touch then
			SV_Drag = false
			Hue_Drag = false
		end
	end)
	local Move = UserInputService.InputChanged:Connect(function(Input)
		if (Input.UserInputType == Enum.UserInputType.MouseMovement or Input.UserInputType == Enum.UserInputType.Touch) then
			if SV_Drag then UpdateSV(Input) end
			if Hue_Drag then UpdateHue(Input) end
		end
	end)
	self.Cleanup:AddConnection(SVBegin)
	self.Cleanup:AddConnection(HueBegin)
	self.Cleanup:AddConnection(End)
	self.Cleanup:AddConnection(Move)
end

function ColorPicker:_ApplyColor()
	local Color = Color3.fromHSV(self.Hue, self.Saturation, self.ValueV)
	self.Value = Color
	self.Swatch.BackgroundColor3 = Color
	self.HexLabel.Text = Utilities.Color3ToHex(Color)
	self:_UpdateCursor()
	self.Changed:Fire(Color)
	Utilities.SafeCall(self.Callback, Color)
end

function ColorPicker:_UpdateCursor()
	self.Cursor.Position = UDim2.new(self.Saturation, 0, 1 - self.ValueV, 0)
end

function ColorPicker:_SetupInteractions(Swatch)
	local Click = Swatch.MouseButton1Click:Connect(function()
		self:Toggle()
	end)
	self.Cleanup:AddConnection(Click)
end

function ColorPicker:Toggle()
	self.Open = not self.Open
	self.Panel.Visible = true
	local TargetHeight = self.Open and 200 or 0
	self.Animation:Tween({
		Duration = 0.25,
		Easing = "QuadOut",
		OnUpdate = function(_, _, Progress)
			self.Panel.Size = UDim2.new(1, 0, 0, TargetHeight * Progress)
		end,
		OnComplete = function()
			if not self.Open then
				self.Panel.Visible = false
			end
		end,
	})
end

function ColorPicker:Set(Color)
	self.Value = Color
	local H, S, V = Color3.toHSV(Color)
	self.Hue = H
	self.Saturation = S
	self.ValueV = V
	self.Swatch.BackgroundColor3 = Color
	self.HexLabel.Text = Utilities.Color3ToHex(Color)
	self.SatValGradient.Color = ColorSequence.new({
		ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 255, 255)),
		ColorSequenceKeypoint.new(1, Color3.fromHSV(self.Hue, 1, 1)),
	})
	self:_UpdateCursor()
end

function ColorPicker:Get()
	return self.Value
end

return ColorPicker

end

Modules["Widgets.CommandPalette"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local CommandPalette = {}
CommandPalette.__index = setmetatable(CommandPalette, Base)

function CommandPalette.new(Application, Options)
	local self = setmetatable(Base.new(Application, Application.Renderer:GetLayer("Overlays"), Options), CommandPalette)
	self.Commands = Options and Options.Commands or {}
	self.Open = false
	self:_Build()
	return self
end

function CommandPalette:_Build()
	local Theme = self.Theme
	local Backdrop = Utilities.Create("Frame", {
		BackgroundColor3 = Color3.fromRGB(0, 0, 0),
		BackgroundTransparency = 0.6,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		Visible = false,
		ZIndex = 200,
		Parent = self.Parent,
	})

	local Panel = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("CardElevated"),
		BorderSizePixel = 0,
		Size = UDim2.new(0, 520, 0, 0),
		Position = UDim2.fromScale(0.5, 0.3),
		AnchorPoint = Vector2.new(0.5, 0),
		ZIndex = 201,
		ClipsDescendants = true,
		Parent = Backdrop,
	})
	local PanelCorner = Utilities.Roundify(Panel, Theme.Layout("RadiusLarge"))
	local PanelStroke = Utilities.AddStroke(Panel, Theme.Color("Border"), 1)
	local PanelGradient = Utilities.AddGradient(Panel, Theme.Gradient("Surface"), 90)
	PanelGradient.Transparency = NumberSequence.new(0.5)

	local SearchBox = Utilities.Create("TextBox", {
		BackgroundColor3 = Theme.Color("Background"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, -24, 0, 40),
		Position = UDim2.new(0, 12, 0, 12),
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		PlaceholderColor3 = Theme.Color("Placeholder"),
		PlaceholderText = "Search commands...",
		TextXAlignment = Enum.TextXAlignment.Left,
		ClearTextOnFocus = false,
		ZIndex = 202,
		Parent = Panel,
	})
	local SearchCorner = Utilities.Roundify(SearchBox, Theme.Layout("RadiusSmall"))
	local SearchStroke = Utilities.AddStroke(SearchBox, Theme.Color("Border"), 1)
	local SearchIcon = Icons.Create("Search", Theme.Color("TextDim"), 16)
	SearchIcon.Position = UDim2.new(0, 10, 0.5, 0)
	SearchIcon.AnchorPoint = Vector2.new(0, 0.5)
	SearchIcon.ZIndex = 203
	SearchIcon.Parent = SearchBox
	SearchBox.TextPadding = UDim.new(0, 28)

	local Results = Utilities.Create("ScrollingFrame", {
		BackgroundColor3 = Theme.Color("Card"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, -24, 1, -64),
		Position = UDim2.new(0, 12, 0, 60),
		CanvasSize = UDim2.new(0, 0, 0, 0),
		AutomaticCanvasSize = Enum.AutomaticCanvasSize.Y,
		ScrollBarThickness = 4,
		ScrollBarImageColor3 = Theme.Color("Scrollbar"),
		ZIndex = 202,
		Parent = Panel,
	})
	local ResultsCorner = Utilities.Roundify(Results, Theme.Layout("RadiusSmall"))
	local ResultsLayout = Utilities.AddListLayout(Results, Enum.FillDirection.Vertical, 4, Enum.HorizontalAlignment.Center)
	ResultsLayout.Padding = UDim.new(0, 4)
	local ResultsPadding = Utilities.AddPadding(Results, 6)

	self.Backdrop = Backdrop
	self.Panel = Panel
	self.SearchBox = SearchBox
	self.Results = Results

	local Changed = SearchBox:GetPropertyChangedSignal("Text"):Connect(function()
		self:_Filter(SearchBox.Text)
	end)
	self.Cleanup:AddConnection(Changed)

	local BackdropClick = Backdrop.InputBegan:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 and Input.Position.Y < Panel.AbsolutePosition.Y then
			self:Close()
		end
	end)
	self.Cleanup:AddConnection(BackdropClick)

	local Focus = SearchBox.FocusLost:Connect(function(Enter, _, _)
		if Enter then
			self:_ExecuteFirst()
		end
	end)
	self.Cleanup:AddConnection(Focus)

	self:_Filter("")
end

function CommandPalette:Register(Name, Description, Callback, Icon)
	table.insert(self.Commands, {
		Name = Name,
		Description = Description or "",
		Callback = Callback,
		Icon = Icon,
	})
end

function CommandPalette:_Filter(Query)
	local Theme = self.Theme
	Query = string.lower(Query)
	for _, Child in ipairs(self.Results:GetChildren()) do
		if Child:IsA("TextButton") then
			Child:Destroy()
		end
	end
	local Count = 0
	for _, Command in ipairs(self.Commands) do
		if Query == "" or string.find(string.lower(Command.Name), Query, 1, true) then
			local Item = Utilities.Create("TextButton", {
				BackgroundColor3 = Theme.Color("Surface"),
				BorderSizePixel = 0,
				Size = UDim2.new(1, 0, 0, 40),
				AutoButtonColor = false,
				Text = "",
				ZIndex = 203,
				Parent = self.Results,
			})
			local ItemCorner = Utilities.Roundify(Item, Theme.Layout("RadiusSmall"))
			local ItemLayout = Utilities.AddListLayout(Item, Enum.FillDirection.Horizontal, 10, Enum.HorizontalAlignment.Left)
			ItemLayout.VerticalAlignment = Enum.VerticalAlignment.Center
			ItemLayout.Padding = UDim.new(0, 10)

			if Command.Icon then
				local IconFrame = Icons.Create(Command.Icon, Theme.Color("Accent"), 18)
				IconFrame.ZIndex = 204
				IconFrame.Parent = Item
			end
			local TextBlock = Utilities.Create("Frame", {
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				Size = UDim2.new(1, -40, 1, 0),
				ZIndex = 204,
				Parent = Item,
			})
			local TextLayout = Utilities.AddListLayout(TextBlock, Enum.FillDirection.Vertical, 0)
			local NameLabel = Utilities.Create("TextLabel", {
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				Size = UDim2.new(1, 0, 0, 18),
				Font = Theme.Typography("FontSemibold"),
				TextSize = Theme.Typography("BodySize"),
				TextColor3 = Theme.Color("Text"),
				TextXAlignment = Enum.TextXAlignment.Left,
				Text = Command.Name,
				ZIndex = 205,
				Parent = TextBlock,
			})
			local DescLabel = Utilities.Create("TextLabel", {
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				Size = UDim2.new(1, 0, 0, 14),
				Font = Theme.Typography("Font"),
				TextSize = Theme.Typography("SmallSize"),
				TextColor3 = Theme.Color("TextDim"),
				TextXAlignment = Enum.TextXAlignment.Left,
				Text = Command.Description,
				ZIndex = 205,
				Parent = TextBlock,
			})

			local Enter = Item.MouseEnter:Connect(function()
				self.Animation:Animate(Item, "BackgroundColor3", Theme.Color("SurfaceHover"), { Duration = 0.1 })
			end)
			local Leave = Item.MouseLeave:Connect(function()
				self.Animation:Animate(Item, "BackgroundColor3", Theme.Color("Surface"), { Duration = 0.1 })
			end)
			local Click = Item.MouseButton1Click:Connect(function()
				self:_Execute(Command)
			end)
			self.Cleanup:AddConnection(Enter)
			self.Cleanup:AddConnection(Leave)
			self.Cleanup:AddConnection(Click)
			Count = Count + 1
		end
	end
	self._Filtered = Count
end

function CommandPalette:_ExecuteFirst()
	if #self.Results:GetChildren() > 0 then
		local First = self.Results:GetChildren()[1]
		if First then
			First.MouseButton1Click:Fire()
		end
	end
end

function CommandPalette:_Execute(Command)
	self:Close()
	Utilities.SafeCall(Command.Callback)
end

function CommandPalette:Open()
	self.Open = true
	self.Backdrop.Visible = true
	self.Animation:Tween({
		Duration = 0.25,
		Easing = "BackOut",
		OnUpdate = function(_, _, Progress)
			self.Panel.Size = UDim2.new(0, 520, 0, 360 * Progress)
		end,
	})
	self.SearchBox:CaptureFocus()
end

function CommandPalette:Close()
	self.Open = false
	self.Animation:Tween({
		Duration = 0.2,
		Easing = "QuadIn",
		OnUpdate = function(_, _, Progress)
			self.Panel.Size = UDim2.new(0, 520, 0, 360 * (1 - Progress))
		end,
		OnComplete = function()
			self.Backdrop.Visible = false
		end,
	})
end

function CommandPalette:Toggle()
	if self.Open then
		self:Close()
	else
		self:Open()
	end
end

return CommandPalette

end

Modules["Widgets.Console"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local Console = {}
Console.__index = setmetatable(Console, Base)

function Console.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Console)
	self.MaxLines = Options.MaxLines or 200
	self.Lines = {}
	self.Filter = Options.Filter or {}
	self:_Build()
	return self
end

function Console:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(0)
	Container.AutomaticSize = Enum.AutomaticSize.Y
	local Card = self:_CreateCard(0, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})

	local Toolbar = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 32),
		Parent = Card,
	})
	local ToolbarCorner = Utilities.Roundify(Toolbar, Theme.Layout("RadiusSmall"))
	local ToolbarLayout = Utilities.AddListLayout(Toolbar, Enum.FillDirection.Horizontal, 6, Enum.HorizontalAlignment.Left)
	ToolbarLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	ToolbarLayout.Padding = UDim.new(0, 8)
	local ToolbarPadding = Utilities.AddPadding(Toolbar, 8)

	local Title = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -80, 1, 0),
		Font = Theme.Typography("FontBold"),
		TextSize = Theme.Typography("CaptionSize"),
		TextColor3 = Theme.Color("TextMuted"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = "Console",
		Parent = Toolbar,
	})

	local ClearButton = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("SurfaceHover"),
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(60, 22),
		AutoButtonColor = false,
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("SmallSize"),
		TextColor3 = Theme.Color("Text"),
		Text = "Clear",
		Parent = Toolbar,
	})
	local ClearCorner = Utilities.Roundify(ClearButton, Theme.Layout("RadiusSmall"))
	local ClearClick = ClearButton.MouseButton1Click:Connect(function()
		self:Clear()
		self.LogArea.CanvasPosition = Vector2.new(0, 0)
	end)
	self.Cleanup:AddConnection(ClearClick)

	local LogHeight = (self.Options and self.Options.Height) or 160
	local LogArea = Utilities.Create("ScrollingFrame", {
		BackgroundColor3 = Theme.Color("Background"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, LogHeight),
		CanvasSize = UDim2.new(0, 0, 0, 0),
		AutomaticCanvasSize = Enum.AutomaticCanvasSize.Y,
		ScrollBarThickness = 6,
		ScrollBarImageColor3 = Theme.Color("Scrollbar"),
		Parent = Card,
	})
	local LogCorner = Utilities.Roundify(LogArea, Theme.Layout("RadiusSmall"))
	local LogPadding = Utilities.AddPadding(LogArea, 8)
	local LogLayout = Utilities.AddListLayout(LogArea, Enum.FillDirection.Vertical, 2, Enum.HorizontalAlignment.Left)

	self.LogArea = LogArea
end

function Console:_AddLine(Text, Level)
	local Theme = self.Theme
	local ColorMap = {
		Info = Theme.Color("Text"),
		Success = Theme.Color("Success"),
		Warning = Theme.Color("Warning"),
		Error = Theme.Color("Danger"),
		Debug = Theme.Color("TextDim"),
	}
	local Color = ColorMap[Level] or Theme.Color("Text")
	local Prefix = {
		Info = "[INFO]",
		Success = "[ OK ]",
		Warning = "[WARN]",
		Error = "[ERR ]",
		Debug = "[DBG ]",
	}
	local Line = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 18),
		Font = Theme.Typography("FontMono"),
		TextSize = Theme.Typography("SmallSize"),
		TextColor3 = Color,
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = (Prefix[Level] or "") .. " " .. Text,
		Parent = self.LogArea,
	})
	table.insert(self.Lines, { Text = Text, Level = Level, Instance = Line })
	if #self.Lines > self.MaxLines then
		local Old = table.remove(self.Lines, 1)
		if Old.Instance then
			Old.Instance:Destroy()
		end
	end
	self.LogArea.CanvasPosition = Vector2.new(0, self.LogArea.CanvasSize.Y.Offset)
end

function Console:Log(Text)
	self:_AddLine(tostring(Text), "Info")
end

function Console:Success(Text)
	self:_AddLine(tostring(Text), "Success")
end

function Console:Warn(Text)
	self:_AddLine(tostring(Text), "Warning")
end

function Console:Error(Text)
	self:_AddLine(tostring(Text), "Error")
end

function Console:Debug(Text)
	self:_AddLine(tostring(Text), "Debug")
end

function Console:Clear()
	for _, Line in ipairs(self.Lines) do
		if Line.Instance then
			Line.Instance:Destroy()
		end
	end
	self.Lines = {}
end

function Console:GetLines()
	return self.Lines
end

return Console

end

Modules["Widgets.ContextMenu"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local ContextMenu = {}
ContextMenu.__index = setmetatable(ContextMenu, Base)

function ContextMenu.new(Application, Items)
	local self = setmetatable(Base.new(Application, Application.Renderer:GetLayer("Overlays"), {}), ContextMenu)
	self.Items = Items or {}
	self.Open = false
	self:_Build()
	return self
end

function ContextMenu:_Build()
	local Theme = self.Theme
	local Menu = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("CardElevated"),
		BorderSizePixel = 0,
		Size = UDim2.new(0, 200, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		ZIndex = 300,
		Visible = false,
		Parent = self.Parent,
	})
	local MenuCorner = Utilities.Roundify(Menu, Theme.Layout("Radius"))
	local MenuStroke = Utilities.AddStroke(Menu, Theme.Color("Border"), 1)
	local MenuGradient = Utilities.AddGradient(Menu, Theme.Gradient("Surface"), 90)
	MenuGradient.Transparency = NumberSequence.new(0.5)
	local MenuPadding = Utilities.AddPadding(Menu, 6)
	local MenuLayout = Utilities.AddListLayout(Menu, Enum.FillDirection.Vertical, 2, Enum.HorizontalAlignment.Center)
	self.Menu = Menu

	for _, Item in ipairs(self.Items) do
		self:_CreateItem(Item)
	end
end

function ContextMenu:_CreateItem(Item)
	local Theme = self.Theme
	if Item.Separator then
		local Divider = Utilities.Create("Frame", {
			BackgroundColor3 = Theme.Color("Border"),
			BorderSizePixel = 0,
			Size = UDim2.new(1, -12, 0, 1),
			Parent = self.Menu,
		})
		return
	end
	local Button = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 32),
		AutoButtonColor = false,
		Text = "",
		ZIndex = 301,
		Parent = self.Menu,
	})
	local ButtonCorner = Utilities.Roundify(Button, Theme.Layout("RadiusSmall"))
	local ButtonLayout = Utilities.AddListLayout(Button, Enum.FillDirection.Horizontal, 8, Enum.HorizontalAlignment.Left)
	ButtonLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	ButtonLayout.Padding = UDim.new(0, 8)

	if Item.Icon then
		local IconFrame = Icons.Create(Item.Icon, Item.Danger and Theme.Color("Danger") or Theme.Color("TextMuted"), 16)
		IconFrame.ZIndex = 302
		IconFrame.Parent = Button
	end

	local Label = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -40, 1, 0),
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Item.Danger and Theme.Color("Danger") or Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = Item.Label or Item.Title or "",
		ZIndex = 302,
		Parent = Button,
	})

	local Enter = Button.MouseEnter:Connect(function()
		self.Animation:Animate(Button, "BackgroundColor3", Theme.Color("SurfaceHover"), { Duration = 0.1 })
	end)
	local Leave = Button.MouseLeave:Connect(function()
		self.Animation:Animate(Button, "BackgroundColor3", Theme.Color("Surface"), { Duration = 0.1 })
	end)
	local Click = Button.MouseButton1Click:Connect(function()
		self:Close()
		Utilities.SafeCall(Item.Callback)
	end)
	self.Cleanup:AddConnection(Enter)
	self.Cleanup:AddConnection(Leave)
	self.Cleanup:AddConnection(Click)
end

function ContextMenu:Show(Position)
	self.Open = true
	self.Menu.Visible = true
	self.Menu.Position = UDim2.fromOffset(Position.X, Position.Y)
	self.Animation:Tween({
		Duration = 0.15,
		Easing = "BackOut",
		OnUpdate = function(_, _, Progress)
			self.Menu.Size = UDim2.new(0, 200, 0, self.Menu.AbsoluteSize.Y * Progress)
			self.Menu.BackgroundTransparency = 1 - Progress
		end,
	})
end

function ContextMenu:Close()
	self.Open = false
	self.Animation:Tween({
		Duration = 0.12,
		Easing = "QuadIn",
		OnUpdate = function(_, _, Progress)
			self.Menu.BackgroundTransparency = Progress
		end,
		OnComplete = function()
			self.Menu.Visible = false
		end,
	})
end

function ContextMenu:SetItems(Items)
	self.Items = Items
	for _, Child in ipairs(self.Menu:GetChildren()) do
		if Child:IsA("TextButton") or Child:IsA("Frame") then
			Child:Destroy()
		end
	end
	for _, Item in ipairs(Items) do
		self:_CreateItem(Item)
	end
end

return ContextMenu

end

Modules["Widgets.Divider"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")

local Divider = {}
Divider.__index = setmetatable(Divider, Base)

function Divider.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Divider)
	self.Orientation = Options.Orientation or "Horizontal"
	self.Text = Options.Text or ""
	self.Thickness = Options.Thickness or 1
	self:_Build()
	return self
end

function Divider:_Build()
	local Theme = self.Theme
	local IsHorizontal = self.Orientation == "Horizontal"
	local Container = self:_CreateContainer(self.Text ~= "" and 28 or self.Thickness + 12)

	if self.Text ~= "" then
		local Layout = Utilities.AddListLayout(Container, Enum.FillDirection.Horizontal, 10, Enum.HorizontalAlignment.Center)
		Layout.VerticalAlignment = Enum.VerticalAlignment.Center
		local Line1 = Utilities.Create("Frame", {
			BackgroundColor3 = Theme.Color("Border"),
			BorderSizePixel = 0,
			Size = UDim2.new(0.4, 0, 0, self.Thickness),
			Parent = Container,
		})
		local Label = Utilities.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(0, 0, 1, 0),
			AutomaticSize = Enum.AutomaticSize.X,
			Font = Theme.Typography("FontSemibold"),
			TextSize = Theme.Typography("SmallSize"),
			TextColor3 = Theme.Color("TextDim"),
			Text = self.Text,
			Parent = Container,
		})
		local Line2 = Utilities.Create("Frame", {
			BackgroundColor3 = Theme.Color("Border"),
			BorderSizePixel = 0,
			Size = UDim2.new(0.4, 0, 0, self.Thickness),
			Parent = Container,
		})
	else
		local Line = Utilities.Create("Frame", {
			BackgroundColor3 = Theme.Color("Border"),
			BorderSizePixel = 0,
			Size = IsHorizontal and UDim2.new(1, 0, 0, self.Thickness) or UDim2.new(0, self.Thickness, 1, 0),
			Position = IsHorizontal and UDim2.new(0, 0, 0.5, 0) or UDim2.new(0.5, 0, 0, 0),
			AnchorPoint = IsHorizontal and Vector2.new(0, 0.5) or Vector2.new(0.5, 0),
			Parent = Container,
		})
		self.Instance = Line
	end
end

function Divider:SetText(Text)
	self.Text = Text
end

return Divider

end

Modules["Widgets.Dropdown"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local Dropdown = {}
Dropdown.__index = setmetatable(Dropdown, Base)

function Dropdown.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Dropdown)
	self.Options = Options.Options or {}
	self.Value = Options.Default or self.Options[1]
	self.Label = Options.Label or ""
	self.Callback = Options.Callback
	self.MultiSelect = Options.MultiSelect or false
	self.Selected = {}
	self.Open = false
	self:_Build()
	return self
end

function Dropdown:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(self.Label ~= "" and 66 or 44)
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})

	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Vertical, 6, Enum.HorizontalAlignment.Left)
	local Padding = Utilities.AddPadding(Card, 12)

	if self.Label ~= "" then
		local Label = Utilities.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 16),
			Font = Theme.Typography("FontSemibold"),
			TextSize = Theme.Typography("CaptionSize"),
			TextColor3 = Theme.Color("TextMuted"),
			TextXAlignment = Enum.TextXAlignment.Left,
			Text = self.Label,
			Parent = Card,
		})
	end

	local Trigger = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("Background"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 28),
		AutoButtonColor = false,
		Text = "",
		Parent = Card,
	})
	local TriggerCorner = Utilities.Roundify(Trigger, Theme.Layout("RadiusSmall"))
	local TriggerStroke = Utilities.AddStroke(Trigger, Theme.Color("Border"), 1)
	local TriggerLayout = Utilities.AddListLayout(Trigger, Enum.FillDirection.Horizontal, 8, Enum.HorizontalAlignment.Left)
	TriggerLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	TriggerLayout.Padding = UDim.new(0, 10)

	local ValueLabel = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -30, 1, 0),
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Value or "Select...",
		Parent = Trigger,
	})
	local Chevron = Icons.Create("ChevronDown", Theme.Color("TextMuted"), 16)
	Chevron.Parent = Trigger

	local Panel = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("CardElevated"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		ClipsDescendants = true,
		Visible = false,
		Parent = Card,
	})
	local PanelCorner = Utilities.Roundify(Panel, Theme.Layout("RadiusSmall"))
	local PanelStroke = Utilities.AddStroke(Panel, Theme.Color("Border"), 1)
	local PanelScroll = Utilities.Create("ScrollingFrame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		CanvasSize = UDim2.new(0, 0, 0, 0),
		AutomaticCanvasSize = Enum.AutomaticCanvasSize.Y,
		ScrollBarThickness = 4,
		ScrollBarImageColor3 = Theme.Color("Scrollbar"),
		Parent = Panel,
	})
	local PanelLayout = Utilities.AddListLayout(PanelScroll, Enum.FillDirection.Vertical, 4, Enum.HorizontalAlignment.Center)
	PanelLayout.Padding = UDim.new(0, 4)

	self.Trigger = Trigger
	self.ValueLabel = ValueLabel
	self.Chevron = Chevron
	self.Panel = Panel
	self.PanelScroll = PanelScroll

	self:_BuildOptions()
	self:_SetupInteractions(Trigger)
end

function Dropdown:_BuildOptions()
	local Theme = self.Theme
	for _, Option in ipairs(self.Options) do
		local Item = Utilities.Create("TextButton", {
			BackgroundColor3 = Theme.Color("Surface"),
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 28),
			AutoButtonColor = false,
			Text = "",
			Parent = self.PanelScroll,
		})
		local ItemCorner = Utilities.Roundify(Item, Theme.Layout("RadiusSmall"))
		local ItemLabel = Utilities.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, -16, 1, 0),
			Position = UDim2.new(0, 8, 0, 0),
			Font = Theme.Typography("Font"),
			TextSize = Theme.Typography("BodySize"),
			TextColor3 = Theme.Color("Text"),
			TextXAlignment = Enum.TextXAlignment.Left,
			Text = tostring(Option),
			Parent = Item,
		})
		local Enter = Item.MouseEnter:Connect(function()
			self.Animation:Animate(Item, "BackgroundColor3", Theme.Color("SurfaceHover"), { Duration = 0.12 })
		end)
		local Leave = Item.MouseLeave:Connect(function()
			self.Animation:Animate(Item, "BackgroundColor3", Theme.Color("Surface"), { Duration = 0.12 })
		end)
		local Click = Item.MouseButton1Click:Connect(function()
			self:_Select(Option)
		end)
		self.Cleanup:AddConnection(Enter)
		self.Cleanup:AddConnection(Leave)
		self.Cleanup:AddConnection(Click)
	end
end

function Dropdown:_SetupInteractions(Trigger)
	local Click = Trigger.MouseButton1Click:Connect(function()
		self:Toggle()
	end)
	self.Cleanup:AddConnection(Click)
end

function Dropdown:Toggle()
	self.Open = not self.Open
	self.Panel.Visible = true
	local TargetHeight = self.Open and math.min(200, #self.Options * 32 + 8) or 0
	self.Animation:Tween({
		Duration = 0.25,
		Easing = "QuadOut",
		OnUpdate = function(_, _, Progress)
			self.Panel.Size = UDim2.new(1, 0, 0, TargetHeight * Progress)
		end,
		OnComplete = function()
			if not self.Open then
				self.Panel.Visible = false
			end
		end,
	})
	self.Animation:Animate(self.Chevron, "Rotation", self.Open and 180 or 0, { Duration = 0.25 })
end

function Dropdown:_Select(Option)
	if self.MultiSelect then
		if self.Selected[Option] then
			self.Selected[Option] = nil
		else
			self.Selected[Option] = true
		end
		local Keys = Utilities.TableKeys(self.Selected)
		self.ValueLabel.Text = #Keys > 0 and table.concat(Keys, ", ") or "Select..."
		self.Changed:Fire(Keys)
		Utilities.SafeCall(self.Callback, Keys)
	else
		self.Value = Option
		self.ValueLabel.Text = tostring(Option)
		self:Toggle()
		self.Changed:Fire(Option)
		Utilities.SafeCall(self.Callback, Option)
	end
end

function Dropdown:Set(Value)
	self.Value = Value
	self.ValueLabel.Text = tostring(Value)
end

function Dropdown:Get()
	return self.Value
end

function Dropdown:SetOptions(Options)
	self.Options = Options
	for _, Child in ipairs(self.PanelScroll:GetChildren()) do
		if Child:IsA("TextButton") then
			Child:Destroy()
		end
	end
	self:_BuildOptions()
end

return Dropdown

end

Modules["Widgets.FileExplorer"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local FileExplorer = {}
FileExplorer.__index = setmetatable(FileExplorer, Base)

function FileExplorer.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), FileExplorer)
	self.Root = Options.Root or {
		Name = "root",
		Type = "Folder",
		Children = {
			{ Name = "Scripts", Type = "Folder", Children = {
				{ Name = "main.lua", Type = "File" },
				{ Name = "utils.lua", Type = "File" },
			} },
			{ Name = "Assets", Type = "Folder", Children = {
				{ Name = "icon.png", Type = "File" },
			} },
			{ Name = "README.md", Type = "File" },
		},
	}
	self.OnOpen = Options.OnOpen
	self:_Build()
	return self
end

function FileExplorer:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(0)
	Container.AutomaticSize = Enum.AutomaticSize.Y
	local Card = self:_CreateCard(0, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})
	local Padding = Utilities.AddPadding(Card, 8)
	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Vertical, 2, Enum.HorizontalAlignment.Left)
	self.Card = Card

	self:_RenderNode(self.Root, Card, 0)
end

function FileExplorer:_RenderNode(Node, Parent, Depth)
	local Theme = self.Theme
	local Row = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 28),
		AutoButtonColor = false,
		Text = "",
		Parent = Parent,
	})
	local RowCorner = Utilities.Roundify(Row, Theme.Layout("RadiusSmall"))
	local RowLayout = Utilities.AddListLayout(Row, Enum.FillDirection.Horizontal, 6, Enum.HorizontalAlignment.Left)
	RowLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	RowLayout.Padding = UDim.new(0, 6 + Depth * 16)

	local IsFolder = Node.Type == "Folder"
	local IconName = IsFolder and "Folder" or "File"
	local IconFrame = Icons.Create(IconName, IsFolder and Theme.Color("Accent") or Theme.Color("TextMuted"), 16)
	IconFrame.Parent = Row

	local Label = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -40, 1, 0),
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = Node.Name,
		Parent = Row,
	})

	local ChildContainer
	if IsFolder and Node.Children then
		ChildContainer = Utilities.Create("Frame", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 0),
			AutomaticSize = Enum.AutomaticSize.Y,
			Visible = false,
			Parent = Parent,
		})
		local ChildLayout = Utilities.AddListLayout(ChildContainer, Enum.FillDirection.Vertical, 2, Enum.HorizontalAlignment.Left)
		self:_RenderNodeList(Node.Children, ChildContainer, Depth + 1)
	end

	local Expanded = false
	local Click = Row.MouseButton1Click:Connect(function()
		if IsFolder then
			Expanded = not Expanded
			ChildContainer.Visible = Expanded
		else
			self.Changed:Fire(Node)
			Utilities.SafeCall(self.OnOpen, Node)
		end
	end)
	self.Cleanup:AddConnection(Click)
	local Enter = Row.MouseEnter:Connect(function()
		self.Animation:Animate(Row, "BackgroundColor3", Theme.Color("SurfaceHover"), { Duration = 0.1 })
	end)
	local Leave = Row.MouseLeave:Connect(function()
		self.Animation:Animate(Row, "BackgroundColor3", Theme.Color("Surface"), { Duration = 0.1 })
	end)
	self.Cleanup:AddConnection(Enter)
	self.Cleanup:AddConnection(Leave)
end

function FileExplorer:_RenderNodeList(Nodes, Parent, Depth)
	for _, Node in ipairs(Nodes) do
		self:_RenderNode(Node, Parent, Depth)
	end
end

return FileExplorer

end

Modules["Widgets.GradientPicker"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local GradientPicker = {}
GradientPicker.__index = setmetatable(GradientPicker, Base)

function GradientPicker.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), GradientPicker)
	self.Stops = Options.Default or {
		{ Position = 0, Color = Color3.fromRGB(124, 162, 255) },
		{ Position = 1, Color = Color3.fromRGB(170, 130, 255) },
	}
	self.Label = Options.Label or "Gradient"
	self.Callback = Options.Callback
	self.Open = false
	self.SelectedStop = 1
	self:_Build()
	return self
end

function GradientPicker:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(self.Label ~= "" and 66 or 44)
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})

	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Horizontal, 12, Enum.HorizontalAlignment.Left)
	Layout.VerticalAlignment = Enum.VerticalAlignment.Center
	local Padding = Utilities.AddPadding(Card, 12)

	local TextBlock = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -60, 1, 0),
		Parent = Card,
	})
	local TextLayout = Utilities.AddListLayout(TextBlock, Enum.FillDirection.Vertical, 2)
	local Label = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 18),
		Font = Theme.Typography("FontSemibold"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Label,
		Parent = TextBlock,
	})

	local Preview = Utilities.Create("TextButton", {
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(40, 40),
		AutoButtonColor = false,
		Text = "",
		Parent = Card,
	})
	local PreviewCorner = Utilities.Roundify(Preview, Theme.Layout("RadiusSmall"))
	local PreviewStroke = Utilities.AddStroke(Preview, Theme.Color("Border"), 1)
	local PreviewGradient = Utilities.AddGradient(Preview, self:_ToSequence(), 90)

	self.Preview = Preview
	self.PreviewGradient = PreviewGradient

	self:_BuildPanel()
	self:_SetupInteractions(Preview)
end

function GradientPicker:_ToSequence()
	local Keypoints = {}
	for _, Stop in ipairs(self.Stops) do
		table.insert(Keypoints, ColorSequenceKeypoint.new(Stop.Position, Stop.Color))
	end
	table.sort(Keypoints, function(A, B)
		return A.Time < B.Time
	end)
	return ColorSequence.new(Keypoints)
end

function GradientPicker:_BuildPanel()
	local Theme = self.Theme
	local Panel = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("CardElevated"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		ClipsDescendants = true,
		Visible = false,
		Parent = self.Container,
	})
	local PanelCorner = Utilities.Roundify(Panel, Theme.Layout("RadiusSmall"))
	local PanelStroke = Utilities.AddStroke(Panel, Theme.Color("Border"), 1)
	local PanelPadding = Utilities.AddPadding(Panel, 12)
	local PanelLayout = Utilities.AddListLayout(Panel, Enum.FillDirection.Vertical, 10, Enum.HorizontalAlignment.Center)

	local Bar = Utilities.Create("TextButton", {
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 24),
		AutoButtonColor = false,
		Text = "",
		Parent = Panel,
	})
	local BarCorner = Utilities.Roundify(Bar, 999)
	local BarGradient = Utilities.AddGradient(Bar, self:_ToSequence(), 0)

	local ColorRow = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 40),
		Parent = Panel,
	})
	local ColorRowLayout = Utilities.AddListLayout(ColorRow, Enum.FillDirection.Horizontal, 8, Enum.HorizontalAlignment.Left)
	ColorRowLayout.VerticalAlignment = Enum.VerticalAlignment.Center

	local Swatch = Utilities.Create("TextButton", {
		BackgroundColor3 = self.Stops[self.SelectedStop].Color,
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(40, 40),
		AutoButtonColor = false,
		Parent = ColorRow,
	})
	local SwatchCorner = Utilities.Roundify(Swatch, Theme.Layout("RadiusSmall"))
	local SwatchStroke = Utilities.AddStroke(Swatch, Theme.Color("Border"), 1)

	local HueBar = Utilities.Create("TextButton", {
		BorderSizePixel = 0,
		Size = UDim2.new(1, -48, 0, 16),
		AutoButtonColor = false,
		Text = "",
		Parent = ColorRow,
	})
	local HueBarCorner = Utilities.Roundify(HueBar, 999)
	local HueGradient = Utilities.AddGradient(HueBar, ColorSequence.new({
		ColorSequenceKeypoint.new(0, Color3.fromHSV(0, 1, 1)),
		ColorSequenceKeypoint.new(0.17, Color3.fromHSV(0.17, 1, 1)),
		ColorSequenceKeypoint.new(0.33, Color3.fromHSV(0.33, 1, 1)),
		ColorSequenceKeypoint.new(0.5, Color3.fromHSV(0.5, 1, 1)),
		ColorSequenceKeypoint.new(0.67, Color3.fromHSV(0.67, 1, 1)),
		ColorSequenceKeypoint.new(0.83, Color3.fromHSV(0.83, 1, 1)),
		ColorSequenceKeypoint.new(1, Color3.fromHSV(1, 1, 1)),
	}), 0)

	self.Panel = Panel
	self.Bar = Bar
	self.BarGradient = BarGradient
	self.Swatch = Swatch
	self.HueBar = HueBar

	self:_SetupPanelInteractions(Bar, HueBar, Swatch)
end

function GradientPicker:_SetupPanelInteractions(Bar, HueBar, Swatch)
	local UserInputService = game:GetService("UserInputService")
	local BarDrag = false
	local HueDrag = false

	local function UpdateBar(Input)
		local Pos = Input.Position - Bar.AbsolutePosition
		local Size = Bar.AbsoluteSize
		local Ratio = Utilities.Clamp(Pos.X / Size.X, 0, 1)
		self.Stops[self.SelectedStop].Position = Ratio
		self:_Refresh()
	end
	local function UpdateHue(Input)
		local Pos = Input.Position - HueBar.AbsolutePosition
		local Size = HueBar.AbsoluteSize
		local Hue = Utilities.Clamp(Pos.X / Size.X, 0, 1)
		local _, S, V = Color3.toHSV(self.Stops[self.SelectedStop].Color)
		self.Stops[self.SelectedStop].Color = Color3.fromHSV(Hue, S, V)
		self:_Refresh()
	end

	local BarBegin = Bar.InputBegan:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 or Input.UserInputType == Enum.UserInputType.Touch then
			BarDrag = true
			UpdateBar(Input)
		end
	end)
	local HueBegin = HueBar.InputBegan:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 or Input.UserInputType == Enum.UserInputType.Touch then
			HueDrag = true
			UpdateHue(Input)
		end
	end)
	local End = UserInputService.InputEnded:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 or Input.UserInputType == Enum.UserInputType.Touch then
			BarDrag = false
			HueDrag = false
		end
	end)
	local Move = UserInputService.InputChanged:Connect(function(Input)
		if (Input.UserInputType == Enum.UserInputType.MouseMovement or Input.UserInputType == Enum.UserInputType.Touch) then
			if BarDrag then UpdateBar(Input) end
			if HueDrag then UpdateHue(Input) end
		end
	end)
	self.Cleanup:AddConnection(BarBegin)
	self.Cleanup:AddConnection(HueBegin)
	self.Cleanup:AddConnection(End)
	self.Cleanup:AddConnection(Move)
end

function GradientPicker:_Refresh()
	local Sequence = self:_ToSequence()
	self.PreviewGradient.Color = Sequence
	self.BarGradient.Color = Sequence
	self.Swatch.BackgroundColor3 = self.Stops[self.SelectedStop].Color
	self.Changed:Fire(Sequence)
	Utilities.SafeCall(self.Callback, Sequence)
end

function GradientPicker:_SetupInteractions(Preview)
	local Click = Preview.MouseButton1Click:Connect(function()
		self:Toggle()
	end)
	self.Cleanup:AddConnection(Click)
end

function GradientPicker:Toggle()
	self.Open = not self.Open
	self.Panel.Visible = true
	local TargetHeight = self.Open and 110 or 0
	self.Animation:Tween({
		Duration = 0.25,
		Easing = "QuadOut",
		OnUpdate = function(_, _, Progress)
			self.Panel.Size = UDim2.new(1, 0, 0, TargetHeight * Progress)
		end,
		OnComplete = function()
			if not self.Open then
				self.Panel.Visible = false
			end
		end,
	})
end

function GradientPicker:Set(Stops)
	self.Stops = Stops
	self:_Refresh()
end

function GradientPicker:Get()
	return self:_ToSequence()
end

function GradientPicker:AddStop(Color, Position)
	table.insert(self.Stops, { Position = Position or 0.5, Color = Color or Color3.fromRGB(255, 255, 255) })
	self:_Refresh()
end

function GradientPicker:RemoveStop(Index)
	table.remove(self.Stops, Index)
	self:_Refresh()
end

return GradientPicker

end

Modules["Widgets.Graph"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")

local Graph = {}
Graph.__index = setmetatable(Graph, Base)

function Graph.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Graph)
	self.Data = Options.Data or {}
	self.Width = Options.Width or 240
	self.Height = Options.Height or 120
	self.Min = Options.Min or 0
	self.Max = Options.Max or 100
	self.Color = Options.Color or self.Theme.Color("Accent")
	self.Filled = Options.Filled ~= false
	self:_Build()
	return self
end

function Graph:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(self.Height + 8)
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})
	local Padding = Utilities.AddPadding(Card, 4)

	local Canvas = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Background"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, self.Height),
		Parent = Card,
	})
	local CanvasCorner = Utilities.Roundify(Canvas, Theme.Layout("RadiusSmall"))

	local Line = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		Parent = Canvas,
	})
	self.Canvas = Canvas
	self.Line = Line

	self:_Render()
end

function Graph:_Render()
	for _, Child in ipairs(self.Line:GetChildren()) do
		if Child:IsA("Frame") then
			Child:Destroy()
		end
	end
	local Data = self.Data
	local Count = #Data
	if Count < 2 then
		return
	end
	local Width = self.Canvas.AbsoluteSize.X
	local Height = self.Canvas.AbsoluteSize.Y
	local Step = Width / (Count - 1)
	for I = 1, Count - 1 do
		local V1 = Utilities.Clamp(Data[I], self.Min, self.Max)
		local V2 = Utilities.Clamp(Data[I + 1], self.Min, self.Max)
		local Y1 = Height - Utilities.InverseLerp(self.Min, self.Max, V1) * Height
		local Y2 = Height - Utilities.InverseLerp(self.Min, self.Max, V2) * Height
		local X1 = (I - 1) * Step
		local X2 = I * Step
		local Length = math.sqrt((X2 - X1) ^ 2 + (Y2 - Y1) ^ 2)
		local Angle = math.deg(math.atan2(Y2 - Y1, X2 - X1))
		local Segment = Utilities.Create("Frame", {
			BackgroundColor3 = self.Color,
			BorderSizePixel = 0,
			Size = UDim2.new(0, Length, 0, 2),
			Position = UDim2.new(0, X1, 0, Y1),
			AnchorPoint = Vector2.new(0, 0.5),
			Rotation = Angle,
			Parent = self.Line,
		})
	end
	if self.Filled then
		local Fill = Utilities.Create("Frame", {
			BackgroundColor3 = self.Color,
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 0),
			Position = UDim2.new(0, 0, 1, 0),
			AnchorPoint = Vector2.new(0, 1),
			BackgroundTransparency = 0.85,
			Parent = self.Line,
		})
	end
end

function Graph:SetData(Data)
	self.Data = Data
	self:_Render()
end

function Graph:Push(Value)
	table.insert(self.Data, Value)
	self:_Render()
end

function Graph:SetRange(Min, Max)
	self.Min = Min
	self.Max = Max
	self:_Render()
end

function Graph:SetColor(Color)
	self.Color = Color
	self:_Render()
end

return Graph

end

