Modules["Widgets.Markdown"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")

local Markdown = {}
Markdown.__index = setmetatable(Markdown, Base)

function Markdown.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Markdown)
	self.Content = Options.Content or ""
	self:_Build()
	return self
end

function Markdown:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(0)
	Container.AutomaticSize = Enum.AutomaticSize.Y
	local Card = self:_CreateCard(0, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})
	local Padding = Utilities.AddPadding(Card, 14)
	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Vertical, 6, Enum.HorizontalAlignment.Left)
	self.Card = Card

	self:SetContent(self.Content)
end

function Markdown:SetContent(Content)
	self.Content = Content
	for _, Child in ipairs(self.Card:GetChildren()) do
		if Child:IsA("TextLabel") or Child:IsA("Frame") then
			Child:Destroy()
		end
	end
	local Lines = Utilities.Split(Content, "\n")
	for _, Line in ipairs(Lines) do
		self:_RenderLine(Line)
	end
end

function Markdown:_RenderLine(Line)
	local Theme = self.Theme
	local Text = Line
	local Size = Theme.Typography("BodySize")
	local Color = Theme.Color("Text")
	local Font = Theme.Typography("Font")
	local Bold = false

	if Utilities.StartsWith(Line, "# ") then
		Text = Line:sub(3)
		Size = Theme.Typography("TitleSize")
		Bold = true
		Font = Theme.Typography("FontBold")
	elseif Utilities.StartsWith(Line, "## ") then
		Text = Line:sub(4)
		Size = Theme.Typography("HeaderSize")
		Bold = true
		Font = Theme.Typography("FontBold")
	elseif Utilities.StartsWith(Line, "### ") then
		Text = Line:sub(5)
		Size = Theme.Typography("SubheaderSize")
		Bold = true
		Font = Theme.Typography("FontSemibold")
	elseif Utilities.StartsWith(Line, "- ") or Utilities.StartsWith(Line, "* ") then
		Text = "• " .. Line:sub(3)
		Color = Theme.Color("TextMuted")
	elseif Utilities.StartsWith(Line, "> ") then
		Text = Line:sub(3)
		Color = Theme.Color("TextDim")
		Font = Theme.Typography("FontItalic") or Theme.Typography("Font")
	end

	Text = Text:gsub("%*%*([^%*]+)%*%*", function(Inner)
		return Inner
	end)

	local Label = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Font = Font,
		TextSize = Size,
		TextColor3 = Color,
		TextXAlignment = Enum.TextXAlignment.Left,
		TextYAlignment = Enum.TextYAlignment.Top,
		TextWrapped = true,
		LineHeight = 1.4,
		RichText = true,
		Text = Text,
		Parent = self.Card,
	})
end

return Markdown

end

Modules["Widgets.Modal"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local Modal = {}
Modal.__index = setmetatable(Modal, Base)

function Modal.new(Application, Options)
	local self = setmetatable(Base.new(Application, Application.Renderer:GetLayer("Overlays"), Options), Modal)
	self.Title = Options.Title or "Dialog"
	self.Description = Options.Description or ""
	self.Buttons = Options.Buttons or { { Label = "OK", Variant = "Primary" } }
	self.Open = false
	self:_Build()
	return self
end

function Modal:_Build()
	local Theme = self.Theme
	local Backdrop = Utilities.Create("Frame", {
		BackgroundColor3 = Color3.fromRGB(0, 0, 0),
		BackgroundTransparency = 0.65,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		ZIndex = 250,
		Visible = false,
		Parent = self.Parent,
	})

	local Dialog = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("CardElevated"),
		BorderSizePixel = 0,
		Size = UDim2.new(0, 400, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Position = UDim2.fromScale(0.5, 0.5),
		AnchorPoint = Vector2.new(0.5, 0.5),
		ZIndex = 251,
		Parent = Backdrop,
	})
	local DialogCorner = Utilities.Roundify(Dialog, Theme.Layout("RadiusLarge"))
	local DialogStroke = Utilities.AddStroke(Dialog, Theme.Color("Border"), 1)
	local DialogGradient = Utilities.AddGradient(Dialog, Theme.Gradient("Surface"), 90)
	DialogGradient.Transparency = NumberSequence.new(0.4)
	local DialogPadding = Utilities.AddPadding(Dialog, 20)
	local DialogLayout = Utilities.AddListLayout(Dialog, Enum.FillDirection.Vertical, 12, Enum.HorizontalAlignment.Center)

	local Title = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 24),
		Font = Theme.Typography("FontBold"),
		TextSize = Theme.Typography("HeaderSize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Title,
		ZIndex = 252,
		Parent = Dialog,
	})

	local Description = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("TextMuted"),
		TextXAlignment = Enum.TextXAlignment.Left,
		TextWrapped = true,
		Text = self.Description,
		ZIndex = 252,
		Parent = Dialog,
	})

	local ButtonRow = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 36),
		ZIndex = 252,
		Parent = Dialog,
	})
	local ButtonLayout = Utilities.AddListLayout(ButtonRow, Enum.FillDirection.Horizontal, 8, Enum.HorizontalAlignment.Right)
	ButtonLayout.VerticalAlignment = Enum.VerticalAlignment.Center

	for _, ButtonOption in ipairs(self.Buttons) do
		local Button = Utilities.Create("TextButton", {
			BackgroundColor3 = ButtonOption.Variant == "Danger" and Theme.Color("Danger") or (ButtonOption.Variant == "Ghost" and Theme.Color("Surface") or Theme.Color("Accent")),
			BorderSizePixel = 0,
			Size = UDim2.fromOffset(100, 36),
			AutoButtonColor = false,
			Font = Theme.Typography("FontSemibold"),
			TextSize = Theme.Typography("BodySize"),
			TextColor3 = ButtonOption.Variant == "Ghost" and Theme.Color("Text") or Theme.Color("TextInverse"),
			Text = ButtonOption.Label,
			ZIndex = 253,
			Parent = ButtonRow,
		})
		local ButtonCorner = Utilities.Roundify(Button, Theme.Layout("RadiusSmall"))
		local Click = Button.MouseButton1Click:Connect(function()
			self:Close()
			Utilities.SafeCall(ButtonOption.Callback, self)
		end)
		self.Cleanup:AddConnection(Click)
		local Enter = Button.MouseEnter:Connect(function()
			self.Animation:Animate(Button, "BackgroundColor3", ButtonOption.Variant == "Danger" and Theme.Color("Danger") or Theme.Color("AccentLight"), { Duration = 0.12 })
		end)
		local Leave = Button.MouseLeave:Connect(function()
			self.Animation:Animate(Button, "BackgroundColor3", ButtonOption.Variant == "Danger" and Theme.Color("Danger") or (ButtonOption.Variant == "Ghost" and Theme.Color("Surface") or Theme.Color("Accent")), { Duration = 0.12 })
		end)
		self.Cleanup:AddConnection(Enter)
		self.Cleanup:AddConnection(Leave)
	end

	self.Backdrop = Backdrop
	self.Dialog = Dialog
end

function Modal:Open()
	self.Open = true
	self.Backdrop.Visible = true
	self.Animation:Tween({
		Duration = 0.3,
		Easing = "BackOut",
		OnUpdate = function(_, _, Progress)
			self.Dialog.Size = UDim2.new(0, 400, 0, self.Dialog.AbsoluteSize.Y * Progress)
			self.Dialog.BackgroundTransparency = 1 - Progress
		end,
	})
end

function Modal:Close()
	self.Open = false
	self.Animation:Tween({
		Duration = 0.2,
		Easing = "QuadIn",
		OnUpdate = function(_, _, Progress)
			self.Dialog.BackgroundTransparency = Progress
		end,
		OnComplete = function()
			self.Backdrop.Visible = false
		end,
	})
end

return Modal

end

Modules["Widgets.NestedTabs"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")
local Events = VoidRequire("Core.Events")

local NestedTabs = {}
NestedTabs.__index = setmetatable(NestedTabs, Base)

function NestedTabs.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), NestedTabs)
	self.Tabs = Options.Tabs or {}
	self.Active = nil
	self.Changed = Events.new()
	self:_Build()
	return self
end

function NestedTabs:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(0)
	Container.AutomaticSize = Enum.AutomaticSize.Y
	local Card = self:_CreateCard(0, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})

	local TabBar = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 34),
		Parent = Card,
	})
	local TabBarCorner = Utilities.Roundify(TabBar, Theme.Layout("RadiusSmall"))
	local TabBarLayout = Utilities.AddListLayout(TabBar, Enum.FillDirection.Horizontal, 4, Enum.HorizontalAlignment.Left)
	TabBarLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	TabBarLayout.Padding = UDim.new(0, 4)
	local TabBarPadding = Utilities.AddPadding(TabBar, 4)

	local Content = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Parent = Card,
	})
	local ContentLayout = Utilities.AddListLayout(Content, Enum.FillDirection.Vertical, 8, Enum.HorizontalAlignment.Center)
	ContentLayout.Padding = UDim.new(0, 8)
	local ContentPadding = Utilities.AddPadding(Content, 8)

	self.TabBar = TabBar
	self.Content = Content
	self.Buttons = {}

	for Index, Tab in ipairs(self.Tabs) do
		self:_CreateTabButton(Tab, Index)
	end

	if #self.Tabs > 0 then
		self:Select(1)
	end
end

function NestedTabs:_CreateTabButton(Tab, Index)
	local Theme = self.Theme
	local Button = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("SurfaceHover"),
		BorderSizePixel = 0,
		Size = UDim2.new(0, 0, 1, -8),
		AutomaticSize = Enum.AutomaticSize.X,
		AutoButtonColor = false,
		Text = "",
		Parent = self.TabBar,
	})
	local ButtonCorner = Utilities.Roundify(Button, Theme.Layout("RadiusSmall"))
	local ButtonLayout = Utilities.AddListLayout(Button, Enum.FillDirection.Horizontal, 6, Enum.HorizontalAlignment.Left)
	ButtonLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	ButtonLayout.Padding = UDim.new(0, 8)
	local ButtonPadding = Utilities.AddPadding(Button, 8)

	if Tab.Icon then
		local IconFrame = Icons.Create(Tab.Icon, Theme.Color("TextMuted"), 16)
		IconFrame.Parent = Button
	end

	local Label = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(0, 0, 1, 0),
		AutomaticSize = Enum.AutomaticSize.X,
		Font = Theme.Typography("FontSemibold"),
		TextSize = Theme.Typography("CaptionSize"),
		TextColor3 = Theme.Color("TextMuted"),
		Text = Tab.Title or Tab.Name or ("Tab " .. Index),
		Parent = Button,
	})

	self.Buttons[Index] = { Button = Button, Label = Label, Icon = IconFrame }

	local Click = Button.MouseButton1Click:Connect(function()
		self:Select(Index)
	end)
	self.Cleanup:AddConnection(Click)
	local Enter = Button.MouseEnter:Connect(function()
		if self.Active ~= Index then
			self.Animation:Animate(Button, "BackgroundColor3", Theme.Color("SurfaceActive"), { Duration = 0.1 })
		end
	end)
	local Leave = Button.MouseLeave:Connect(function()
		if self.Active ~= Index then
			self.Animation:Animate(Button, "BackgroundColor3", Theme.Color("SurfaceHover"), { Duration = 0.1 })
		end
	end)
	self.Cleanup:AddConnection(Enter)
	self.Cleanup:AddConnection(Leave)
end

function NestedTabs:Select(Index)
	if self.Active == Index then
		return
	end
	local Theme = self.Theme
	if self.Active and self.Buttons[self.Active] then
		local Old = self.Buttons[self.Active]
		self.Animation:Animate(Old.Button, "BackgroundColor3", Theme.Color("SurfaceHover"), { Duration = 0.15 })
		self.Animation:Animate(Old.Label, "TextColor3", Theme.Color("TextMuted"), { Duration = 0.15 })
	end
	self.Active = Index
	local Current = self.Buttons[Index]
	self.Animation:Animate(Current.Button, "BackgroundColor3", Theme.Color("Accent"), { Duration = 0.15 })
	self.Animation:Animate(Current.Label, "TextColor3", Theme.Color("TextInverse"), { Duration = 0.15 })

	for _, Child in ipairs(self.Content:GetChildren()) do
		if Child:IsA("Frame") or Child:IsA("TextButton") then
			Child:Destroy()
		end
	end
	local Tab = self.Tabs[Index]
	if Tab.Content then
		if type(Tab.Content) == "string" then
			local Text = Utilities.Create("TextLabel", {
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				Size = UDim2.new(1, 0, 0, 0),
				AutomaticSize = Enum.AutomaticSize.Y,
				Font = Theme.Typography("Font"),
				TextSize = Theme.Typography("BodySize"),
				TextColor3 = Theme.Color("TextMuted"),
				TextWrapped = true,
				Text = Tab.Content,
				Parent = self.Content,
			})
		elseif typeof(Tab.Content) == "Instance" then
			Tab.Content.Parent = self.Content
		elseif type(Tab.Content) == "function" then
			pcall(Tab.Content, self.Content)
		end
	end
	self.Changed:Fire(Index, Tab)
end

function NestedTabs:AddTab(Tab)
	table.insert(self.Tabs, Tab)
	self:_CreateTabButton(Tab, #self.Tabs)
end

return NestedTabs

end

Modules["Widgets.Notification"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local Notification = {}
Notification.__index = setmetatable(Notification, Base)

function Notification.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Notification)
	self.Title = Options.Title or "Notification"
	self.Description = Options.Description or ""
	self.Type = Options.Type or "Info"
	self.Duration = Options.Duration or 4
	self:_Build()
	return self
end

function Notification:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(0)
	Container.AutomaticSize = Enum.AutomaticSize.Y
	local Card = self:_CreateCard(0, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})

	local ColorMap = {
		Success = Theme.Color("Success"),
		Warning = Theme.Color("Warning"),
		Danger = Theme.Color("Danger"),
		Info = Theme.Color("Info"),
	}
	local IconMap = {
		Success = "CheckCircle",
		Warning = "Warning",
		Danger = "Danger",
		Info = "Info",
	}
	local Accent = ColorMap[self.Type] or Theme.Color("Accent")

	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Horizontal, 12, Enum.HorizontalAlignment.Left)
	Layout.VerticalAlignment = Enum.VerticalAlignment.Center
	local Padding = Utilities.AddPadding(Card, 14)

	local IconFrame = Icons.Create(IconMap[self.Type] or "Info", Accent, 22)
	IconFrame.Parent = Card

	local TextBlock = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -34, 1, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Parent = Card,
	})
	local TextLayout = Utilities.AddListLayout(TextBlock, Enum.FillDirection.Vertical, 3)
	local Title = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 18),
		Font = Theme.Typography("FontBold"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Title,
		Parent = TextBlock,
	})
	local Desc = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("CaptionSize"),
		TextColor3 = Theme.Color("TextMuted"),
		TextXAlignment = Enum.TextXAlignment.Left,
		TextWrapped = true,
		Text = self.Description,
		Parent = TextBlock,
	})

	local AccentBar = Utilities.Create("Frame", {
		BackgroundColor3 = Accent,
		BorderSizePixel = 0,
		Size = UDim2.new(0, 3, 1, 0),
		Parent = Card,
	})

	self.Instance = Card
	self.Card = Card

	if self.Duration > 0 then
		local Connection
		Connection = game:GetService("RunService").Heartbeat:Connect(function(Delta)
			self.Duration = self.Duration - Delta
			if self.Duration <= 0 then
				Connection:Disconnect()
				self:Dismiss()
			end
		end)
		self.Cleanup:AddConnection(Connection)
	end

	local Click = Card.InputBegan:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 then
			self:Dismiss()
		end
	end)
	self.Cleanup:AddConnection(Click)
end

function Notification:Dismiss()
	self.Animation:Tween({
		Duration = 0.3,
		Easing = "QuadIn",
		OnUpdate = function(_, _, Progress)
			self.Card.Size = UDim2.new(1, 0, 0, self.Card.AbsoluteSize.Y * (1 - Progress))
			self.Card.BackgroundTransparency = Progress
		end,
		OnComplete = function()
			self:Destroy()
		end,
	})
end

function Notification:SetTitle(Title)
	self.Title = Title
	self.Instance:FindFirstChild("TextLabel", true).Text = Title
end

function Notification:SetDescription(Description)
	self.Description = Description
end

return Notification

end

