Modules["Widgets.SearchDropdown"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")
local Dropdown = VoidRequire("Widgets.Dropdown")

local SearchDropdown = {}
SearchDropdown.__index = setmetatable(SearchDropdown, Base)

function SearchDropdown.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), SearchDropdown)
	self.AllOptions = Options.Options or {}
	self.Filtered = Utilities.ShallowCopy(self.AllOptions)
	self.Value = Options.Default or self.AllOptions[1]
	self.Label = Options.Label or ""
	self.Callback = Options.Callback
	self.MaxResults = Options.MaxResults or 50
	self.Open = false
	self:_Build()
	return self
end

function SearchDropdown:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(self.Label ~= "" and 66 or 44)
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})

	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Vertical, 6, Enum.HorizontalAlignment.Left)
	local Padding = Utilities.AddPadding(Card, 12)

	if self.Label ~= "" then
		local Label = Utilities.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 16),
			Font = Theme.Typography("FontSemibold"),
			TextSize = Theme.Typography("CaptionSize"),
			TextColor3 = Theme.Color("TextMuted"),
			TextXAlignment = Enum.TextXAlignment.Left,
			Text = self.Label,
			Parent = Card,
		})
	end

	local SearchBox = Utilities.Create("TextBox", {
		BackgroundColor3 = Theme.Color("Background"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 28),
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		PlaceholderColor3 = Theme.Color("Placeholder"),
		PlaceholderText = "Search...",
		TextXAlignment = Enum.TextXAlignment.Left,
		ClearTextOnFocus = false,
		Parent = Card,
	})
	local SearchCorner = Utilities.Roundify(SearchBox, Theme.Layout("RadiusSmall"))
	local SearchStroke = Utilities.AddStroke(SearchBox, Theme.Color("Border"), 1)
	local SearchIcon = Icons.Create("Search", Theme.Color("TextDim"), 14)
	SearchIcon.Position = UDim2.new(0, 8, 0.5, 0)
	SearchIcon.AnchorPoint = Vector2.new(0, 0.5)
	SearchIcon.Parent = SearchBox
	SearchBox.TextPadding = UDim.new(0, 28)

	local Panel = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("CardElevated"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		ClipsDescendants = true,
		Visible = false,
		Parent = Card,
	})
	local PanelCorner = Utilities.Roundify(Panel, Theme.Layout("RadiusSmall"))
	local PanelStroke = Utilities.AddStroke(Panel, Theme.Color("Border"), 1)
	local PanelScroll = Utilities.Create("ScrollingFrame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		CanvasSize = UDim2.new(0, 0, 0, 0),
		AutomaticCanvasSize = Enum.AutomaticCanvasSize.Y,
		ScrollBarThickness = 4,
		ScrollBarImageColor3 = Theme.Color("Scrollbar"),
		Parent = Panel,
	})
	local PanelLayout = Utilities.AddListLayout(PanelScroll, Enum.FillDirection.Vertical, 4, Enum.HorizontalAlignment.Center)
	PanelLayout.Padding = UDim.new(0, 4)

	self.SearchBox = SearchBox
	self.Panel = Panel
	self.PanelScroll = PanelScroll

	self:_BuildResults()
	self:_SetupInteractions(SearchBox)
end

function SearchDropdown:_BuildResults()
	local Theme = self.Theme
	for _, Child in ipairs(self.PanelScroll:GetChildren()) do
		if Child:IsA("TextButton") then
			Child:Destroy()
		end
	end
	local Count = 0
	for _, Option in ipairs(self.Filtered) do
		if Count >= self.MaxResults then
			break
		end
		local Item = Utilities.Create("TextButton", {
			BackgroundColor3 = Theme.Color("Surface"),
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 28),
			AutoButtonColor = false,
			Text = "",
			Parent = self.PanelScroll,
		})
		local ItemCorner = Utilities.Roundify(Item, Theme.Layout("RadiusSmall"))
		local ItemLabel = Utilities.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, -16, 1, 0),
			Position = UDim2.new(0, 8, 0, 0),
			Font = Theme.Typography("Font"),
			TextSize = Theme.Typography("BodySize"),
			TextColor3 = Theme.Color("Text"),
			TextXAlignment = Enum.TextXAlignment.Left,
			Text = tostring(Option),
			Parent = Item,
		})
		local Enter = Item.MouseEnter:Connect(function()
			self.Animation:Animate(Item, "BackgroundColor3", Theme.Color("SurfaceHover"), { Duration = 0.12 })
		end)
		local Leave = Item.MouseLeave:Connect(function()
			self.Animation:Animate(Item, "BackgroundColor3", Theme.Color("Surface"), { Duration = 0.12 })
		end)
		local Click = Item.MouseButton1Click:Connect(function()
			self:_Select(Option)
		end)
		self.Cleanup:AddConnection(Enter)
		self.Cleanup:AddConnection(Leave)
		self.Cleanup:AddConnection(Click)
		Count = Count + 1
	end
end

function SearchDropdown:_SetupInteractions(SearchBox)
	local Changed = SearchBox:GetPropertyChangedSignal("Text"):Connect(function()
		local Query = string.lower(SearchBox.Text)
		self.Filtered = Utilities.TableFilter(self.AllOptions, function(Option)
			return Query == "" or string.find(string.lower(tostring(Option)), Query, 1, true) ~= nil
		end)
		self:_BuildResults()
		if not self.Open and #self.Filtered > 0 then
			self:Open()
		end
	end)
	self.Cleanup:AddConnection(Changed)
	local Focus = SearchBox.Focused:Connect(function()
		if #self.Filtered > 0 then
			self:Open()
		end
	end)
	self.Cleanup:AddConnection(Focus)
end

function SearchDropdown:Open()
	self.Open = true
	self.Panel.Visible = true
	local TargetHeight = math.min(200, #self.Filtered * 32 + 8)
	self.Animation:Tween({
		Duration = 0.2,
		Easing = "QuadOut",
		OnUpdate = function(_, _, Progress)
			self.Panel.Size = UDim2.new(1, 0, 0, TargetHeight * Progress)
		end,
	})
end

function SearchDropdown:Close()
	self.Open = false
	self.Animation:Tween({
		Duration = 0.2,
		Easing = "QuadIn",
		OnUpdate = function(_, _, Progress)
			self.Panel.Size = UDim2.new(1, 0, 0, TargetHeight * (1 - Progress))
		end,
		OnComplete = function()
			self.Panel.Visible = false
		end,
	})
end

function SearchDropdown:_Select(Option)
	self.Value = Option
	self.SearchBox.Text = tostring(Option)
	self:Close()
	self.Changed:Fire(Option)
	Utilities.SafeCall(self.Callback, Option)
end

function SearchDropdown:Set(Value)
	self.Value = Value
	self.SearchBox.Text = tostring(Value)
end

function SearchDropdown:Get()
	return self.Value
end

function SearchDropdown:SetOptions(Options)
	self.AllOptions = Options
	self.Filtered = Utilities.ShallowCopy(Options)
	self:_BuildResults()
end

return SearchDropdown

end

Modules["Widgets.Section"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local Section = {}
Section.__index = setmetatable(Section, Base)

function Section.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Section)
	self.Title = Options.Title or "Section"
	self.Icon = Options.Icon
	self.Collapsible = Options.Collapsible or false
	self.Collapsed = Options.Collapsed or false
	self.Children = {}
	self:_Build()
	return self
end

function Section:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(0)
	Container.AutomaticSize = Enum.AutomaticSize.Y

	local Header = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 36),
		AutoButtonColor = false,
		Text = "",
		Parent = Container,
	})
	local HeaderCorner = Utilities.Roundify(Header, Theme.Layout("RadiusSmall"))
	local HeaderStroke = Utilities.AddStroke(Header, Theme.Color("Border"), 1)
	local HeaderLayout = Utilities.AddListLayout(Header, Enum.FillDirection.Horizontal, 8, Enum.HorizontalAlignment.Left)
	HeaderLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	HeaderLayout.Padding = UDim.new(0, 12)

	if self.Icon then
		local IconFrame = Icons.Create(self.Icon, Theme.Color("Accent"), 18)
		IconFrame.Parent = Header
	end

	local Title = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -40, 1, 0),
		Font = Theme.Typography("FontBold"),
		TextSize = Theme.Typography("HeaderSize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Title,
		Parent = Header,
	})

	local Chevron
	if self.Collapsible then
		Chevron = Icons.Create("ChevronDown", Theme.Color("TextMuted"), 16)
		Chevron.Parent = Header
	end

	local Body = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Parent = Container,
	})
	local BodyLayout = Utilities.AddListLayout(Body, Enum.FillDirection.Vertical, 8, Enum.HorizontalAlignment.Center)
	BodyLayout.Padding = UDim.new(0, 8)
	local BodyPadding = Utilities.AddPadding(Body, 8)

	self.Header = Header
	self.Body = Body
	self.Chevron = Chevron

	if self.Collapsible then
		local Click = Header.MouseButton1Click:Connect(function()
			self:ToggleCollapse()
		end)
		self.Cleanup:AddConnection(Click)
	end
	local Enter = Header.MouseEnter:Connect(function()
		self.Animation:Animate(Header, "BackgroundColor3", Theme.Color("SurfaceHover"), { Duration = 0.12 })
	end)
	local Leave = Header.MouseLeave:Connect(function()
		self.Animation:Animate(Header, "BackgroundColor3", Theme.Color("Surface"), { Duration = 0.12 })
	end)
	self.Cleanup:AddConnection(Enter)
	self.Cleanup:AddConnection(Leave)
end

function Section:Add(Widget)
	Widget:SetParent(self.Body)
	table.insert(self.Children, Widget)
	return Widget
end

function Section:ToggleCollapse()
	self.Collapsed = not self.Collapsed
	if self.Chevron then
		self.Animation:Animate(self.Chevron, "Rotation", self.Collapsed and -90 or 0, { Duration = 0.2 })
	end
	self.Body.Visible = not self.Collapsed
end

function Section:SetTitle(Title)
	self.Title = Title
	self.Header:FindFirstChild("TextLabel", true).Text = Title
end

function Section:_ApplyTheme()
	Base._ApplyTheme(self)
	if self.Header then
		self.Header.BackgroundColor3 = self.Theme.Color("Surface")
	end
end

return Section

end

Modules["Widgets.Slider"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")

local Slider = {}
Slider.__index = setmetatable(Slider, Base)

function Slider.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Slider)
	self.Value = Options.Default or Options.Min or 0
	self.Min = Options.Min or 0
	self.Max = Options.Max or 100
	self.Increment = Options.Increment or 1
	self.Label = Options.Label or "Slider"
	self.Suffix = Options.Suffix or ""
	self.Callback = Options.Callback
	self.Precision = Options.Precision or 0
	self._Dragging = false
	self:_Build()
	return self
end

function Slider:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(64)
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})

	local Header = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 22),
		Parent = Card,
	})
	local HeaderLayout = Utilities.AddListLayout(Header, Enum.FillDirection.Horizontal, 8, Enum.HorizontalAlignment.Left)
	HeaderLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	local Padding = Utilities.AddPadding(Card, 14)

	local Label = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -60, 1, 0),
		Font = Theme.Typography("FontSemibold"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Label,
		Parent = Header,
	})
	local ValueLabel = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(0, 60, 1, 0),
		Font = Theme.Typography("FontMono"),
		TextSize = Theme.Typography("CaptionSize"),
		TextColor3 = Theme.Color("Accent"),
		TextXAlignment = Enum.TextXAlignment.Right,
		Parent = Header,
	})

	local Track = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("SurfaceActive"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 6),
		AutoButtonColor = false,
		Text = "",
		Parent = Card,
	})
	local TrackCorner = Utilities.Roundify(Track, 999)
	local Fill = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Accent"),
		BorderSizePixel = 0,
		Size = UDim2.new(0, 0, 1, 0),
		Parent = Track,
	})
	local FillCorner = Utilities.Roundify(Fill, 999)
	local FillGradient = Utilities.AddGradient(Fill, Theme.Gradient("Accent"), 90)
	local Knob = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Text"),
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(16, 16),
		Position = UDim2.new(0, 0, 0.5, 0),
		AnchorPoint = Vector2.new(0.5, 0.5),
		Parent = Track,
	})
	local KnobCorner = Utilities.Roundify(Knob, 999)
	local KnobStroke = Utilities.AddStroke(Knob, Theme.Color("AccentLight"), 2)

	self.Track = Track
	self.Fill = Fill
	self.Knob = Knob
	self.ValueLabel = ValueLabel

	self:_SetupInteractions(Track)
	self:_UpdateVisual(false)
end

function Slider:_SetupInteractions(Track)
	local UserInputService = game:GetService("UserInputService")
	local function UpdateFromInput(Input)
		local Absolute = Track.AbsolutePosition
		local Size = Track.AbsoluteSize
		local Ratio = Utilities.Clamp((Input.Position.X - Absolute.X) / Size.X, 0, 1)
		local Raw = Utilities.Lerp(self.Min, self.Max, Ratio)
		local Snapped = Utilities.Snap(Raw, self.Increment)
		Snapped = Utilities.Clamp(Snapped, self.Min, self.Max)
		Snapped = Utilities.Round(Snapped, self.Precision)
		self:Set(Snapped)
	end
	local Begin = Track.InputBegan:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 or Input.UserInputType == Enum.UserInputType.Touch then
			self._Dragging = true
			UpdateFromInput(Input)
		end
	end)
	local End = UserInputService.InputEnded:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 or Input.UserInputType == Enum.UserInputType.Touch then
			self._Dragging = false
		end
	end)
	local Move = UserInputService.InputChanged:Connect(function(Input)
		if self._Dragging and (Input.UserInputType == Enum.UserInputType.MouseMovement or Input.UserInputType == Enum.UserInputType.Touch) then
			UpdateFromInput(Input)
		end
	end)
	local Enter = Track.MouseEnter:Connect(function()
		self.Renderer:ShowGlow(Track, 0.3)
	end)
	local Leave = Track.MouseLeave:Connect(function()
		self.Renderer:HideGlow(Track)
	end)
	self.Cleanup:AddConnection(Begin)
	self.Cleanup:AddConnection(End)
	self.Cleanup:AddConnection(Move)
	self.Cleanup:AddConnection(Enter)
	self.Cleanup:AddConnection(Leave)
end

function Slider:_UpdateVisual(Animated)
	local Ratio = Utilities.InverseLerp(self.Min, self.Max, self.Value)
	local TargetFill = UDim2.new(Ratio, 0, 1, 0)
	local TargetKnob = UDim2.new(Ratio, 0, 0.5, 0)
	if Animated then
		self.Animation:Animate(self.Fill, "Size", TargetFill, { Duration = 0.1 })
		self.Animation:Animate(self.Knob, "Position", TargetKnob, { Duration = 0.1 })
	else
		self.Fill.Size = TargetFill
		self.Knob.Position = TargetKnob
	end
	self.ValueLabel.Text = tostring(self.Value) .. self.Suffix
end

function Slider:Set(Value, Silent)
	Value = Utilities.Clamp(Value, self.Min, self.Max)
	if self.Value == Value then
		return
	end
	self.Value = Value
	self:_UpdateVisual(true)
	if not Silent then
		self.Changed:Fire(Value)
		Utilities.SafeCall(self.Callback, Value)
	end
end

function Slider:Get()
	return self.Value
end

function Slider:SetRange(Min, Max)
	self.Min = Min
	self.Max = Max
	self:Set(Utilities.Clamp(self.Value, Min, Max))
end

function Slider:SetLabel(Label)
	self.Label = Label
	self.Instance:FindFirstChild("TextLabel", true).Text = Label
end

return Slider

end

Modules["Widgets.Table"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")

local Table = {}
Table.__index = setmetatable(Table, Base)

function Table.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Table)
	self.Columns = Options.Columns or {}
	self.Rows = Options.Rows or {}
	self.Sortable = Options.Sortable ~= false
	self.Striped = Options.Striped or false
	self.OnRowClick = Options.OnRowClick
	self:_Build()
	return self
end

function Table:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(0)
	Container.AutomaticSize = Enum.AutomaticSize.Y
	local Card = self:_CreateCard(0, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})
	local Padding = Utilities.AddPadding(Card, 0)
	self.Card = Card

	local Header = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 34),
		Parent = Card,
	})
	local HeaderCorner = Utilities.Roundify(Header, Theme.Layout("RadiusSmall"))
	local HeaderLayout = Utilities.AddListLayout(Header, Enum.FillDirection.Horizontal, 0, Enum.HorizontalAlignment.Left)
	HeaderLayout.VerticalAlignment = Enum.VerticalAlignment.Center

	for _, Column in ipairs(self.Columns) do
		local Cell = Utilities.Create("TextButton", {
			BackgroundColor3 = Theme.Color("Surface"),
			BorderSizePixel = 0,
			Size = UDim2.new(Column.Width or 0.25, 0, 1, 0),
			AutoButtonColor = false,
			Text = "",
			Parent = Header,
		})
		local Label = Utilities.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, -16, 1, 0),
			Position = UDim2.new(0, 8, 0, 0),
			Font = Theme.Typography("FontBold"),
			TextSize = Theme.Typography("CaptionSize"),
			TextColor3 = Theme.Color("TextMuted"),
			TextXAlignment = Enum.TextXAlignment.Left,
			Text = Column.Title or Column.Name or "",
			Parent = Cell,
		})
		if self.Sortable then
			local Click = Cell.MouseButton1Click:Connect(function()
				self:_SortBy(Column)
			end)
			self.Cleanup:AddConnection(Click)
		end
	end

	self.Body = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Parent = Card,
	})
	local BodyLayout = Utilities.AddListLayout(self.Body, Enum.FillDirection.Vertical, 2, Enum.HorizontalAlignment.Center)
	BodyLayout.Padding = UDim.new(0, 2)

	self:_BuildRows()
end

function Table:_BuildRows()
	local Theme = self.Theme
	for RowIndex, Row in ipairs(self.Rows) do
		local RowFrame = Utilities.Create("TextButton", {
			BackgroundColor3 = self.Striped and (RowIndex % 2 == 0 and Theme.Color("Surface") or Theme.Color("Card")) or Theme.Color("Card"),
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 30),
			AutoButtonColor = false,
			Text = "",
			Parent = self.Body,
		})
		local RowCorner = Utilities.Roundify(RowFrame, Theme.Layout("RadiusSmall"))
		local RowLayout = Utilities.AddListLayout(RowFrame, Enum.FillDirection.Horizontal, 0, Enum.HorizontalAlignment.Left)
		RowLayout.VerticalAlignment = Enum.VerticalAlignment.Center

		for ColIndex, Column in ipairs(self.Columns) do
			local Value = Row[Column.Name] or Row[ColIndex]
			local Cell = Utilities.Create("TextLabel", {
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				Size = UDim2.new(Column.Width or 0.25, 0, 1, 0),
				Position = UDim2.new(0, 8, 0, 0),
				Font = Theme.Typography("Font"),
				TextSize = Theme.Typography("CaptionSize"),
				TextColor3 = Theme.Color("Text"),
				TextXAlignment = Enum.TextXAlignment.Left,
				TextTruncate = Enum.TextTruncate.AtEnd,
				Text = tostring(Value),
				Parent = RowFrame,
			})
		end

		local Click = RowFrame.MouseButton1Click:Connect(function()
			self.Changed:Fire(Row, RowIndex)
			Utilities.SafeCall(self.OnRowClick, Row, RowIndex)
		end)
		self.Cleanup:AddConnection(Click)
		local Enter = RowFrame.MouseEnter:Connect(function()
			self.Animation:Animate(RowFrame, "BackgroundColor3", Theme.Color("SurfaceHover"), { Duration = 0.1 })
		end)
		local Leave = RowFrame.MouseLeave:Connect(function()
			self.Animation:Animate(RowFrame, "BackgroundColor3", self.Striped and (RowIndex % 2 == 0 and Theme.Color("Surface") or Theme.Color("Card")) or Theme.Color("Card"), { Duration = 0.1 })
		end)
		self.Cleanup:AddConnection(Enter)
		self.Cleanup:AddConnection(Leave)
	end
end

function Table:_SortBy(Column)
	local Sorted = Utilities.SortBy(self.Rows, Column.Name, self._SortAscending)
	self._SortAscending = not self._SortAscending
	self.Rows = Sorted
	for _, Child in ipairs(self.Body:GetChildren()) do
		if Child:IsA("TextButton") then
			Child:Destroy()
		end
	end
	self:_BuildRows()
end

function Table:SetRows(Rows)
	self.Rows = Rows
	for _, Child in ipairs(self.Body:GetChildren()) do
		if Child:IsA("TextButton") then
			Child:Destroy()
		end
	end
	self:_BuildRows()
end

function Table:AddRow(Row)
	table.insert(self.Rows, Row)
	self:SetRows(self.Rows)
end

return Table

end

Modules["Widgets.Tabs"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")
local Events = VoidRequire("Core.Events")

local Tabs = {}
Tabs.__index = setmetatable(Tabs, Base)

function Tabs.new(Window, Options)
	local self = setmetatable(Base.new(Window.Application, Window.ContentScroll, Options), Tabs)
	self.Window = Window
	self.Title = Options.Title or "Tab"
	self.Icon = Options.Icon
	self.Selected = false
	self.Widgets = {}
	self.Sections = {}
	self.Changed = Events.new()
	self:_Build()
	return self
end

function Tabs:_Build()
	local Theme = self.Theme
	local Button = Utilities.Create("TextButton", {
		Name = "TabButton",
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 40),
		AutoButtonColor = false,
		Text = "",
		Parent = self.Window.TabList,
	})
	local Corner = Utilities.Roundify(Button, Theme.Layout("RadiusSmall"))
	local Stroke = Utilities.AddStroke(Button, Theme.Color("Border"), 1)
	local Layout = Utilities.AddListLayout(Button, Enum.FillDirection.Horizontal, 10, Enum.HorizontalAlignment.Left)
	Layout.VerticalAlignment = Enum.VerticalAlignment.Center
	Layout.Padding = UDim.new(0, 12)

	local Indicator = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Accent"),
		BorderSizePixel = 0,
		Size = UDim2.new(0, 3, 0.6, 0),
		Position = UDim2.new(0, 0, 0.2, 0),
		Parent = Button,
	})
	local IndicatorCorner = Utilities.Roundify(Indicator, 999)

	if self.Icon then
		local IconFrame = Icons.Create(self.Icon, Theme.Color("TextMuted"), 20)
		IconFrame.Parent = Button
		self.IconFrame = IconFrame
	end

	local Label = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -40, 1, 0),
		Font = Theme.Typography("FontSemibold"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("TextMuted"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Title,
		Parent = Button,
	})
	self.Button = Button
	self.Label = Label
	self.Indicator = Indicator
	self.Stroke = Stroke

	local Click = Button.MouseButton1Click:Connect(function()
		self.Window:SelectTab(self)
	end)
	self.Cleanup:AddConnection(Click)
	local Enter = Button.MouseEnter:Connect(function()
		if not self.Selected then
			self.Animation:Animate(Button, "BackgroundColor3", Theme.Color("SurfaceHover"), { Duration = 0.12 })
		end
	end)
	local Leave = Button.MouseLeave:Connect(function()
		if not self.Selected then
			self.Animation:Animate(Button, "BackgroundColor3", Theme.Color("Surface"), { Duration = 0.12 })
		end
	end)
	self.Cleanup:AddConnection(Enter)
	self.Cleanup:AddConnection(Leave)
end

function Tabs:Select()
	self.Selected = true
	local Theme = self.Theme
	self.Animation:Animate(self.Button, "BackgroundColor3", Theme.Color("SurfaceActive"), { Duration = 0.2 })
	self.Animation:Animate(self.Label, "TextColor3", Theme.Color("Text"), { Duration = 0.2 })
	self.Animation:Animate(self.Indicator, "Size", UDim2.new(0, 3, 0.6, 0), { Duration = 0.2 })
	self.Animation:Animate(self.Stroke, "Color", Theme.Color("Accent"), { Duration = 0.2 })
	if self.IconFrame then
		self.Animation:Animate(self.IconFrame, "ImageColor3", Theme.Color("Accent"), { Duration = 0.2 })
	end
	self.ContentFrame = self.Window.ContentScroll
end

function Tabs:Deselect()
	self.Selected = false
	local Theme = self.Theme
	self.Animation:Animate(self.Button, "BackgroundColor3", Theme.Color("Surface"), { Duration = 0.2 })
	self.Animation:Animate(self.Label, "TextColor3", Theme.Color("TextMuted"), { Duration = 0.2 })
	self.Animation:Animate(self.Indicator, "Size", UDim2.new(0, 3, 0, 0), { Duration = 0.2 })
	self.Animation:Animate(self.Stroke, "Color", Theme.Color("Border"), { Duration = 0.2 })
	if self.IconFrame then
		self.Animation:Animate(self.IconFrame, "ImageColor3", Theme.Color("TextMuted"), { Duration = 0.2 })
	end
end

