Modules["Widgets.Terminal"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local Terminal = {}
Terminal.__index = setmetatable(Terminal, Base)

function Terminal.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Terminal)
	self.Prompt = Options.Prompt or "void@ui:~$"
	self.History = {}
	self.Commands = Options.Commands or {}
	self:_Build()
	return self
end

function Terminal:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(0)
	Container.AutomaticSize = Enum.AutomaticSize.Y
	local Card = self:_CreateCard(0, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})

	local TitleBar = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Surface"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 30),
		Parent = Card,
	})
	local TitleCorner = Utilities.Roundify(TitleBar, Theme.Layout("RadiusSmall"))
	local TitleLayout = Utilities.AddListLayout(TitleBar, Enum.FillDirection.Horizontal, 8, Enum.HorizontalAlignment.Left)
	TitleLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	TitleLayout.Padding = UDim.new(0, 10)
	local TitlePadding = Utilities.AddPadding(TitleBar, 10)

	local Dots = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(50, 12),
		Parent = TitleBar,
	})
	local DotLayout = Utilities.AddListLayout(Dots, Enum.FillDirection.Horizontal, 6, Enum.HorizontalAlignment.Left)
	for _, Color in ipairs({ Theme.Color("Danger"), Theme.Color("Warning"), Theme.Color("Success") }) do
		local Dot = Utilities.Create("Frame", {
			BackgroundColor3 = Color,
			BorderSizePixel = 0,
			Size = UDim2.fromOffset(10, 10),
			Parent = Dots,
		})
		local DotCorner = Utilities.Roundify(Dot, 999)
	end

	local Title = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -60, 1, 0),
		Font = Theme.Typography("FontBold"),
		TextSize = Theme.Typography("CaptionSize"),
		TextColor3 = Theme.Color("TextMuted"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = "Terminal",
		Parent = TitleBar,
	})

	local Output = Utilities.Create("ScrollingFrame", {
		BackgroundColor3 = Color3.fromRGB(8, 9, 12),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, (self.Options and self.Options.Height) or 160),
		CanvasSize = UDim2.new(0, 0, 0, 0),
		AutomaticCanvasSize = Enum.AutomaticCanvasSize.Y,
		ScrollBarThickness = 6,
		ScrollBarImageColor3 = Theme.Color("Scrollbar"),
		Parent = Card,
	})
	local OutputCorner = Utilities.Roundify(Output, Theme.Layout("RadiusSmall"))
	local OutputPadding = Utilities.AddPadding(Output, 10)
	local OutputLayout = Utilities.AddListLayout(Output, Enum.FillDirection.Vertical, 2, Enum.HorizontalAlignment.Left)

	local InputRow = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 28),
		Parent = Card,
	})
	local InputLayout = Utilities.AddListLayout(InputRow, Enum.FillDirection.Horizontal, 6, Enum.HorizontalAlignment.Left)
	InputLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	InputLayout.Padding = UDim.new(0, 10)

	local PromptLabel = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(0, 0, 1, 0),
		AutomaticSize = Enum.AutomaticSize.X,
		Font = Theme.Typography("FontMono"),
		TextSize = Theme.Typography("SmallSize"),
		TextColor3 = Theme.Color("Success"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Prompt,
		Parent = InputRow,
	})

	local Input = Utilities.Create("TextBox", {
		BackgroundColor3 = Color3.fromRGB(8, 9, 12),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 1, 0),
		Font = Theme.Typography("FontMono"),
		TextSize = Theme.Typography("SmallSize"),
		TextColor3 = Theme.Color("Text"),
		PlaceholderColor3 = Theme.Color("Placeholder"),
		PlaceholderText = "Type a command...",
		TextXAlignment = Enum.TextXAlignment.Left,
		ClearTextOnFocus = false,
		Parent = InputRow,
	})
	local InputCorner = Utilities.Roundify(Input, Theme.Layout("RadiusSmall"))

	self.Output = Output
	self.Input = Input

	local Focus = Input.FocusLost:Connect(function(EnterPressed)
		if EnterPressed then
			local Command = Input.Text
			if Command ~= "" then
				self:Run(Command)
				Input.Text = ""
			end
		end
	end)
	self.Cleanup:AddConnection(Focus)
end

function Terminal:_Print(Text, Color)
	local Theme = self.Theme
	local Line = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 18),
		Font = Theme.Typography("FontMono"),
		TextSize = Theme.Typography("SmallSize"),
		TextColor3 = Color or Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = Text,
		Parent = self.Output,
	})
	self.Output.CanvasPosition = Vector2.new(0, self.Output.CanvasSize.Y.Offset)
end

function Terminal:Run(Command)
	self:_Print(self.Prompt .. " " .. Command, self.Theme.Color("Success"))
	table.insert(self.History, Command)
	local Parts = Utilities.Split(Command, " ")
	local Name = Parts[1]
	local Handler = self.Commands[Name]
	if Handler then
		local Result = Utilities.SafeCall(Handler, table.unpack(Parts, 2))
		if type(Result) == "string" then
			self:_Print(Result)
		end
	else
		self:_Print("command not found: " .. Name, self.Theme.Color("Danger"))
	end
end

function Terminal:RegisterCommand(Name, Handler)
	self.Commands[Name] = Handler
end

function Terminal:Clear()
	for _, Child in ipairs(self.Output:GetChildren()) do
		if Child:IsA("TextLabel") then
			Child:Destroy()
		end
	end
end

function Terminal:GetHistory()
	return self.History
end

return Terminal

end

Modules["Widgets.Textbox"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")

local Textbox = {}
Textbox.__index = setmetatable(Textbox, Base)

function Textbox.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Textbox)
	self.Value = Options.Default or ""
	self.Placeholder = Options.Placeholder or "Type here..."
	self.Label = Options.Label or ""
	self.Callback = Options.Callback
	self.Numeric = Options.Numeric or false
	self.Password = Options.Password or false
	self.Multiline = Options.Multiline or false
	self.MaxLength = Options.MaxLength or 99999
	self:_Build()
	return self
end

function Textbox:_Build()
	local Theme = self.Theme
	local Height = self.Multiline and 100 or 44
	local Container = self:_CreateContainer(self.Label ~= "" and Height + 22 or Height)
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})

	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Vertical, 6, Enum.HorizontalAlignment.Left)
	local Padding = Utilities.AddPadding(Card, 12)

	if self.Label ~= "" then
		local Label = Utilities.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 16),
			Font = Theme.Typography("FontSemibold"),
			TextSize = Theme.Typography("CaptionSize"),
			TextColor3 = Theme.Color("TextMuted"),
			TextXAlignment = Enum.TextXAlignment.Left,
			Text = self.Label,
			Parent = Card,
		})
	end

	local InputClass = self.Multiline and "TextBox" or "TextBox"
	local Input = Utilities.Create(InputClass, {
		BackgroundColor3 = Theme.Color("Background"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, self.Multiline and 76 or 28),
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		PlaceholderColor3 = Theme.Color("Placeholder"),
		PlaceholderText = self.Placeholder,
		Text = self.Password and "" or self.Value,
		TextXAlignment = Enum.TextXAlignment.Left,
		TextYAlignment = self.Multiline and Enum.TextYAlignment.Top or Enum.TextYAlignment.Center,
		ClearTextOnFocus = false,
		MultiLine = self.Multiline,
		Parent = Card,
	})
	local InputCorner = Utilities.Roundify(Input, Theme.Layout("RadiusSmall"))
	local InputStroke = Utilities.AddStroke(Input, Theme.Color("Border"), 1)
	self.Input = Input
	self.InputStroke = InputStroke

	self:_SetupInteractions(Input)
	if self.Password then
		self:_ApplyPasswordMask()
	end
end

function Textbox:_ApplyPasswordMask()
	self.Input.Text = string.rep("•", #self.Value)
end

function Textbox:_SetupInteractions(Input)
	local Theme = self.Theme
	local Focus = Input.Focused:Connect(function()
		self._Focused = true
		self.Animation:Animate(Input, "BackgroundColor3", Theme.Color("SurfaceActive"), { Duration = 0.15 })
		self.Animation:Animate(InputStroke, "Color", Theme.Color("Accent"), { Duration = 0.15 })
		self.Renderer:ShowGlow(Input, 0.25)
	end)
	local Blur = Input.FocusLost:Connect(function(EnterPressed)
		self._Focused = false
		self.Animation:Animate(Input, "BackgroundColor3", Theme.Color("Background"), { Duration = 0.15 })
		self.Animation:Animate(InputStroke, "Color", Theme.Color("Border"), { Duration = 0.15 })
		self.Renderer:HideGlow(Input)
		if self.Password then
			self:_ApplyPasswordMask()
		end
		self.Changed:Fire(self.Value)
		Utilities.SafeCall(self.Callback, self.Value, EnterPressed)
	end)
	local Changed = Input:GetPropertyChangedSignal("Text"):Connect(function()
		local Text = Input.Text
		if #Text > self.MaxLength then
			Text = Text:sub(1, self.MaxLength)
			Input.Text = Text
		end
		if self.Numeric then
			local Num = tonumber(Text)
			if Num == nil and Text ~= "" and Text ~= "-" then
				Input.Text = self.Value
				return
			end
		end
		self.Value = Text
		if self.Password and self._Focused then
			Input.Text = Text
		end
	end)
	self.Cleanup:AddConnection(Focus)
	self.Cleanup:AddConnection(Blur)
	self.Cleanup:AddConnection(Changed)
end

function Textbox:Set(Value, Silent)
	self.Value = tostring(Value)
	if self.Password then
		self:_ApplyPasswordMask()
	else
		self.Input.Text = self.Value
	end
	if not Silent then
		self.Changed:Fire(self.Value)
	end
end

function Textbox:Get()
	return self.Value
end

function Textbox:Clear()
	self:Set("")
end

function Textbox:Focus()
	self.Input:CaptureFocus()
end

function Textbox:SetPlaceholder(Text)
	self.Placeholder = Text
	self.Input.PlaceholderText = Text
end

return Textbox

end

Modules["Widgets.Timeline"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local Timeline = {}
Timeline.__index = setmetatable(Timeline, Base)

function Timeline.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Timeline)
	self.Events = Options.Events or {}
	self.Duration = Options.Duration or 100
	self.Height = Options.Height or 120
	self.Playing = false
	self.Position = 0
	self.OnSeek = Options.OnSeek
	self:_Build()
	return self
end

function Timeline:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(self.Height + 50)
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})
	local Padding = Utilities.AddPadding(Card, 12)

	local Controls = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 32),
		Parent = Card,
	})
	local ControlsLayout = Utilities.AddListLayout(Controls, Enum.FillDirection.Horizontal, 8, Enum.HorizontalAlignment.Left)
	ControlsLayout.VerticalAlignment = Enum.VerticalAlignment.Center

	local PlayButton = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("Accent"),
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(32, 32),
		AutoButtonColor = false,
		Text = "",
		Parent = Controls,
	})
	local PlayCorner = Utilities.Roundify(PlayButton, Theme.Layout("RadiusSmall"))
	local PlayIcon = Icons.Create("Play", Theme.Color("TextInverse"), 16)
	PlayIcon.Parent = PlayButton
	local PlayClick = PlayButton.MouseButton1Click:Connect(function()
		self:TogglePlay()
	end)
	self.Cleanup:AddConnection(PlayClick)

	local TimeLabel = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -40, 1, 0),
		Font = Theme.Typography("FontMono"),
		TextSize = Theme.Typography("CaptionSize"),
		TextColor3 = Theme.Color("TextMuted"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = "0.0 / " .. self.Duration .. "s",
		Parent = Controls,
	})
	self.TimeLabel = TimeLabel

	local Track = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("SurfaceActive"),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, self.Height),
		AutoButtonColor = false,
		Text = "",
		Parent = Card,
	})
	local TrackCorner = Utilities.Roundify(Track, Theme.Layout("RadiusSmall"))
	local TrackGradient = Utilities.AddGradient(Track, Theme.Gradient("Surface"), 90)
	TrackGradient.Transparency = NumberSequence.new(0.6)

	local Playhead = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Accent"),
		BorderSizePixel = 0,
		Size = UDim2.new(0, 2, 1, 0),
		Position = UDim2.new(0, 0, 0, 0),
		Parent = Track,
	})

	for _, Event in ipairs(self.Events) do
		local Marker = Utilities.Create("Frame", {
			BackgroundColor3 = Theme.Color("AccentGlow"),
			BorderSizePixel = 0,
			Size = UDim2.new(0, 4, 1, 0),
			Position = UDim2.new(Utilities.Clamp(Event.Time / self.Duration, 0, 1), 0, 0, 0),
			Parent = Track,
		})
	end

	self.Track = Track
	self.Playhead = Playhead

	local UserInputService = game:GetService("UserInputService")
	local Dragging = false
	local Begin = Track.InputBegan:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 or Input.UserInputType == Enum.UserInputType.Touch then
			Dragging = true
			self:_SeekFromInput(Input)
		end
	end)
	local End = UserInputService.InputEnded:Connect(function(Input)
		if Input.UserInputType == Enum.UserInputType.MouseButton1 or Input.UserInputType == Enum.UserInputType.Touch then
			Dragging = false
		end
	end)
	local Move = UserInputService.InputChanged:Connect(function(Input)
		if Dragging and (Input.UserInputType == Enum.UserInputType.MouseMovement or Input.UserInputType == Enum.UserInputType.Touch) then
			self:_SeekFromInput(Input)
		end
	end)
	self.Cleanup:AddConnection(Begin)
	self.Cleanup:AddConnection(End)
	self.Cleanup:AddConnection(Move)

	local Connection
	Connection = game:GetService("RunService").Heartbeat:Connect(function(Delta)
		if self.Playing then
			self.Position = self.Position + Delta
			if self.Position >= self.Duration then
				self.Position = self.Duration
				self:Stop()
			end
			self:_UpdatePlayhead()
		end
	end)
	self.Cleanup:AddConnection(Connection)
end

function Timeline:_SeekFromInput(Input)
	local Ratio = Utilities.Clamp((Input.Position.X - self.Track.AbsolutePosition.X) / self.Track.AbsoluteSize.X, 0, 1)
	self.Position = Ratio * self.Duration
	self:_UpdatePlayhead()
	Utilities.SafeCall(self.OnSeek, self.Position)
end

function Timeline:_UpdatePlayhead()
	local Ratio = self.Position / self.Duration
	self.Playhead.Position = UDim2.new(Ratio, 0, 0, 0)
	self.TimeLabel.Text = string.format("%.1f / %ds", self.Position, self.Duration)
end

function Timeline:TogglePlay()
	if self.Playing then
		self:Stop()
	else
		self:Play()
	end
end

function Timeline:Play()
	self.Playing = true
end

function Timeline:Stop()
	self.Playing = false
end

function Timeline:Seek(Position)
	self.Position = Utilities.Clamp(Position, 0, self.Duration)
	self:_UpdatePlayhead()
end

function Timeline:SetEvents(Events)
	self.Events = Events
end

return Timeline

end

Modules["Widgets.Toggle"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")

local Toggle = {}
Toggle.__index = setmetatable(Toggle, Base)

function Toggle.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Toggle)
	self.Value = Options.Default or false
	self.Label = Options.Label or "Toggle"
	self.Description = Options.Description or ""
	self.Callback = Options.Callback
	self:_Build()
	return self
end

function Toggle:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(self.Description ~= "" and 56 or 44)
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})

	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Horizontal, 12, Enum.HorizontalAlignment.Left)
	Layout.VerticalAlignment = Enum.VerticalAlignment.Center
	local Padding = Utilities.AddPadding(Card, 12)

	local TextBlock = Utilities.Create("Frame", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, -70, 1, 0),
		Parent = Card,
	})
	local TextLayout = Utilities.AddListLayout(TextBlock, Enum.FillDirection.Vertical, 2)
	local Label = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 18),
		Font = Theme.Typography("FontSemibold"),
		TextSize = Theme.Typography("BodySize"),
		TextColor3 = Theme.Color("Text"),
		TextXAlignment = Enum.TextXAlignment.Left,
		Text = self.Label,
		Parent = TextBlock,
	})
	local Desc = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 14),
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("SmallSize"),
		TextColor3 = Theme.Color("TextDim"),
		TextXAlignment = Enum.TextXAlignment.Left,
		TextWrapped = true,
		Text = self.Description,
		Visible = self.Description ~= "",
		Parent = TextBlock,
	})

	local Switch = Utilities.Create("TextButton", {
		BackgroundColor3 = Theme.Color("SurfaceActive"),
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(46, 24),
		AutoButtonColor = false,
		Text = "",
		Parent = Card,
	})
	local SwitchCorner = Utilities.Roundify(Switch, 999)
	local SwitchStroke = Utilities.AddStroke(Switch, Theme.Color("Border"), 1)
	local Knob = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Text"),
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(18, 18),
		Position = UDim2.new(0, 3, 0.5, 0),
		AnchorPoint = Vector2.new(0, 0.5),
		Parent = Switch,
	})
	local KnobCorner = Utilities.Roundify(Knob, 999)
	self.Switch = Switch
	self.Knob = Knob
	self.SwitchStroke = SwitchStroke

	self:_SetupInteractions(Switch)
	self:_UpdateVisual(false)
end

function Toggle:_SetupInteractions(Switch)
	local Click = Switch.MouseButton1Click:Connect(function()
		self:Set(not self.Value)
	end)
	self.Cleanup:AddConnection(Click)
	local Enter = Switch.MouseEnter:Connect(function()
		self.Renderer:ShowGlow(Switch, 0.3)
	end)
	local Leave = Switch.MouseLeave:Connect(function()
		self.Renderer:HideGlow(Switch)
	end)
	self.Cleanup:AddConnection(Enter)
	self.Cleanup:AddConnection(Leave)
end

function Toggle:_UpdateVisual(Animated)
	local Theme = self.Theme
	local TargetColor = self.Value and Theme.Color("Accent") or Theme.Color("SurfaceActive")
	local TargetPos = self.Value and UDim2.new(0, 25, 0.5, 0) or UDim2.new(0, 3, 0.5, 0)
	local TargetKnob = self.Value and Theme.Color("TextInverse") or Theme.Color("Text")
	if Animated then
		self.Animation:Animate(self.Switch, "BackgroundColor3", TargetColor, { Duration = 0.25, Easing = "QuadOut" })
		self.Animation:Animate(self.Knob, "Position", TargetPos, { Duration = 0.25, Easing = "BackOut" })
		self.Animation:Animate(self.Knob, "BackgroundColor3", TargetKnob, { Duration = 0.25 })
	else
		self.Switch.BackgroundColor3 = TargetColor
		self.Knob.Position = TargetPos
		self.Knob.BackgroundColor3 = TargetKnob
	end
end

function Toggle:Set(Value, Silent)
	if self.Value == Value then
		return
	end
	self.Value = Value
	self:_UpdateVisual(true)
	if not Silent then
		self.Changed:Fire(Value)
		Utilities.SafeCall(self.Callback, Value)
	end
end

function Toggle:Get()
	return self.Value
end

function Toggle:Toggle()
	self:Set(not self.Value)
end

function Toggle:SetLabel(Label)
	self.Label = Label
	self.Instance:FindFirstChild("TextLabel", true).Text = Label
end

function Toggle:_ApplyTheme()
	Base._ApplyTheme(self)
	self:_UpdateVisual(false)
end

return Toggle

end

Modules["Widgets.Tooltip"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")

local Tooltip = {}
Tooltip.__index = setmetatable(Tooltip, Base)

function Tooltip.new(Application, Text)
	local self = setmetatable(Base.new(Application, Application.Renderer:GetLayer("Cursor"), {}), Tooltip)
	self.Text = Text or ""
	self.Target = nil
	self.Visible = false
	self:_Build()
	return self
end

function Tooltip:_Build()
	local Theme = self.Theme
	local TooltipFrame = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("CardElevated"),
		BorderSizePixel = 0,
		Size = UDim2.new(0, 0, 0, 28),
		AutomaticSize = Enum.AutomaticSize.X,
		ZIndex = 400,
		Visible = false,
		Parent = self.Parent,
	})
	local Corner = Utilities.Roundify(TooltipFrame, Theme.Layout("RadiusSmall"))
	local Stroke = Utilities.AddStroke(TooltipFrame, Theme.Color("Border"), 1)
	local Padding = Utilities.AddPadding(TooltipFrame, 10)

	local Label = Utilities.Create("TextLabel", {
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		Size = UDim2.new(0, 0, 1, 0),
		AutomaticSize = Enum.AutomaticSize.X,
		Font = Theme.Typography("Font"),
		TextSize = Theme.Typography("CaptionSize"),
		TextColor3 = Theme.Color("Text"),
		Text = self.Text,
		ZIndex = 401,
		Parent = TooltipFrame,
	})
	self.Frame = TooltipFrame
	self.Label = Label
end

function Tooltip:Attach(Instance)
	self.Target = Instance
	local Enter = Instance.MouseEnter:Connect(function()
		self:Show()
	end)
	local Leave = Instance.MouseLeave:Connect(function()
		self:Hide()
	end)
	self.Cleanup:AddConnection(Enter)
	self.Cleanup:AddConnection(Leave)
	local Move = Instance.MouseMoved:Connect(function()
		self:_Follow()
	end)
	self.Cleanup:AddConnection(Move)
end

function Tooltip:Show()
	self.Visible = true
	self.Frame.Visible = true
	self:_Follow()
end

function Tooltip:Hide()
	self.Visible = false
	self.Frame.Visible = false
end

function Tooltip:_Follow()
	local Mouse = self.Application.InputManager:GetMousePosition()
	self.Frame.Position = UDim2.fromOffset(Mouse.X + 14, Mouse.Y + 14)
end

function Tooltip:SetText(Text)
	self.Text = Text
	self.Label.Text = Text
end

return Tooltip

end

Modules["Widgets.TreeView"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local TreeView = {}
TreeView.__index = setmetatable(TreeView, Base)

function TreeView.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), TreeView)
	self.Nodes = Options.Nodes or {}
	self.OnSelect = Options.OnSelect
	self:_Build()
	return self
end

function TreeView:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(0)
	Container.AutomaticSize = Enum.AutomaticSize.Y
	local Card = self:_CreateCard(0, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})
	local Padding = Utilities.AddPadding(Card, 8)
	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Vertical, 2, Enum.HorizontalAlignment.Left)
	self.Card = Card

	self:_BuildNodes(self.Nodes, Card, 0)
end

function TreeView:_BuildNodes(Nodes, Parent, Depth)
	local Theme = self.Theme
	for _, Node in ipairs(Nodes) do
		local Row = Utilities.Create("TextButton", {
			BackgroundColor3 = Theme.Color("Surface"),
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 28),
			AutoButtonColor = false,
			Text = "",
			Parent = Parent,
		})
		local RowCorner = Utilities.Roundify(Row, Theme.Layout("RadiusSmall"))
		local RowLayout = Utilities.AddListLayout(Row, Enum.FillDirection.Horizontal, 6, Enum.HorizontalAlignment.Left)
		RowLayout.VerticalAlignment = Enum.VerticalAlignment.Center
		RowLayout.Padding = UDim.new(0, 6 + Depth * 16)

		local HasChildren = Node.Children and #Node.Children > 0
		local Chevron
		if HasChildren then
			Chevron = Icons.Create("ChevronRight", Theme.Color("TextMuted"), 14)
			Chevron.Parent = Row
		else
			local Spacer = Utilities.Create("Frame", {
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				Size = UDim2.fromOffset(14, 14),
				Parent = Row,
			})
		end

		local IconName = Node.Icon or (HasChildren and "Folder" or "File")
		local IconFrame = Icons.Create(IconName, Theme.Color("TextMuted"), 16)
		IconFrame.Parent = Row

		local Label = Utilities.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, -60, 1, 0),
			Font = Theme.Typography("Font"),
			TextSize = Theme.Typography("BodySize"),
			TextColor3 = Theme.Color("Text"),
			TextXAlignment = Enum.TextXAlignment.Left,
			Text = Node.Label or Node.Name or "Node",
			Parent = Row,
		})

		local ChildContainer
		if HasChildren then
			ChildContainer = Utilities.Create("Frame", {
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				Size = UDim2.new(1, 0, 0, 0),
				AutomaticSize = Enum.AutomaticSize.Y,
				Visible = false,
				Parent = Parent,
			})
			local ChildLayout = Utilities.AddListLayout(ChildContainer, Enum.FillDirection.Vertical, 2, Enum.HorizontalAlignment.Left)
			self:_BuildNodes(Node.Children, ChildContainer, Depth + 1)
		end

		local Expanded = false
		local Click = Row.MouseButton1Click:Connect(function()
			if HasChildren then
				Expanded = not Expanded
				self.Animation:Animate(Chevron, "Rotation", Expanded and 90 or 0, { Duration = 0.15 })
				ChildContainer.Visible = Expanded
			end
			self.Changed:Fire(Node)
			Utilities.SafeCall(self.OnSelect, Node)
		end)
		self.Cleanup:AddConnection(Click)
		local Enter = Row.MouseEnter:Connect(function()
			self.Animation:Animate(Row, "BackgroundColor3", Theme.Color("SurfaceHover"), { Duration = 0.1 })
		end)
		local Leave = Row.MouseLeave:Connect(function()
			self.Animation:Animate(Row, "BackgroundColor3", Theme.Color("Surface"), { Duration = 0.1 })
		end)
		self.Cleanup:AddConnection(Enter)
		self.Cleanup:AddConnection(Leave)
	end
end

function TreeView:SetNodes(Nodes)
	self.Nodes = Nodes
	for _, Child in ipairs(self.Card:GetChildren()) do
		if Child:IsA("TextButton") or Child:IsA("Frame") then
			Child:Destroy()
		end
	end
	self:_BuildNodes(Nodes, self.Card, 0)
end

return TreeView

end

Modules["Widgets.Video"] = function()
local Utilities = VoidRequire("Core.Utilities")
local Base = VoidRequire("Widgets.Base")
local Icons = VoidRequire("Assets.Icons")

local Video = {}
Video.__index = setmetatable(Video, Base)

function Video.new(Application, Parent, Options)
	local self = setmetatable(Base.new(Application, Parent, Options), Video)
	self.VideoId = Options.VideoId or Options.Source or ""
	self.Label = Options.Label or ""
	self.Playing = false
	self:_Build()
	return self
end

function Video:_Build()
	local Theme = self.Theme
	local Container = self:_CreateContainer(self.Label ~= "" and 200 or 180)
	local Card = self:_CreateCard(Container.AbsoluteSize.Y, {
		AutomaticSize = Enum.AutomaticSize.Y,
	})
	local Layout = Utilities.AddListLayout(Card, Enum.FillDirection.Vertical, 6, Enum.HorizontalAlignment.Center)
	local Padding = Utilities.AddPadding(Card, 8)

	local Frame = Utilities.Create("ImageLabel", {
		Image = "rbxassetid://0",
		BackgroundColor3 = Color3.fromRGB(0, 0, 0),
		BorderSizePixel = 0,
		Size = UDim2.new(1, 0, 0, 150),
		ScaleType = Enum.ScaleType.Fit,
		Parent = Card,
	})
	local Corner = Utilities.Roundify(Frame, Theme.Layout("RadiusSmall"))

	local Overlay = Utilities.Create("TextButton", {
		BackgroundColor3 = Color3.fromRGB(0, 0, 0),
		BackgroundTransparency = 0.4,
		BorderSizePixel = 0,
		Size = UDim2.fromScale(1, 1),
		AutoButtonColor = false,
		Text = "",
		Parent = Frame,
	})
	local PlayButton = Utilities.Create("Frame", {
		BackgroundColor3 = Theme.Color("Accent"),
		BorderSizePixel = 0,
		Size = UDim2.fromOffset(48, 48),
		Position = UDim2.fromScale(0.5, 0.5),
		AnchorPoint = Vector2.new(0.5, 0.5),
		Parent = Overlay,
	})
	local PlayCorner = Utilities.Roundify(PlayButton, 999)
	local PlayIcon = Icons.Create("Play", Theme.Color("TextInverse"), 22)
	PlayIcon.Position = UDim2.fromScale(0.5, 0.5)
	PlayIcon.AnchorPoint = Vector2.new(0.5, 0.5)
	PlayIcon.Parent = PlayButton

	self.Frame = Frame
	self.Overlay = Overlay
	self.PlayButton = PlayButton

	local Click = Overlay.MouseButton1Click:Connect(function()
		self:Toggle()
	end)
	self.Cleanup:AddConnection(Click)

	if self.Label ~= "" then
		local Label = Utilities.Create("TextLabel", {
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 16),
			Font = Theme.Typography("FontSemibold"),
			TextSize = Theme.Typography("CaptionSize"),
			TextColor3 = Theme.Color("TextMuted"),
			Text = self.Label,
			Parent = Card,
		})
	end
end

function Video:Toggle()
	self.Playing = not self.Playing
	self.Overlay.BackgroundTransparency = self.Playing and 1 or 0.4
	self.PlayButton.Visible = not self.Playing
end

function Video:SetVideoId(Id)
	self.VideoId = Id
end

return Video

end

